-- Poems batch 456
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-72','重酬周判官','白居易','唐','御定全唐诗','yuding','','[]','秋愛冷吟春愛醉，詩家眷屬酒家仙。',32,'御定全唐詩/json/443.json','["秋愛冷吟春愛醉，詩家眷屬酒家仙。", "若教早被浮名系，可得閒遊三十年。"]'),
('yuding-73','飲後夜醒','白居易','唐','御定全唐诗','yuding','','[]','黃昏飲散歸來臥，夜半人扶強起行。枕上酒容和睡醒，',40,'御定全唐詩/json/443.json','["黃昏飲散歸來臥，夜半人扶強起行。枕上酒容和睡醒，", "直至曉來猶妄想，耳中如有管弦聲。"]'),
('yuding-74','代賣薪女贈諸妓','白居易','唐','御定全唐诗','yuding','','[]','亂蓬為鬢布為巾，曉蹋寒山自負薪。',32,'御定全唐詩/json/443.json','["亂蓬為鬢布為巾，曉蹋寒山自負薪。", "一種錢唐江畔女，著紅騎馬是何人。"]'),
('yuding-75','奉和李大夫題新詩二首各六韻：因嚴亭','白居易','唐','御定全唐诗','yuding','','[]','箕潁人窮獨，蓬壺路阻難。何如兼吏隱，複得事躋攀。',72,'御定全唐詩/json/443.json','["箕潁人窮獨，蓬壺路阻難。何如兼吏隱，複得事躋攀。", "岩樹羅階下，江雲貯棟間。似移天目石，疑入武丘山。", "清景徒堪賞，皇恩肯放閑。遙知興未足，即被詔征還。"]'),
('yuding-76','奉和李大夫題新詩二首各六韻：忘筌亭','白居易','唐','御定全唐诗','yuding','','[]','翠巘公門對，朱軒野徑連。只開新戶牖，不改舊風煙。',72,'御定全唐詩/json/443.json','["翠巘公門對，朱軒野徑連。只開新戶牖，不改舊風煙。", "虛室閑生白，高情澹入玄。酒容同座勸，詩借屬城傳。", "自笑滄江畔，遙思絳帳前。亭台隨處有，爭敢比忘筌。"]'),
('yuding-77','予以長慶二年冬十月到杭州，明年秋九月始與范陽盧賈、汝南周元範、蘭陵蕭悅、清河崔求、東萊劉方輿同遊恩德寺之泉洞竹石，籍甚久矣，及茲目擊，果愜心期，因自嗟云：到郡周歲，方來入寺，半日復去，俯視朱綬，仰睇白雲，有愧於心，遂留絕句','白居易','唐','御定全唐诗','yuding','','[]','雲水埋藏恩德洞，簪裾束縛使君身。',32,'御定全唐詩/json/443.json','["雲水埋藏恩德洞，簪裾束縛使君身。", "暫來不宿歸州去，應被山呼作俗人。"]'),
('yuding-78','早冬','白居易','唐','御定全唐诗','yuding','','[]','十月江南天氣好，可憐冬景似春華。霜輕未殺萋萋草，',40,'御定全唐詩/json/443.json','["十月江南天氣好，可憐冬景似春華。霜輕未殺萋萋草，", "此時卻羨閒人醉，五馬無由入酒家。"]'),
('yuding-79','歲假內命酒贈周判官、蕭協律','白居易','唐','御定全唐诗','yuding','','[]','共知欲老流年急，且喜新正假日頻。聞健此時相勸醉，',40,'御定全唐詩/json/443.json','["共知欲老流年急，且喜新正假日頻。聞健此時相勸醉，", "歲酒先拈辭不得，被君推作少年人。"]'),
('yuding-80','與諸客攜酒尋去年梅花有感','白居易','唐','御定全唐诗','yuding','','[]','馬上同攜今日杯，湖邊共覓去春梅。年年只是人空老，',40,'御定全唐詩/json/443.json','["馬上同攜今日杯，湖邊共覓去春梅。年年只是人空老，", "樽前百事皆依舊，點檢惟無薛秀才。"]'),
('yuding-81','醉送李協律赴湖南辟命，因寄沈八中丞','白居易','唐','御定全唐诗','yuding','','[]','富陽山底樟亭畔，立馬停舟飛酒盂。曾共中丞情繾綣，',40,'御定全唐詩/json/443.json','["富陽山底樟亭畔，立馬停舟飛酒盂。曾共中丞情繾綣，", "不羨君官羨君幕，幕中收得阮元瑜。"]'),
('yuding-82','內道場永讙上人就郡見訪善說維摩經臨別請詩因以此贈','白居易','唐','御定全唐诗','yuding','','[]','五夏登壇內殿師，水為心地玉為儀。正傳金粟如來偈，',40,'御定全唐詩/json/443.json','["五夏登壇內殿師，水為心地玉為儀。正傳金粟如來偈，", "他生莫忘今朝會，虛白亭中法樂時。"]'),
('yuding-83','見李蘇州示男阿武詩，自感成詠','白居易','唐','御定全唐诗','yuding','','[]','遙羨青雲裏，祥鸞正引雛。自憐滄海伴，老蚌不生珠。',24,'御定全唐詩/json/443.json','["遙羨青雲裏，祥鸞正引雛。自憐滄海伴，老蚌不生珠。"]'),
('yuding-84','正月十五日夜月','白居易','唐','御定全唐诗','yuding','','[]','歲熟人心樂，朝遊複夜遊。春風來海上，明月在江頭。',48,'御定全唐詩/json/443.json','["歲熟人心樂，朝遊複夜遊。春風來海上，明月在江頭。", "燈火家家市，笙歌處處樓。無妨思帝裏，不合厭杭州。"]'),
('yuding-85','題州北路傍老柳樹','白居易','唐','御定全唐诗','yuding','','[]','皮枯緣受風霜久，條短為應攀折頻。但見半衰當此路，',40,'御定全唐詩/json/443.json','["皮枯緣受風霜久，條短為應攀折頻。但見半衰當此路，", "莫道老株芳意少，逢春猶勝不逢春。"]'),
('yuding-86','題清頭陀','白居易','唐','御定全唐诗','yuding','','[]','頭陀獨宿寺西峰，百尺禪庵半夜鐘。',32,'御定全唐詩/json/443.json','["頭陀獨宿寺西峰，百尺禪庵半夜鐘。", "煙月蒼蒼風瑟瑟，更無雜樹對山松。"]'),
('yuding-87','自歎二首','白居易','唐','御定全唐诗','yuding','','[]','形羸自覺朝餐減，睡少偏知夜漏長。',64,'御定全唐詩/json/443.json','["形羸自覺朝餐減，睡少偏知夜漏長。", "實事漸消虛事在，銀魚金帶繞腰光。", "二毛曉落梳頭懶，兩眼春昏點藥頻。", "唯有閑行猶得在，心情未到不如人。"]'),
('yuding-88','湖上醉中代諸妓寄嚴郎中','白居易','唐','御定全唐诗','yuding','','[]','笙歌杯酒正歡娛，忽憶仙郎望帝都。借問連宵直南省，',40,'御定全唐詩/json/443.json','["笙歌杯酒正歡娛，忽憶仙郎望帝都。借問連宵直南省，", "還有些些惆悵事，春來山路見蘼蕪。"]'),
('yuding-89','自詠','白居易','唐','御定全唐诗','yuding','','[]','悶發每吟詩引興，興來兼酌酒開顏。欲逢假日先招客，',40,'御定全唐詩/json/443.json','["悶發每吟詩引興，興來兼酌酒開顏。欲逢假日先招客，", "誰能頭白勞心力，人道無才也是閑。"]'),
('yuding-90','晚興','白居易','唐','御定全唐诗','yuding','','[]','草淺馬翩翩，新晴薄暮天。柳條春拂面，衫袖醉垂鞭。',48,'御定全唐詩/json/443.json','["草淺馬翩翩，新晴薄暮天。柳條春拂面，衫袖醉垂鞭。", "立語花堤上，行吟水寺前。等閒消一日，不覺過三年。"]'),
('yuding-91','早興','白居易','唐','御定全唐诗','yuding','','[]','晨光出照屋樑明，初打開門鼓一聲。犬上階眠知地濕，',40,'御定全唐詩/json/443.json','["晨光出照屋樑明，初打開門鼓一聲。犬上階眠知地濕，", "睡覺心空思想盡，近來鄉夢不多成。"]'),
('yuding-92','竹樓宿','白居易','唐','御定全唐诗','yuding','','[]','小書樓下千竿竹，深火爐前一醆燈。',32,'御定全唐詩/json/443.json','["小書樓下千竿竹，深火爐前一醆燈。", "此處與誰相伴宿，燒丹道士坐禪僧。"]'),
('yuding-93','湖上招客送春泛舟','白居易','唐','御定全唐诗','yuding','','[]','欲送殘春招酒伴，客中誰最有風情。兩瓶箬下新開得，',40,'御定全唐詩/json/443.json','["欲送殘春招酒伴，客中誰最有風情。兩瓶箬下新開得，", "慢牽好向湖心去，恰似菱花鏡上行。"]'),
('yuding-94','戲醉客','白居易','唐','御定全唐诗','yuding','','[]','莫言魯國書生懦，莫把杭州刺史欺。',32,'御定全唐詩/json/443.json','["莫言魯國書生懦，莫把杭州刺史欺。", "醉客請君開眼望，綠楊風下有紅旗。"]'),
('yuding-95','紫陽花','白居易','唐','御定全唐诗','yuding','','[]','何年植向仙壇上，早晚移栽到梵家。',32,'御定全唐詩/json/443.json','["何年植向仙壇上，早晚移栽到梵家。", "雖在人間人不識，與君名作紫陽花。"]'),
('yuding-0','郡齋旬假始命宴呈座客示郡寮','白居易','唐','御定全唐诗','yuding','','[]','公門日兩衙，公假月三旬。衙用決簿領，旬以會親賓。',192,'御定全唐詩/json/444.json','["公門日兩衙，公假月三旬。衙用決簿領，旬以會親賓。", "公多及私少，勞逸常不均。況為劇郡長，安得閒宴頻。", "下車已二月，開筵始今晨。初黔軍廚突，一拂郡榻塵。", "既備獻酬禮，亦具水陸珍。萍醅箬溪醑，水鱠松江鱗。", "侑食樂懸動，佐歡妓席陳。風流吳中客，佳麗江南人。", "歌節點隨袂，舞香遺在茵。清奏凝未闋，酡顏氣已春。", "眾賓勿遽起，群寮且逡巡。無輕一日醉，用犒九日勤。", "微彼九日勤，何以治吾民。微此一日醉，何以樂吾身。"]'),
('yuding-1','題西亭','白居易','唐','御定全唐诗','yuding','','[]','朝亦視簿書，暮亦視簿書。簿書視未竟，蟋蟀鳴座隅。',168,'御定全唐詩/json/444.json','["朝亦視簿書，暮亦視簿書。簿書視未竟，蟋蟀鳴座隅。", "始覺芳歲晚，複嗟塵務拘。西園景多暇，可以少躊躇。", "池鳥澹容與，橋柳高扶疏。煙蔓嫋青薜，水花披白蕖。", "何人造茲亭，華敞綽有餘。四簷軒鳥翅，複屋羅蜘蛛。", "直廊抵曲房，窈窕深且虛。修竹夾左右，清風來徐徐。", "此宜宴佳賓，鼓瑟吹笙竽。荒淫即不可，廢曠將何如。", "幸有酒與樂，及時歡且娛。忽其解郡印，他人來此居。"]'),
('yuding-2','郡中西園','白居易','唐','御定全唐诗','yuding','','[]','閑園多芳草，春夏香靡靡。深樹足佳禽，旦暮鳴不已。',96,'御定全唐詩/json/444.json','["閑園多芳草，春夏香靡靡。深樹足佳禽，旦暮鳴不已。", "院門閉松竹，庭徑穿蘭芷。愛彼池上橋，獨來聊徙倚。", "魚依藻長樂，鷗見人暫起。有時舟隨風，盡日蓮照水。", "誰知郡府內，景物閑如此。始悟喧靜緣，何嘗系遠邇。"]'),
('yuding-3','北亭臥','白居易','唐','御定全唐诗','yuding','','[]','樹綠晚陰合，池涼朝氣清。蓮開有佳色，鶴唳無凡聲。',60,'御定全唐詩/json/444.json','["樹綠晚陰合，池涼朝氣清。蓮開有佳色，鶴唳無凡聲。", "唯此閑寂境，愜我幽獨情。病假十五日，十日臥茲亭。", "明朝吏呼起，還複視黎甿。"]'),
('yuding-4','一葉落','白居易','唐','御定全唐诗','yuding','','[]','煩暑鬱未退，涼飆潛已起。寒溫與盛衰，遞相為表裏。',48,'御定全唐詩/json/444.json','["煩暑鬱未退，涼飆潛已起。寒溫與盛衰，遞相為表裏。", "蕭蕭秋林下，一葉忽先委。勿言微搖落，搖落從此始。"]'),
('yuding-5','崔湖州贈紅石琴薦煥如錦文，無以答之，以詩酬謝','白居易','唐','御定全唐诗','yuding','','[]','赬錦支綠綺，韻同相感深。千年古澗石，八月秋堂琴。',48,'御定全唐詩/json/444.json','["赬錦支綠綺，韻同相感深。千年古澗石，八月秋堂琴。", "引出山水思，助成金玉音。人間無可比，比我與君心。"]'),
('yuding-6','九日宴集，醉題郡樓，兼呈周、殷二判官','白居易','唐','御定全唐诗','yuding','','[]','前年九日餘杭郡，呼賓命宴虛白堂。去年九日到東洛，',192,'御定全唐詩/json/444.json','["前年九日餘杭郡，呼賓命宴虛白堂。去年九日到東洛，", "一日日知添老病，一年年覺惜重陽。江南九月未搖落，", "可憐假日好天色，公門吏靜風景涼。榜舟鞭馬取賓客，", "笙歌一曲思凝絕，金鈿再拜光低昂。日腳欲落備燈燭，", "半酣憑檻起四顧，七堰八門六十坊。遠近高低寺間出，", "人煙樹色無隙罅，十裏一片青茫茫。自問有何才與政，", "郊無戎馬郡無事，門有棨戟腰有章。盛時儻來合慚愧，", "請君停杯聽我語，此語真實非虛狂。五旬已過不為夭，"]'),
('yuding-7','同微之贈別郭虛舟煉師五十韻','白居易','唐','御定全唐诗','yuding','','[]','我為江司馬，君為荊判司。俱當愁悴日，始識虛舟師。',576,'御定全唐詩/json/444.json','["我為江司馬，君為荊判司。俱當愁悴日，始識虛舟師。", "師年三十餘，白皙好容儀。專心在鉛汞，餘力工琴棋。", "靜彈弦數聲，閑飲酒一卮。因指塵土下，蜉蝣良可悲。", "不聞姑射上，千歲冰雪肌。不見遼城外，古今塚累累。", "嗟我天地間，有術人莫知。得可逃死籍，不唯走三屍。", "授我參同契，其辭妙且微。六一閟扃鐍，子午守雄雌。", "我讀隨日悟，心中了無疑。黃芽與紫車，謂其坐致之。", "自負因自歎，人生號男兒。若不佩金印，即合翳玉芝。", "高謝人間世，深結山中期。泥壇方合矩，鑄鼎圓中規。", "爐橐一以動，瑞氣紅輝輝。齋心獨歎拜，中夜偷一窺。", "二物正欣合，厥狀何怪奇。綢繆夫婦體，狎獵魚龍姿。", "簡寂館鐘後，紫霄峰曉時。心塵未淨潔，火候遂參差。", "萬壽覬刀圭，千功失毫釐。先生彈指起，姹女隨煙飛。", "始知緣會間，陰騭不可移。藥灶今夕罷，詔書明日追。", "追我複追君，次第承恩私。官雖小大殊，同立白玉墀。", "我直紫微闥，手進賞罰詞。君侍玉皇座，口含生殺機。", "直躬易媒孽，浮俗我瑕疵。轉徙今安在，越嶠吳江湄。", "一提支郡印，一建連帥旗。何言四百里，不見如天涯。", "秋風旦夕來，白日西南馳。雪霜各滿鬢，朱紫徒為衣。", "師從廬山洞，訪舊來於斯。尋君又覓我，風馭紛逶迤。", "帔裾曳黃絹，鬚髮垂青絲。逢人但斂手，問道亦頷頤。", "孤雲難久留，十日告將歸。款曲話平昔，殷勤勉衰羸。", "後會杳何許，前心日磷緇。俗家無異物，何以充別資。", "素箋一百句，題附元家詩。朱頂鶴一隻，與師雲間騎。"]'),
('yuding-8','霓裳羽衣歌','白居易','唐','御定全唐诗','yuding','','[]','我昔元和侍憲皇，曾陪內宴宴昭陽。千歌百舞不可數，',359,'御定全唐詩/json/444.json','["我昔元和侍憲皇，曾陪內宴宴昭陽。千歌百舞不可數，", "案前舞者顏如玉，不著人家俗衣服。虹裳霞帔步搖冠，", "磬簫箏笛遞相攙，擊擫彈吹聲邐迤。散序六奏未動衣，", "飄然轉旋回雪輕，嫣然縱送游龍驚。小垂手後柳無力，", "上元點鬟招萼綠，王母揮袂別飛瓊。繁音急節十二遍，", "當時乍見驚心目，凝視諦聽殊未足。一落人間八九年，", "移領錢唐第二年，始有心情問絲竹。玲瓏箜篌謝好箏，", "虛白亭前湖水畔，前後祗應三度按。便除庶子拋卻來，", "貪看案牘常侵夜，不聽笙歌直到秋。秋來無事多閑悶，", "答雲七縣十萬戶，無人知有霓裳舞。唯寄長歌與我來，", "千姿萬狀分明見，恰與昭陽舞者同。眼前仿佛睹形質，", "我愛霓裳君合知，發于歌詠形於詩。君不見我歌雲，", "由來能事皆有主，楊氏創聲君造譜。君言此舞難得人，", "嬌花巧笑久寂寥，娃館苧蘿空處所。如君所言誠有是，", "妍媸優劣寧相遠，大都只在人抬舉。李娟張態君莫嫌，"]'),
('yuding-9','小童薛陽陶吹觱栗歌','白居易','唐','御定全唐诗','yuding','','[]','剪削幹蘆插寒竹，九孔漏聲五音足。近來吹者誰得名，',136,'御定全唐詩/json/444.json','["剪削幹蘆插寒竹，九孔漏聲五音足。近來吹者誰得名，", "指點之下師授聲，含嚼之間天與氣。潤州城高霜月明，", "翕然聲作疑管裂，詘然聲盡疑刀截。有時婉軟無筋骨，", "緩聲展引長有條，有條直直如筆描。下聲乍墜石沉重，", "碎絲細竹徒紛紛，宮調一聲雄出群。眾音覙縷不落道，", "若教頭白吹不休，但恐聲名壓關李。"]'),
('yuding-10','啄木曲','白居易','唐','御定全唐诗','yuding','','[]','莫買寶剪刀，虛費千金直。我有心中愁，知君剪不得。',117,'御定全唐詩/json/444.json','["莫買寶剪刀，虛費千金直。我有心中愁，知君剪不得。", "莫磨解結錐，徒勞人氣力。我有腸中結，知君解不得。", "莫染紅絲線，徒誇好顏色。我有雙淚珠，知君穿不得。", "莫近紅爐火，炎氣徒相逼。我有兩鬢霜，知君銷不得。", "刀不能剪心愁，錐不能解腸結。線不能穿淚珠，"]'),
('yuding-11','題靈岩寺','白居易','唐','御定全唐诗','yuding','','[]','娃宮屟廊尋已傾，硯池香徑又欲平。二三月時何草綠，',48,'御定全唐詩/json/444.json','["娃宮屟廊尋已傾，硯池香徑又欲平。二三月時何草綠，", "今愁古恨入絲竹，一曲涼州無限情。直自當時到今日，"]'),
('yuding-12','雙石','白居易','唐','御定全唐诗','yuding','','[]','蒼然兩片石，厥狀怪且醜。俗用無所堪，時人嫌不取。',192,'御定全唐詩/json/444.json','["蒼然兩片石，厥狀怪且醜。俗用無所堪，時人嫌不取。", "結從胚渾始，得自洞庭口。萬古遺水濱，一朝入吾手。", "擔舁來郡內，洗刷去泥垢。孔黑煙痕深，罅青苔色厚。", "老蛟蟠作足，古劍插為首。忽疑天上落，不似人間有。", "一可支吾琴，一可貯吾酒。峭絕高數尺，坳泓容一鬥。", "五弦倚其左，一杯置其右。窪樽酌未空，玉山頹已久。", "人皆有所好，物各求其偶。漸恐少年場，不容垂白叟。", "回頭問雙石，能伴老夫否。石雖不能言，許我為三友。"]'),
('yuding-13','宿東亭曉興','白居易','唐','御定全唐诗','yuding','','[]','溫溫土爐火，耿耿紗籠燭。獨抱一張琴，夜入東齋宿。',96,'御定全唐詩/json/444.json','["溫溫土爐火，耿耿紗籠燭。獨抱一張琴，夜入東齋宿。", "窗聲度殘漏，簾影浮初旭。頭癢曉梳多，眼昏春睡足。", "負暄簷宇下，散步池塘曲。南雁去未回，東風來何速。", "雪依瓦溝白，草繞牆根綠。何言萬戶州，太守常幽獨。"]'),
('yuding-14','日漸長，贈周、殷二判官','白居易','唐','御定全唐诗','yuding','','[]','日漸長，春尚早。牆頭半露紅萼枝，池岸新鋪綠芽草。',64,'御定全唐詩/json/444.json','["日漸長，春尚早。牆頭半露紅萼枝，池岸新鋪綠芽草。", "蹋草攀枝仰頭歎，何人知此春懷抱。年顏盛壯名未成，", "賴得君來勸一杯，愁開悶破心頭好。"]'),
('yuding-15','花前歎','白居易','唐','御定全唐诗','yuding','','[]','前歲花前五十二，今年花前五十五。歲課年功頭髮知，',48,'御定全唐詩/json/444.json','["前歲花前五十二，今年花前五十五。歲課年功頭髮知，", "南州桃李北州梅，且喜年年作花主。花前置酒誰相勸，"]'),
('yuding-16','自詠五首','白居易','唐','御定全唐诗','yuding','','[]','朝亦隨群動，暮亦隨群動。榮華瞬息間，求得將何用。',240,'御定全唐詩/json/444.json','["朝亦隨群動，暮亦隨群動。榮華瞬息間，求得將何用。", "形骸與冠蓋，假合相戲弄。但異睡著人，不知夢是夢。", "一家五十口，一郡十萬戶。出為差科頭，入為衣食主。", "水旱合心憂，饑寒須手撫。何異食蓼蟲，不知苦是苦。", "公私頗多事，衰憊殊少歡。迎送賓客懶，鞭笞黎庶難。", "老耳倦聲樂，病口厭杯盤。既無可戀者，何以不休官。", "一日復一日，自問何留滯。為貪逐日俸，擬作歸田計。", "亦須隨豐約，可得無限劑。若待足始休，休官在何歲。", "官舍非我廬，官園非我樹。洛中有小宅，渭上有別墅。", "既無婚嫁累，幸有歸休處。歸去誠已遲，猶勝不歸去。"]'),
('yuding-17','和微之聽妻彈別鶴操，因為解釋其義，依韻加四句','白居易','唐','御定全唐诗','yuding','','[]','義重莫若妻，生離不如死。誓將死同穴，其奈生無子。',168,'御定全唐詩/json/444.json','["義重莫若妻，生離不如死。誓將死同穴，其奈生無子。", "商陵追禮教，婦出不能止。舅姑明旦辭，夫妻中夜起。", "起聞雙鶴別，若與人相似。聽其悲唳聲，亦如不得已。", "青田八九月，遼城一萬里。裴回去住雲，嗚咽東西水。", "寫之在琴曲，聽者酸心髓。況當秋月彈，先入憂人耳。", "怨抑掩朱弦，沉吟停玉指。一聞無兒歎，相念兩如此。", "無兒雖薄命，有妻偕老矣。倖免生別離，猶勝商陵氏。"]'),
('yuding-18','題故元少尹集後二首','白居易','唐','御定全唐诗','yuding','','[]','黃壤詎知我，白頭徒憶君。唯將老年淚，一灑故人文。',48,'御定全唐詩/json/444.json','["黃壤詎知我，白頭徒憶君。唯將老年淚，一灑故人文。", "遺文三十軸，軸軸金玉聲。龍門原上土，埋骨不埋名。"]'),
('yuding-19','和微之四月一日作','白居易','唐','御定全唐诗','yuding','','[]','四月一日天，花稀葉陰薄。泥新燕影忙，蜜熟蜂聲樂。',96,'御定全唐詩/json/444.json','["四月一日天，花稀葉陰薄。泥新燕影忙，蜜熟蜂聲樂。", "麥風低冉冉，稻水準漠漠。芳節或蹉跎，遊心稍牢落。", "春華信為美，夏景亦未惡。颭浪嫩青荷，重欄晚紅藥。", "吳宮好風月，越郡多樓閣。兩地誠可憐，其奈久離索。"]'),
('yuding-20','吳中好風景二首','白居易','唐','御定全唐诗','yuding','','[]','吳中好風景，八月如三月。水荇葉仍香，木蓮花未歇。',144,'御定全唐詩/json/444.json','["吳中好風景，八月如三月。水荇葉仍香，木蓮花未歇。", "海天微雨散，江郭纖埃滅。暑退衣服幹，潮生船舫活。", "兩衙漸多暇，亭午初無熱。騎吏語使君，正是遊時節。", "吳中好風景，風景無朝暮。曉色萬家煙，秋聲八月樹。", "舟移管弦動，橋擁旌旗駐。改號齊雲樓，重開武丘路。", "況當豐歲熟，好是歡遊處。州民勸使君，且莫拋官去。"]'),
('yuding-21','答劉禹錫白太守行','白居易','唐','御定全唐诗','yuding','','[]','吏滿六百石，昔賢輒去之。秩登二千石，今我方罷歸。',144,'御定全唐詩/json/444.json','["吏滿六百石，昔賢輒去之。秩登二千石，今我方罷歸。", "我秩訝已多，我歸慚已遲。猶勝塵土下，終老無休期。", "臥乞百日告，起吟五篇詩。朝與府吏別，暮與州民辭。", "去年到郡時，麥穗黃離離。今年去郡日，稻花白霏霏。", "為郡已周歲，半歲罹旱饑。襦袴無一片，甘棠無一枝。", "何乃老與幼，泣別盡沾衣。下慚蘇人淚，上愧劉君辭。"]'),
('yuding-22','別蘇州','白居易','唐','御定全唐诗','yuding','','[]','浩浩姑蘇民，鬱鬱長洲城。來慚荷寵命，去愧無能名。',96,'御定全唐詩/json/444.json','["浩浩姑蘇民，鬱鬱長洲城。來慚荷寵命，去愧無能名。", "青紫行將吏，班白列黎氓。一時臨水拜，十裏隨舟行。", "餞筵猶未收，征棹不可停。稍隔煙樹色，尚聞絲竹聲。", "悵望武丘路，沉吟滸水亭。還鄉信有興，去郡能無情。"]'),
('yuding-23','卯時酒','白居易','唐','御定全唐诗','yuding','','[]','佛法贊醍醐，仙方誇沆瀣。未如卯時酒，神速功力倍。',204,'御定全唐詩/json/444.json','["佛法贊醍醐，仙方誇沆瀣。未如卯時酒，神速功力倍。", "一杯置掌上，三咽入腹內。煦若春貫腸，暄如日炙背。", "豈獨肢體暢，仍加志氣大。當時遺形骸，竟日忘冠帶。", "似游華胥國，疑反混元代。一性既完全，萬機皆破碎。", "半醒思往來，往來籲可怪。寵辱憂喜間，惶惶二十載。", "前年辭紫闥，今歲拋皂蓋。去矣魚返泉，超然蟬離蛻。", "是非莫分別，行止無疑礙。浩氣貯胸中，青雲委身外。", "捫心私自語，自語誰能會。五十年來心，未如今日泰。", "況茲杯中物，行坐長相對。"]'),
('yuding-24','自問行何遲','白居易','唐','御定全唐诗','yuding','','[]','前月發京口，今辰次淮涯。二旬四百里，自問行何遲。',120,'御定全唐詩/json/444.json','["前月發京口，今辰次淮涯。二旬四百里，自問行何遲。", "還鄉無他計，罷郡有餘資。進不慕富貴，退未憂寒饑。", "以此易過日，騰騰何所為。逢山輒倚棹，遇寺多題詩。", "酒醒夜深後，睡足日高時。眼底一無事，心中百不知。", "想到京國日，懶放亦如斯。何必冒風水，促促赴程歸。"]'),
('yuding-25','除日答夢得同發楚州','白居易','唐','御定全唐诗','yuding','','[]','共作千里伴，俱為一郡回。歲陰中路盡，鄉思先春來。',48,'御定全唐詩/json/444.json','["共作千里伴，俱為一郡回。歲陰中路盡，鄉思先春來。", "山雪晚猶在，淮冰晴欲開。歸歟吟可作，休戀主人杯。"]'),
('yuding-26','問楊瓊','白居易','唐','御定全唐诗','yuding','','[]','古人唱歌兼唱情，今人唱歌唯唱聲。',32,'御定全唐詩/json/444.json','["古人唱歌兼唱情，今人唱歌唯唱聲。", "欲說向君君不會，試將此語問楊瓊。"]'),
('yuding-27','有感三首','白居易','唐','御定全唐诗','yuding','','[]','鬢髮已斑白，衣綬方朱紫。窮賤當壯年，富榮臨暮齒。',264,'御定全唐詩/json/444.json','["鬢髮已斑白，衣綬方朱紫。窮賤當壯年，富榮臨暮齒。", "車輿紅塵合，第宅青煙起。彼來此須去，品物之常理。", "第宅非吾廬，逆旅暫留止。子孫非我有，委蛻而已矣。", "有如蠶造繭，又似花生子。子結花暗凋，繭成蠶老死。", "悲哉可奈何，舉世皆如此。", "莫養瘦馬駒，莫教小妓女。後事在目前，不信君看取。", "馬肥快行走，妓長能歌舞。三年五歲間，已聞換一主。", "借問新舊主，誰樂誰辛苦。請君大帶上，把筆書此語。", "往事勿追思，追思多悲愴。來事勿相迎，相迎已惆悵。", "不如兀然坐，不如塌然臥。食來即開口，睡來即合眼。", "二事最關身，安寢加餐飯。忘懷任行止，委命隨修短。", "更若有興來，狂歌酒一醆。"]'),
('yuding-28','宿滎陽','白居易','唐','御定全唐诗','yuding','','[]','生長在滎陽，少小辭鄉曲。迢迢四十載，複向滎陽宿。',84,'御定全唐詩/json/444.json','["生長在滎陽，少小辭鄉曲。迢迢四十載，複向滎陽宿。", "去時十一二，今年五十六。追思兒戲時，宛然猶在目。", "舊居失處所，故里無宗族。豈唯變市朝，兼亦遷陵穀。", "獨有溱洧水，無情依舊綠。"]'),
('yuding-29','經溱洧','白居易','唐','御定全唐诗','yuding','','[]','落日駐行騎，沉吟懷古情。鄭風變已盡，溱洧至今清。',36,'御定全唐詩/json/444.json','["落日駐行騎，沉吟懷古情。鄭風變已盡，溱洧至今清。", "不見士與女，亦無芍藥名。"]'),
('yuding-30','就花枝','白居易','唐','御定全唐诗','yuding','','[]','就花枝，移酒海，今朝不醉明朝悔。且算歡娛逐日來，',40,'御定全唐詩/json/444.json','["就花枝，移酒海，今朝不醉明朝悔。且算歡娛逐日來，", "自量氣力與心情，三五年間猶得在。"]'),
('yuding-31','喜雨','白居易','唐','御定全唐诗','yuding','','[]','圃旱憂葵堇，農旱憂禾菽。人各有所私，我旱憂松竹。',120,'御定全唐詩/json/444.json','["圃旱憂葵堇，農旱憂禾菽。人各有所私，我旱憂松竹。", "松幹竹焦死，眷眷在心目。灑葉溉其根，汲水勞僮僕。", "油雲忽東起，涼雨淒相續。似面洗垢塵，如頭得膏沐。", "千柯習習潤，萬葉欣欣綠。千日澆灌功，不如一霢霂。", "方知宰生靈，何異活草木。所以聖與賢，同心調玉燭。"]'),
('yuding-32','題道宗上人十韻','白居易','唐','御定全唐诗','yuding','','[]','如來說偈贊，菩薩著論議。是故宗律師，以詩為佛事。',120,'御定全唐詩/json/444.json','["如來說偈贊，菩薩著論議。是故宗律師，以詩為佛事。", "一音無差別，四句有詮次。欲使第一流，皆知不二義。", "精潔沾戒體，閑淡藏禪味。從容恣語言，縹緲離文字。", "旁延邦國彥，上達王公貴。先以詩句牽，後令入佛智。", "人多愛師句，我獨知師意。不似休上人，空多碧雲思。"]'),
('yuding-33','寄皇甫賓客','白居易','唐','御定全唐诗','yuding','','[]','名利既兩忘，形體方自遂。臥掩羅雀門，無人驚我睡。',60,'御定全唐詩/json/444.json','["名利既兩忘，形體方自遂。臥掩羅雀門，無人驚我睡。", "睡足鬥擻衣，閒步中庭地。食飽摩挲腹，心頭無一事。", "除卻玄晏翁，何人知此味。"]'),
('yuding-34','寄庾侍郎','白居易','唐','御定全唐诗','yuding','','[]','一雙華亭鶴，數片太湖石。巉巉蒼玉峰，矯矯青雲翮。',72,'御定全唐詩/json/444.json','["一雙華亭鶴，數片太湖石。巉巉蒼玉峰，矯矯青雲翮。", "是時歲雲暮，淡薄煙景夕。庭霜封石棱，池雪印鶴跡。", "幽致竟誰別，閒靜聊自適。懷哉庾順之，好是今宵客。"]'),
('yuding-35','寄崔少監','白居易','唐','御定全唐诗','yuding','','[]','微微西風生，稍稍東方明。入秋神骨爽，琴曉絲桐清。',84,'御定全唐詩/json/444.json','["微微西風生，稍稍東方明。入秋神骨爽，琴曉絲桐清。", "彈為古宮調，玉水寒泠泠。自覺弦指下，不是尋常聲。", "須臾群動息，掩琴坐空庭。直至日出後，猶得心和平。", "惜哉意未已，不使崔君聽。"]'),
('yuding-36','醉題沈子明壁','白居易','唐','御定全唐诗','yuding','','[]','不愛君池東十叢菊，不愛君池南萬竿竹。愛君簾下唱歌人，',26,'御定全唐詩/json/444.json','["不愛君池東十叢菊，不愛君池南萬竿竹。愛君簾下唱歌人，"]'),
('yuding-37','勸酒','白居易','唐','御定全唐诗','yuding','','[]','勸君一醆君莫辭，勸君兩醆君莫疑，勸君三醆君始知。',91,'御定全唐詩/json/444.json','["勸君一醆君莫辭，勸君兩醆君莫疑，勸君三醆君始知。", "面上今日老昨日，心中醉時勝醒時。天地迢遙自長久，", "君不見春明門外天欲明，喧喧歌哭半死生。", "遊人駐馬出不得，白輿素車爭路行。歸去來，頭已白，"]'),
('yuding-38','落花','白居易','唐','御定全唐诗','yuding','','[]','留春春不住，春歸人寂寞。厭風風不定，風起花蕭索。',72,'御定全唐詩/json/444.json','["留春春不住，春歸人寂寞。厭風風不定，風起花蕭索。", "既興風前歎，重命花下酌。勸君嘗綠醅，教人拾紅萼。", "桃飄火焰焰，梨墮雪漠漠。獨有病眼花，春風吹不落。"]'),
('yuding-39','對鏡吟','白居易','唐','御定全唐诗','yuding','','[]','白頭老人照鏡時，掩鏡沉吟吟舊詩。二十年前一莖白，',64,'御定全唐詩/json/444.json','["白頭老人照鏡時，掩鏡沉吟吟舊詩。二十年前一莖白，", "老於我者多窮賤，設使身存寒且饑。少於我者半為土，", "眼前有酒心無苦，只合歡娛不合悲。"]'),
('yuding-40','耳順吟，寄敦詩、夢得','白居易','唐','御定全唐诗','yuding','','[]','三十四十五欲牽，七十八十百病纏。五十六十卻不惡，',48,'御定全唐詩/json/444.json','["三十四十五欲牽，七十八十百病纏。五十六十卻不惡，", "未無筋力尋山水，尚有心情聽管弦。閑開新酒嘗數醆，"]'),
('yuding-41','別氈帳火爐','白居易','唐','御定全唐诗','yuding','','[]','憶昨臘月天，北風三尺雪。年老不禁寒，夜長安可徹。',133,'御定全唐詩/json/444.json','["憶昨臘月天，北風三尺雪。年老不禁寒，夜長安可徹。", "賴有青氈帳，風前自張設。複此紅火爐，雪中相暖熱。", "如魚入淵水，似兔藏深穴。婉軟蟄鱗蘇，溫燉凍肌活。", "方安陰慘夕，遽變陽和節。無奈時候遷，豈是恩情絕。", "毳bD逐日卷，香燎隨灰滅。離恨屬三春，佳期在十月。", "但令此身健，不作多時別。"]'),
('yuding-42','六年春贈分司東都諸公','白居易','唐','御定全唐诗','yuding','','[]','我為同州牧，內愧無才術。忝擢恩已多，遭逢幸非一。',192,'御定全唐詩/json/444.json','["我為同州牧，內愧無才術。忝擢恩已多，遭逢幸非一。", "偶當穀賤歲，適值民安日。郡縣獄空虛，鄉閭盜奔逸。", "其間最幸者，朝客多分秩。行接鴛鷺群，坐成芝蘭室。", "時聯拜表騎，間動題詩筆。夜雪秉燭游，春風攜榼出。", "花教鶯點檢，柳付風排比。法酒淡清漿，含桃嫋紅實。", "洛童調金管，盧女鏗瑤瑟。黛慘歌思深，腰凝舞拍密。", "每因同醉樂，自覺忘衰疾。始悟肘後方，不如杯中物。", "生涯隨日過，世事何時畢。老子苦乖慵，希君數牽率。"]'),
('yuding-43','九日代羅、樊二妓招舒著作','白居易','唐','御定全唐诗','yuding','','[]','羅敷斂雙袂，樊姬獻一杯。不見舒員外，秋菊為誰開。',24,'御定全唐詩/json/444.json','["羅敷斂雙袂，樊姬獻一杯。不見舒員外，秋菊為誰開。"]'),
('yuding-44','憶舊游','白居易','唐','御定全唐诗','yuding','','[]','憶舊游，舊游安在哉。舊游之人半白首，舊遊之地多蒼苔。',98,'御定全唐詩/json/444.json','["憶舊游，舊游安在哉。舊游之人半白首，舊遊之地多蒼苔。", "江南舊遊凡幾處，就中最憶吳江隈。長洲苑綠柳萬樹，", "修蛾慢臉燈下醉，急管繁弦頭上催。六七年前狂爛熳，", "虎丘月色為誰好，娃宮花枝應自開。賴得劉郎解吟詠，"]'),
('yuding-45','答崔賓客晦叔十二月四日見寄','白居易','唐','御定全唐诗','yuding','','[]','今歲日餘二十六，來歲年登六十二，尚不能憂眼下身，',40,'御定全唐詩/json/444.json','["今歲日餘二十六，來歲年登六十二，尚不能憂眼下身，", "早晚相從歸醉鄉，醉鄉去此無多地。"]'),
('yuding-46','勸我酒','白居易','唐','御定全唐诗','yuding','','[]','勸我酒，我不辭。請君歌，歌莫遲。歌聲長，辭亦切，',24,'御定全唐詩/json/444.json','["勸我酒，我不辭。請君歌，歌莫遲。歌聲長，辭亦切，"]'),
('yuding-47','贈韋處士，六年夏大熱旱','白居易','唐','御定全唐诗','yuding','','[]','驕陽連毒暑，動植皆枯槁。旱日幹密雲，炎煙焦茂草。',72,'御定全唐詩/json/444.json','["驕陽連毒暑，動植皆枯槁。旱日幹密雲，炎煙焦茂草。", "少壯猶困苦，況予病且老。脫無白栴檀，何以除熱惱。", "汗巾束頭鬢，膻食熏襟抱。始覺韋山人，休糧散發好。"]'),
('yuding-0','和微之詩二十三首：和晨霞','白居易','唐','御定全唐诗','yuding','','[]','君歌仙氏真，我歌慈氏真。慈氏發真念，念此閻浮人。',144,'御定全唐詩/json/445.json','["君歌仙氏真，我歌慈氏真。慈氏發真念，念此閻浮人。", "左命大迦葉，右召桓提因。千萬化菩薩，百億諸鬼神。", "上自非相頂，下及風水輪。胎卵濕化類，蠢蠢難具陳。", "弘願在救拔，大悲忘辛勤。無論善不善，豈間冤與親。", "抉開生盲眼，擺去煩惱塵。燭以智慧日，灑之甘露津。", "千界一時度，萬法無與鄰。借問晨霞子，何如朝玉宸。"]'),
('yuding-1','和微之詩二十三首：和送劉道士游天臺','白居易','唐','御定全唐诗','yuding','','[]','聞君夢遊仙，輕舉超世雰。握持尊皇節，統衛吏兵軍。',240,'御定全唐詩/json/445.json','["聞君夢遊仙，輕舉超世雰。握持尊皇節，統衛吏兵軍。", "靈旗星月象，天衣龍鳳紋。佩服交帶籙，諷吟蕊珠文。", "閬宮縹緲間，鈞樂依稀聞。齋心謁西母，暝拜朝東君。", "煙霏子晉裾，霞爛麻姑裙。倏忽別真侶，悵望隨歸雲。", "人生同大夢，夢與覺誰分。況此夢中夢，悠哉何足雲。", "假如金闕頂，設使銀河濆。既未出三界，猶應在五蘊。", "飲咽日月精，茹嚼沆瀣芬。尚是色香味，六塵之所熏。", "仙中有大仙，首出夢幻群。慈光一照燭，奧法相絪縕。", "不知萬齡暮，不見三光曛。一性自了了，萬緣徒紛紛。", "苦海不能漂，劫火不能焚。此是竺幹教，先生垂典墳。"]'),
('yuding-2','和微之詩二十三首：和櫛沐寄道友','白居易','唐','御定全唐诗','yuding','','[]','櫛沐事朝謁，中門初動關。盛服去尚早，假寐須臾間。',144,'御定全唐詩/json/445.json','["櫛沐事朝謁，中門初動關。盛服去尚早，假寐須臾間。", "鐘聲發東寺，夜色藏南山。停驂待五漏，人馬同時閑。", "高星粲金粟，落月沉玉環。出門向關路，坦坦無阻艱。", "始出裏北閈，稍轉市西闤。晨燭照朝服，紫爛複朱殷。", "由來朝廷士，一入多不還。因循擲白日，積漸凋朱顏。", "青雲已難致，碧落安能攀。但且知止足，尚可銷憂患。"]'),
('yuding-3','和微之詩二十三首：和祝蒼華','白居易','唐','御定全唐诗','yuding','','[]','日居複月諸，環回照下土。使我玄雲發，化為素絲縷。',144,'御定全唐詩/json/445.json','["日居複月諸，環回照下土。使我玄雲發，化為素絲縷。", "稟質本羸劣，養生仍莽鹵。痛飲困連宵，悲吟饑過午。", "遂令頭上發，種種無尺五。根稀比黍苗，梢細同釵股。", "豈是乏膏沐，非關櫛風雨。最為悲傷多，心焦衰落苦。", "餘者能有幾，落者不可數。禿似鵲填河，墮如烏解羽。", "蒼華何用祝，苦辭亦休吐。匹如剃頭僧，豈要巾冠主。"]'),
('yuding-4','和微之詩二十三首：和我年三首','白居易','唐','御定全唐诗','yuding','','[]','我年五十七，榮名得幾許。甲乙三道科，蘇杭兩州主。',288,'御定全唐詩/json/445.json','["我年五十七，榮名得幾許。甲乙三道科，蘇杭兩州主。", "才能本淺薄，心力虛勞苦。可能隨眾人，終老於塵土。", "我年五十七，歸去誠已遲。曆官十五政，數若珠累累。", "野萍始賓薦，場苗初縶維。因讀管蕭書，竊慕大有為。", "及遭榮遇來，乃覺才力羸。黃紙詔頻草，朱輪車載脂。", "妻孥及僕使，皆免寒與饑。省躬私自愧，知我者微之。", "永懷山陰守，未遂嵩陽期。如何坐留滯，頭白江之湄。", "我年五十七，榮名得非少。報國竟何如，謀身猶未了。", "昔嘗速官謗，恩大而懲小。一黜鶴辭軒，七年魚在沼。", "將枯鱗再躍，經鎩翮重矯。白日上昭昭，青雲高渺渺。", "平生頗同病，老大宜相曉。紫綬足可榮，白頭不為夭。", "夙懷慕箕潁，晚節期松筱。何當闕下來，同拜陳情表。"]'),
('yuding-5','和微之詩二十三首：和三月三十日四十韻','白居易','唐','御定全唐诗','yuding','','[]','送春君何在，君在山陰署。憶我蘇杭時，春遊亦多處。',480,'御定全唐詩/json/445.json','["送春君何在，君在山陰署。憶我蘇杭時，春遊亦多處。", "為君歌往事，豈敢辭勞慮。莫怪言語狂，須知酬答遽。", "江南臘月半，水凍凝如瘀。寒景尚蒼茫，和風已吹噓。", "女牆城似灶，雁齒橋如鋸。魚尾上奫淪，草芽生沮洳。", "律遲太簇管，日緩羲和馭。布澤木龍催，迎春土牛助。", "雨師習習灑，雲將飄飄翥。四野萬里晴，千山一時曙。", "杭土麗且康，蘇民富而庶。善惡有懲勸，剛柔無吐茹。", "兩衙少辭牒，四境稀書疏。俗以勞俫安，政因閒暇著。", "仙亭日登眺，虎丘時遊豫。尋幽駐旌軒，選勝回賓禦。", "舟移溪鳥避，樂作林猿覷。池古莫耶沉，石奇羅刹踞。", "水苗泥易耨，畬粟灰難鋤。紫蕨抽出畦，白蓮埋在淤。", "萎花紅帶黯，濕葉黃含煙。鏡動波颭菱，雪回風旋絮。", "手經攀桂馥，齒為嘗梅楚。坐並船腳欹，行多馬蹄跙。", "聖賢清濁醉，水陸鮮肥飫。魚鱠芥醬調，水葵鹽豉絮。", "雖微五袴詠，倖免兆人詛。但令樂不荒，何必遊無倨。", "吳苑僕尋罷，越城公尚據。舊遊幾客存，新宴誰人與。", "莫空文舉酒，強下何曾箸。江上易優遊，城中多毀譽。", "分應當自盡，事勿求人恕。我既無子孫，君仍畢婚娶。", "久為雲雨別，終擬江湖去。范蠡有扁舟，陶潛有籃輿。", "兩心苦相憶，兩口遙相語。最恨七年春，春來各一處。"]'),
('yuding-6','和微之詩二十三首：和寄樂天','白居易','唐','御定全唐诗','yuding','','[]','賢愚類相交，人情之大率。然自古今來，幾人號膠漆。',264,'御定全唐詩/json/445.json','["賢愚類相交，人情之大率。然自古今來，幾人號膠漆。", "近聞屈指數，元某與白乙。旁愛及弟兄，中權避家室。", "松筠與金石，未足喻堅密。在車如輪轅，在身如肘腋。", "又如風雲會，天使相召匹。不似勢利交，有名而無實。", "頃我在杭歲，值君之越日。望愁來儀遲，宴惜流景疾。", "坐耀黃金帶，酌酡赬玉質。酣歌口不停，狂舞衣相拂。", "平生賞心事，施展十未一。會笑始啞啞，離嗟乃唧唧。", "餞筵才收拾，征棹遽排比。後恨苦綿綿，前歡何卒卒。", "居人色慘澹，行子心紆鬱。風袂去時揮，雲帆望中失。", "宿酲和別思，目眩心忽忽。病魂黯然銷，老淚淒其出。", "別君只如昨，芳歲換六七。俱是官家身，後期難自必。"]'),
('yuding-7','和微之詩二十三首：和寄問劉、白','白居易','唐','御定全唐诗','yuding','','[]','正與劉夢得，醉笑大開口。適值此詩來，歡喜君知否。',96,'御定全唐詩/json/445.json','["正與劉夢得，醉笑大開口。適值此詩來，歡喜君知否。", "遂令高卷幕，兼遣重添酒。起望會稽雲，東南一回首。", "愛君金玉句，舉世誰人有。功用隨日新，資材本天授。", "吟哦不能散，自午將及酉。遂留夢得眠，匡床宿東牖。"]'),
('yuding-8','和微之詩二十三首：和新樓北園偶集從孫公度周巡官韓秀才盧秀才范處士小飲鄭侍御判官周劉二從事皆先歸','白居易','唐','御定全唐诗','yuding','','[]','聞君新樓宴，下對北園花。主人既賢豪，賓客皆才華。',240,'御定全唐詩/json/445.json','["聞君新樓宴，下對北園花。主人既賢豪，賓客皆才華。", "初筵日未高，中飲景已斜。天地為幕席，富貴如泥沙。", "嵇劉陶阮徒，不足置齒牙。臥甕鄙畢卓，落帽嗤孟嘉。", "芳草供枕藉，亂鶯助喧嘩。醉鄉得道路，狂海無津涯。", "一歲春又盡，百年期不賒。同醉君莫辭，獨醒古所嗟。", "銷愁若沃雪，破悶如割瓜。稱觴起為壽，此樂無以加。", "歌聲凝貫珠，舞袖飄亂麻。相公謂四座，今日非自誇。", "有奴善吹笙，有婢彈琵琶。十指纖若筍，雙鬟黳如鴉。", "履舄起交雜，杯盤散紛拏。歸去勿擁遏，倒載逃難遮。", "明日宴東武，後日遊若耶。豈獨相公樂，謳歌千萬家。"]'),
('yuding-9','和微之詩二十三首：和除夜作','白居易','唐','御定全唐诗','yuding','','[]','君賦此詩夜，窮陰歲之餘。我和此詩日，微和春之初。',240,'御定全唐詩/json/445.json','["君賦此詩夜，窮陰歲之餘。我和此詩日，微和春之初。", "老知顏狀改，病覺肢體虛。頭上毛髮短，口中牙齒疏。", "一落老病界，難逃生死墟。況此促促世，與君多索居。", "君在浙江東，榮駕方伯輿。我在魏闕下，謬乘大夫車。", "妻孥常各飽，奴婢亦盈廬。唯是利人事，比君全不如。", "我統十郎官，君領百吏胥。我掌四曹局，君管十鄉閭。", "君為父母君，大惠在資儲。我為刀筆吏，小惡乃誅鋤。", "君提七郡籍，我按三尺書。俱已佩金印，嘗同趨玉除。", "外寵信非薄，中懷何不攄。恩光未報答，日月空居諸。", "磊落嘗許君，局促應笑予。所以自知分，欲先歌歸歟。"]'),
('yuding-10','和微之詩二十三首：和知非','白居易','唐','御定全唐诗','yuding','','[]','因君知非問，詮較天下事。第一莫若禪，第二無如醉。',240,'御定全唐詩/json/445.json','["因君知非問，詮較天下事。第一莫若禪，第二無如醉。", "禪能泯人我，醉可忘榮悴。與君次第言，為我少留意。", "儒教重禮法，道家養神氣。重禮足滋彰，養神多避忌。", "不如學禪定，中有甚深味。曠廓了如空，澄凝勝於睡。", "屏除默默念，銷盡悠悠思。春無傷春心，秋無感秋淚。", "坐成真諦樂，如受空王賜。既得脫塵勞，兼應離慚愧。", "除禪其次醉，此說非無謂。一酌機即忘，三杯性咸遂。", "逐臣去室婦，降虜敗軍帥。思苦膏火煎，憂深扃鎖秘。", "須憑百杯沃，莫惜千金費。便似罩中魚，脫飛生兩翅。", "勸君雖老大，逢酒莫回避。不然即學禪，兩途同一致。"]'),
('yuding-11','和微之詩二十三首：和望曉','白居易','唐','御定全唐诗','yuding','','[]','休吟稽山曉，聽詠秦城旦。鳴雞初有聲，宿鳥猶未散。',240,'御定全唐詩/json/445.json','["休吟稽山曉，聽詠秦城旦。鳴雞初有聲，宿鳥猶未散。", "丁丁漏向盡，冬冬鼓過半。南山青沉沉，東方白漫漫。", "街心若流水，城角如斷岸。星河稍隅落，宮闕方輪煥。", "朝車雷四合，騎火星一貫。赫奕冠蓋盛，熒煌朱紫爛。", "沙堤亙蟆池，市路繞龍斷。白日忽照耀，紅塵紛散亂。", "貴教過客避，榮任行人看。祥煙滿虛空，春色無邊畔。", "鵷行候晷刻，龍尾登霄漢。台殿暖宜攀，風光晴可玩。", "草鋪地茵褥，雲卷天幃幔。鶯雜佩鏘鏘，花饒衣粲粲。", "何言終日樂，獨起臨風歎。歎我同心人，一別春七換。", "相望山隔礙，欲去官羈絆。何日到江東，超然似張翰。"]'),
('yuding-12','和微之詩二十三首：和李勢女','白居易','唐','御定全唐诗','yuding','','[]','減一分太短，增一分太長。不朱面若花，不粉肌如霜。',180,'御定全唐詩/json/445.json','["減一分太短，增一分太長。不朱面若花，不粉肌如霜。", "色為天下豔，心乃女中郎。自言重不幸，家破身未亡。", "人各有一死，此死職所當。忍將先人體，與主為疣瘡。", "妾死主意快，從此兩無妨。願信赤心語，速即白刃光。", "南郡忽感激，卻立舍鋒鋩。撫背稱阿姉，歸我如歸鄉。", "竟以恩信待，豈止猜妒忘。由來幾上肉，不足揮幹將。", "南郡死已久，骨枯墓蒼蒼。願于墓上頭，立石鐫此章。", "勸誡天下婦，不令陰勝陽。"]'),
('yuding-13','和微之詩二十三首：和酬鄭侍禦東陽春悶放懷追越遊見寄','白居易','唐','御定全唐诗','yuding','','[]','君得嘉魚置賓席，樂如南有嘉魚時。勁氣森爽竹竿竦，',168,'御定全唐詩/json/445.json','["君得嘉魚置賓席，樂如南有嘉魚時。勁氣森爽竹竿竦，", "一緘疏入掩穀永，三都賦成排左思。自言拜辭主人後，", "昨日嘉魚來訪我，方駕同出何所之。樂游原頭春尚早，", "流年惝怳不饒我，美景鮮妍來為誰。紅塵三條界阡陌，", "暮鐘遠近聲互動，暝鳥高下飛追隨。酒酣將歸未能去，", "胡不花下伴春醉，滿酌綠酒聽黃鸝。嘉魚點頭時一歎，", "此詩勿遣閒人見，見恐與他為笑資。白首舊寮知我者，"]'),
('yuding-14','和微之詩二十三首：和自勸二首','白居易','唐','御定全唐诗','yuding','','[]','稀稀疏疏繞籬竹，窄窄狹狹向陽屋。屋中有一曝背翁，',128,'御定全唐詩/json/445.json','["稀稀疏疏繞籬竹，窄窄狹狹向陽屋。屋中有一曝背翁，", "不知有益及民無，二十年來食官祿。就暖移盤簷下食，", "勤操丹筆念黃沙，莫使饑寒囚滯獄。", "急景凋年急於水，念此攬衣中夜起。門無宿客共誰言，", "微酣靜坐未能眠，風霰蕭蕭打窗紙。自問有何才與術，", "請看韋孔與錢崔，半月之間四人死。"]'),
('yuding-15','和微之詩二十三首：和雨中花','白居易','唐','御定全唐诗','yuding','','[]','真宰倒持生殺柄，閑物命長人短命。松枝上鶴蓍下龜，',72,'御定全唐詩/json/445.json','["真宰倒持生殺柄，閑物命長人短命。松枝上鶴蓍下龜，", "何異花開旦暝間，未落仍遭風雨橫。草得經年菜連月，", "桃李無言難自訴，黃鶯解語憑君說。鶯雖為說不分明，"]'),
('yuding-16','和微之詩二十三首：和晨興因報問龜兒','白居易','唐','御定全唐诗','yuding','','[]','冬旦寒慘澹，雲日無晶輝。當此歲暮感，見君晨興詩。',264,'御定全唐詩/json/445.json','["冬旦寒慘澹，雲日無晶輝。當此歲暮感，見君晨興詩。", "君詩亦多苦，苦在兄遠離。我苦不在遠，纏綿肝與脾。", "西院病孀婦，後床孤侄兒。黃昏一慟後，夜半十起時。", "病眼兩行血，衰鬢萬莖絲。咽絕五臟脈，瘦消百骸脂。", "雙目失一目，四肢斷兩肢。不如溘然逝，安用半活為。", "誰謂荼檗苦，荼檗甘如飴。誰謂湯火熱，湯火冷如澌。", "前時君寄詩，憂念問阿龜。喉燥聲氣窒，經年無報辭。", "及睹晨興句，未吟先涕垂。因茲漣洳際，一吐心中悲。", "茫茫四海間，此苦唯君知。去我四千里，使我告訴誰。", "仰頭向青天，但見雁南飛。憑雁寄一語，為我達微之。", "弦絕有續膠，樹斬可接枝。唯我中腸斷，應無連得期。"]'),
('yuding-17','和微之詩二十三首：和朝回與王煉師游南山下','白居易','唐','御定全唐诗','yuding','','[]','藹藹春景餘，峨峨夏雲初。躞蹀退朝騎，飄颻隨風裾。',132,'御定全唐詩/json/445.json','["藹藹春景餘，峨峨夏雲初。躞蹀退朝騎，飄颻隨風裾。", "晨從四丞相，入拜白玉除。暮與一道士，出尋青溪居。", "吏隱本齊致，朝野孰雲殊。道在有中適，機忘無外虞。", "但愧煙霄上，鸞鳳為吾徒。又慚雲林間，鷗鶴不我疏。", "坐傾數杯酒，臥枕一卷書。興酣頭兀兀，睡覺心于於。", "以此送日月，問師為何如。"]'),
('yuding-18','和微之詩二十三首：和嘗新酒','白居易','唐','御定全唐诗','yuding','','[]','空腹嘗新酒，偶成卯時醉。醉來擁褐裘，直至齋時睡。',72,'御定全唐詩/json/445.json','["空腹嘗新酒，偶成卯時醉。醉來擁褐裘，直至齋時睡。", "睡酣不語笑，真寢無夢寐。殆欲忘形骸，詎知屬天地。", "醒餘和未散，起坐澹無事。舉臂一欠伸，引琴彈秋思。"]'),
('yuding-19','和微之詩二十三首：和順之琴者','白居易','唐','御定全唐诗','yuding','','[]','陰陰花院月，耿耿蘭房燭。中有弄琴人，聲貌俱如玉。',48,'御定全唐詩/json/445.json','["陰陰花院月，耿耿蘭房燭。中有弄琴人，聲貌俱如玉。", "清泠石泉引，雅澹風松曲。遂使君子心，不愛凡絲竹。"]'),
('yuding-20','感舊寫真','白居易','唐','御定全唐诗','yuding','','[]','李放寫我真，寫來二十載。莫問真何如，畫亦銷光彩。',48,'御定全唐詩/json/445.json','["李放寫我真，寫來二十載。莫問真何如，畫亦銷光彩。", "朱顏與玄鬢，日夜改複改。無磋貌遽非，且喜身猶在。"]'),
('yuding-21','授太子賓客歸洛','白居易','唐','御定全唐诗','yuding','','[]','南省去拂衣，東都來掩扉。病將老齊至，心與身同歸。',48,'御定全唐詩/json/445.json','["南省去拂衣，東都來掩扉。病將老齊至，心與身同歸。", "白首外緣少，紅塵前事非。懷哉紫芝叟，千載心相依。"]'),
('yuding-22','秋池二首','白居易','唐','御定全唐诗','yuding','','[]','身閑無所為，心閑無所思。況當故園夜，複此新秋池。',144,'御定全唐詩/json/445.json','["身閑無所為，心閑無所思。況當故園夜，複此新秋池。", "岸暗鳥棲後，橋明月出時。菱風香散漫，桂露光參差。", "靜境多獨得，幽懷竟誰知。悠然心中語，自問來何遲。", "朝衣薄且健，晚簟清仍滑。社近燕影稀，雨餘蟬聲歇。", "閑中得詩境，此境幽難說。露荷珠自傾，風竹玉相戛。", "誰能一同宿，共玩新秋月。暑退早涼歸，池邊好時節。"]'),
('yuding-23','中隱','白居易','唐','御定全唐诗','yuding','','[]','大隱住朝市，小隱入丘樊。丘樊太冷落，朝市太囂喧。',192,'御定全唐詩/json/445.json','["大隱住朝市，小隱入丘樊。丘樊太冷落，朝市太囂喧。", "不如作中隱，隱在留司官。似出複似處，非忙亦非閑。", "不勞心與力，又免饑與寒。終歲無公事，隨月有俸錢。", "君若好登臨，城南有秋山。君若愛遊蕩，城東有春園。", "君若欲一醉，時出赴賓筵。洛中多君子，可以恣歡言。", "君若欲高臥，但自深掩關。亦無車馬客，造次到門前。", "人生處一世，其道難兩全。賤即苦凍餒，貴則多憂患。", "唯此中隱士，致身吉且安。窮通與豐約，正在四者間。"]'),
('yuding-24','問秋光','白居易','唐','御定全唐诗','yuding','','[]','殷卿領北鎮，崔尹開南幕。外事信為榮，中懷未必樂。',96,'御定全唐詩/json/445.json','["殷卿領北鎮，崔尹開南幕。外事信為榮，中懷未必樂。", "何如不才者，兀兀無所作。不引窗下琴，即舉池上酌。", "淡交唯對水，老伴無如鶴。自適頗從容，旁觀誠濩落。", "身心轉恬泰，煙景彌淡泊。回首語秋光，東來應不錯。"]'),
('yuding-25','引泉','白居易','唐','御定全唐诗','yuding','','[]','一為止足限，二為衰疾牽。邴罷不因事，陶歸非待年。',96,'御定全唐詩/json/445.json','["一為止足限，二為衰疾牽。邴罷不因事，陶歸非待年。", "歸來嵩洛下，閉戶何翛然。靜掃林下地，閑疏池畔泉。", "伊流狹似帶，洛石大如拳。誰教明月下，為我聲濺濺。", "竟夕舟中坐，有時橋上眠。何用施屏障，水竹繞床前。"]'),
('yuding-26','知足吟','白居易','唐','御定全唐诗','yuding','','[]','不種一隴田，倉中有餘粟。不采一株桑，箱中有餘服。',96,'御定全唐詩/json/445.json','["不種一隴田，倉中有餘粟。不采一株桑，箱中有餘服。", "官閑離憂責，身泰無羈束。中人百戶稅，賓客一年祿。", "樽中不乏酒，籬下仍多菊。是物皆有餘，非心無所欲。", "吟君未貧作，同歌知足曲。自問此時心，不足何時足。"]'),
('yuding-27','酬集賢劉郎中對月見寄，兼懷元浙東','白居易','唐','御定全唐诗','yuding','','[]','月在洛陽天，天高淨如水。下有白頭人，攬衣中夜起。',48,'御定全唐詩/json/445.json','["月在洛陽天，天高淨如水。下有白頭人，攬衣中夜起。", "思遠鏡亭上，光深書殿裏。眇然三處心，相去各千里。"]'),
('yuding-28','太湖石','白居易','唐','御定全唐诗','yuding','','[]','遠望老嵯峨，近觀怪嶔崟。才高八九尺，勢若千萬尋。',120,'御定全唐詩/json/445.json','["遠望老嵯峨，近觀怪嶔崟。才高八九尺，勢若千萬尋。", "嵌空華陽洞，重疊匡山岑。邈矣仙掌迥，呀然劍門深。", "形質冠今古，氣色通晴陰。未秋已瑟瑟，欲雨先沉沉。", "天姿信為異，時用非所任。磨刀不如礪，搗帛不如砧。", "何乃主人意，重之如萬金。豈伊造物者，獨能知我心。"]'),
('yuding-29','偶作二首','白居易','唐','御定全唐诗','yuding','','[]','擾擾貪生人，幾何不夭閼。遑遑愛名人，幾何能貴達。',336,'御定全唐詩/json/445.json','["擾擾貪生人，幾何不夭閼。遑遑愛名人，幾何能貴達。", "伊餘信多幸，拖紫垂白髮。身為三品官，年已五十八。", "筋骸雖早衰，尚未苦羸惙。資產雖不豐，亦不甚貧竭。", "登山力猶在，遇酒興時發。無事日月長，不羈天地闊。", "安身有處所，適意無時節。解帶松下風，抱琴池上月。", "人間所重者，相印將軍鉞。謀慮系安危，威權主生殺。", "焦心一身苦，炙手旁人熱。未必方寸間，得如吾快活。", "日出起盥櫛，振衣入道場。寂然無他念，但對一爐香。", "日高始就食，食亦非膏粱。精粗隨所有，亦足飽充腸。", "日午脫巾簪，燕息窗下床。清風颯然至，臥可致羲皇。", "日西引杖屨，散步游林塘。或飲茶一醆，或吟詩一章。", "日入多不食，有時唯命觴。何以送閑夜，一曲秋霓裳。", "一日分五時，作息率有常。自喜老後健，不嫌閑中忙。", "是非一以貫，身世交相忘。若問此何許，此是無何鄉。"]'),
('yuding-30','葺池上舊亭','白居易','唐','御定全唐诗','yuding','','[]','池月夜淒涼，池風曉蕭颯。欲入池上冬，先葺池上合。',72,'御定全唐詩/json/445.json','["池月夜淒涼，池風曉蕭颯。欲入池上冬，先葺池上合。", "向暖窗戶開，迎寒簾幕合。苔封舊瓦木，水照新朱蠟。", "軟火深土爐，香醪小瓷榼。中有獨宿翁，一燈對一榻。"]'),
('yuding-31','崔十八新池','白居易','唐','御定全唐诗','yuding','','[]','愛君新小池，池色無人知。見底月明夜，無波風定時。',36,'御定全唐詩/json/445.json','["愛君新小池，池色無人知。見底月明夜，無波風定時。", "忽看不似水，一泊稀琉璃。"]'),
('yuding-32','玩止水','白居易','唐','御定全唐诗','yuding','','[]','動者樂流水，靜者樂止水。利物不如流，鑒形不如止。',144,'御定全唐詩/json/445.json','["動者樂流水，靜者樂止水。利物不如流，鑒形不如止。", "淒清早霜降，淅瀝微風起。中面紅葉開，四隅綠萍委。", "廣狹八九丈，灣環有涯涘。淺深三四尺，洞徹無表裏。", "淨分鶴翹足，澄見魚掉尾。迎眸洗眼塵，隔胸蕩心滓。", "定將禪不別，明與誠相似。清能律貪夫，淡可交君子。", "豈唯空狎玩，亦取相倫擬。欲識靜者心，心源只如此。"]'),
('yuding-33','聞崔十八宿予新昌弊宅時予亦宿崔家依仁新亭一宵偶同兩興暗合因而成詠聊以寫懷','白居易','唐','御定全唐诗','yuding','','[]','陋巷掩弊廬，高居敞華屋。新昌七株松，依仁萬莖竹。',72,'御定全唐詩/json/445.json','["陋巷掩弊廬，高居敞華屋。新昌七株松，依仁萬莖竹。", "松前月臺白，竹下風池綠。君向我齋眠，我在君亭宿。", "平生有微尚，彼此多幽獨。何必本主人，兩心聊自足。"]'),
('yuding-34','日長','白居易','唐','御定全唐诗','yuding','','[]','日長晝加餐，夜短朝餘睡。春來寢食間，雖老猶有味。',72,'御定全唐詩/json/445.json','["日長晝加餐，夜短朝餘睡。春來寢食間，雖老猶有味。", "林塘得芳景，園曲生幽致。愛水多棹舟，惜花不掃地。", "幸無眼下病，且向樽前醉。身外何足言，人間本無事。"]'),
('yuding-35','三月三十日作','白居易','唐','御定全唐诗','yuding','','[]','今朝三月盡，寂寞春事畢。黃鳥漸無聲，朱櫻新結實。',72,'御定全唐詩/json/445.json','["今朝三月盡，寂寞春事畢。黃鳥漸無聲，朱櫻新結實。", "臨風獨長歎，此歎意非一。半百過九年，豔陽殘一日。", "隨年減歡笑，逐日添衰疾。且遣花下歌，送此杯中物。"]'),
('yuding-36','慵不能','白居易','唐','御定全唐诗','yuding','','[]','架上非無書，眼慵不能看。匣中亦有琴，手慵不能彈。',72,'御定全唐詩/json/445.json','["架上非無書，眼慵不能看。匣中亦有琴，手慵不能彈。", "腰慵不能帶，頭慵不能冠。午後恣情寢，午時隨事餐。", "一餐終日飽，一寢至夜安。饑寒亦閒事，況乃不饑寒。"]'),
('yuding-37','晨興','白居易','唐','御定全唐诗','yuding','','[]','宿鳥動前林，晨光上東屋。銅爐添早香，紗籠滅殘燭。',60,'御定全唐詩/json/445.json','["宿鳥動前林，晨光上東屋。銅爐添早香，紗籠滅殘燭。", "頭醒風稍愈，眼飽睡初足。起坐兀無思，叩齒三十六。", "何以解宿齋，一杯雲母粥。"]'),
('yuding-38','朝課','白居易','唐','御定全唐诗','yuding','','[]','平甃白石渠，靜掃青苔院。池上好風來，新荷大如扇。',60,'御定全唐詩/json/445.json','["平甃白石渠，靜掃青苔院。池上好風來，新荷大如扇。", "小亭中何有，素琴對黃卷。蕊珠諷數篇，秋思彈一遍。", "從容朝課畢，方與客相見。"]'),
('yuding-39','天竺寺七葉堂避暑','白居易','唐','御定全唐诗','yuding','','[]','鬱鬱複鬱鬱，伏熱何時畢。行入七葉堂，煩暑隨步失。',48,'御定全唐詩/json/445.json','["鬱鬱複鬱鬱，伏熱何時畢。行入七葉堂，煩暑隨步失。", "簷雨稍霏微，窗風正蕭瑟。清宵一覺睡，可以銷百疾。"]'),
('yuding-40','香山寺石樓潭夜浴','白居易','唐','御定全唐诗','yuding','','[]','炎光晝方熾，暑氣宵彌毒。搖扇風甚微，褰裳汗霢霂。',72,'御定全唐詩/json/445.json','["炎光晝方熾，暑氣宵彌毒。搖扇風甚微，褰裳汗霢霂。", "起向月下行，來就潭中浴。平石為浴床，窪石為浴斛。", "綃巾薄露頂，草屨輕乘足。清涼詠而歸，歸上石樓宿。"]'),
('yuding-41','嗟發落','白居易','唐','御定全唐诗','yuding','','[]','朝亦嗟發落，暮亦嗟發落。落盡誠可嗟，盡來亦不惡。',96,'御定全唐詩/json/445.json','["朝亦嗟發落，暮亦嗟發落。落盡誠可嗟，盡來亦不惡。", "既不勞洗沐，又不煩梳掠。最宜濕暑天，頭輕無髻縛。", "脫置垢巾幘，解去塵纓絡。銀瓶貯寒泉，當頂傾一勺。", "有如醍醐灌，坐受清涼樂。因悟自在僧，亦資於剃削。"]'),
('yuding-42','安穩眠','白居易','唐','御定全唐诗','yuding','','[]','家雖日漸貧，猶未苦饑凍。身雖日漸老，幸無急病痛。',48,'御定全唐詩/json/445.json','["家雖日漸貧，猶未苦饑凍。身雖日漸老，幸無急病痛。", "眼逢鬧處合，心向閒時用。既得安穩眠，亦無顛倒夢。"]'),
('yuding-43','池上夜境','白居易','唐','御定全唐诗','yuding','','[]','晴空星月落池塘，澄鮮淨綠表裏光。露簟清瑩迎夜滑，',40,'御定全唐詩/json/445.json','["晴空星月落池塘，澄鮮淨綠表裏光。露簟清瑩迎夜滑，", "但問塵埃能去否，濯纓何必向滄浪。"]'),
('yuding-44','書紳','白居易','唐','御定全唐诗','yuding','','[]','仕有職役勞，農有畎畝勤。優哉分司叟，心力無苦辛。',120,'御定全唐詩/json/445.json','["仕有職役勞，農有畎畝勤。優哉分司叟，心力無苦辛。", "歲晚頭又白，自問何欣欣。新酒始開甕，舊谷猶滿囷。", "吾嘗靜自思，往往夜達晨。何以送吾老，何以安吾貧。", "歲計莫如穀，飽則不幹人。日計莫如醉，醉則兼忘身。", "誠知有道理，未敢勸交親。恐為人所哂，聊自書諸紳。"]'),
('yuding-45','秋游平泉，贈韋處士、閑禪師','白居易','唐','御定全唐诗','yuding','','[]','秋景引閒步，山遊不知疲。杖藜舍輿馬，十裏與僧期。',96,'御定全唐詩/json/445.json','["秋景引閒步，山遊不知疲。杖藜舍輿馬，十裏與僧期。", "昔嘗憂六十，四體不支持。今來已及此，猶未苦衰羸。", "心興遇境發，身力因行知。尋雲到起處，愛泉聽滴時。", "南村韋處士，西寺閑禪師。山頭與澗底，聞健且相隨。"]'),
('yuding-46','遊坊口懸泉，偶題石上','白居易','唐','御定全唐诗','yuding','','[]','濟源山水好，老尹知之久。常日聽人言，今秋入吾手。',168,'御定全唐詩/json/445.json','["濟源山水好，老尹知之久。常日聽人言，今秋入吾手。", "孔山刀劍立，沁水龍蛇走。危磴上懸泉，澄灣轉坊口。", "虛明見深底，淨綠無纖垢。仙棹浪悠揚，塵纓風斗藪。", "岩寒松柏短，石古莓苔厚。錦坐纓高低，翠屏張左右。", "雖無安石妓，不乏文舉酒。談笑逐身來，管弦隨事有。", "時逢杖錫客，或值垂綸叟。相與澹忘歸，自辰將及酉。", "公門欲返駕，溪路猶回首。早晚重來遊，心期罷官後。"]'),
('yuding-47','對火玩雪','白居易','唐','御定全唐诗','yuding','','[]','平生所心愛，愛火兼憐雪。火是臘天春，雪為陰夜月。',96,'御定全唐詩/json/445.json','["平生所心愛，愛火兼憐雪。火是臘天春，雪為陰夜月。", "鵝毛紛正墮，獸炭敲初折。盈尺白鹽寒，滿爐紅玉熱。", "稍宜杯酌動，漸引笙歌發。但識歡來由，不知醉時節。", "銀盤堆柳絮，羅袖摶瓊屑。共愁明日銷，便作經年別。"]'),
('yuding-48','六年寒食洛下宴游，贈馮、李二少尹','白居易','唐','御定全唐诗','yuding','','[]','豐年寒食節，美景洛陽城。三尹皆強健，七日盡晴明。',132,'御定全唐詩/json/445.json','["豐年寒食節，美景洛陽城。三尹皆強健，七日盡晴明。", "東郊蹋青草，南園攀紫荊。風拆海榴豔，露墜木蘭英。", "假開春未老，宴合日屢傾。珠翠混花影，管弦藏水聲。", "佳會不易得，良辰亦難並。聽吟歌暫輟，看舞杯徐行。", "米價賤如土，酒味濃於餳。此時不盡醉，但恐負平生。", "殷勤二曹長，各捧一銀觥。"]'),
('yuding-49','苦熱中寄舒員外','白居易','唐','御定全唐诗','yuding','','[]','何堪日衰病，複此時炎燠。厭對俗杯盤，倦聽凡絲竹。',60,'御定全唐詩/json/445.json','["何堪日衰病，複此時炎燠。厭對俗杯盤，倦聽凡絲竹。", "藤床鋪晚雪，角枕截寒玉。安得清瘦人，新秋夜同宿。", "非君固不可，何夕枉高躅。"]'),
('yuding-50','閑夕','白居易','唐','御定全唐诗','yuding','','[]','一聲早蟬發，數點新螢度。蘭釭耿無煙，筠簟清有露。',72,'御定全唐詩/json/445.json','["一聲早蟬發，數點新螢度。蘭釭耿無煙，筠簟清有露。", "未歸後房寢，且下前軒步。斜月入低廊，涼風滿高樹。", "放懷常自適，遇境多成趣。何法使之然，心中無細故。"]'),
('yuding-51','寄情','白居易','唐','御定全唐诗','yuding','','[]','灼灼早春梅，東南枝最早。持來玩未足，花向手中老。',48,'御定全唐詩/json/445.json','["灼灼早春梅，東南枝最早。持來玩未足，花向手中老。", "芳香銷掌握，悵望生懷抱。豈無後開花，念此先開好。"]'),
('yuding-52','舒員外遊香山寺數日不歸兼辱尺書大誇勝事時正值坐衙慮囚之際走筆題長句以贈之','白居易','唐','御定全唐诗','yuding','','[]','香山石樓倚天開，翠屏壁立波環回。黃菊繁時好客到，',72,'御定全唐詩/json/445.json','["香山石樓倚天開，翠屏壁立波環回。黃菊繁時好客到，", "軒騎逶遲棹容與，留連三日不能回。白頭老尹府中坐，", "豈無池塘長秋草，亦有絲竹生塵埃。今日清光昨夜月，"]'),
('yuding-53','早冬遊王屋自靈都抵陽臺上方望天壇偶吟成章寄溫谷周尊師中書李相公','白居易','唐','御定全唐诗','yuding','','[]','霜降山水清，王屋十月時。石泉碧漾漾，岩樹紅離離。',168,'御定全唐詩/json/445.json','["霜降山水清，王屋十月時。石泉碧漾漾，岩樹紅離離。", "朝為靈都遊，暮有陽臺期。飄然世塵外，鸞鶴如可追。", "忽念公程盡，複慚身力衰。天壇在天半，欲上心遲遲。", "嘗聞此遊者，隱客與損之。各抱貴仙骨，俱非泥垢姿。", "二人相顧言，彼此稱男兒。若不為松喬，即須作皋夔。", "今果如其語，光彩雙葳蕤。一人佩金印，一人翳玉芝。", "我來高其事，詠歎偶成詩。為君題石上，欲使故山知。"]'),
('yuding-54','吳宮辭','白居易','唐','御定全唐诗','yuding','','[]','淡紅花帔淺檀蛾，睡臉初開似剪波。',32,'御定全唐詩/json/445.json','["淡紅花帔淺檀蛾，睡臉初開似剪波。", "坐對珠籠閑理曲，琵琶鸚鵡語相和。"]'),
('yuding-0','元微之除浙東觀察使，喜得杭越鄰州，先贈長句','白居易','唐','御定全唐诗','yuding','','[]','稽山鏡水歡遊地，犀帶金章榮貴身。官職比君雖校小，',40,'御定全唐詩/json/446.json','["稽山鏡水歡遊地，犀帶金章榮貴身。官職比君雖校小，", "杭越風光詩酒主，相看更合與何人。"]'),
('yuding-1','席上答微之','白居易','唐','御定全唐诗','yuding','','[]','我住浙江西，君去浙江東。勿言一水隔，便與千里同。',40,'御定全唐詩/json/446.json','["我住浙江西，君去浙江東。勿言一水隔，便與千里同。", "富貴無人勸君酒，今宵為我盡杯中。"]'),
('yuding-2','答微之上船後留別','白居易','唐','御定全唐诗','yuding','','[]','燭下尊前一分手，舟中岸上兩回頭。',32,'御定全唐詩/json/446.json','["燭下尊前一分手，舟中岸上兩回頭。", "歸來虛白堂中夢，合眼先應到越州。"]'),
('yuding-3','答微之泊西陵驛見寄','白居易','唐','御定全唐诗','yuding','','[]','煙波盡處一點白，應是西陵古驛台。',32,'御定全唐詩/json/446.json','["煙波盡處一點白，應是西陵古驛台。", "知在台邊望不見，暮潮空送渡船回。"]'),
('yuding-4','答微之誇越州州宅','白居易','唐','御定全唐诗','yuding','','[]','賀上人回得報書，大誇州宅似仙居。厭看馮翊風沙久，',40,'御定全唐詩/json/446.json','["賀上人回得報書，大誇州宅似仙居。厭看馮翊風沙久，", "知君暗數江南郡，除卻餘杭盡不如。"]'),
('yuding-5','微之重誇州居其落句有西州羅刹之謔因嘲茲石聊以寄懷','白居易','唐','御定全唐诗','yuding','','[]','君問西州城下事，醉中疊紙為君書。嵌空石面標羅刹，',40,'御定全唐詩/json/446.json','["君問西州城下事，醉中疊紙為君書。嵌空石面標羅刹，", "誰知太守心相似，抵滯堅頑兩有餘。"]'),
('yuding-6','張十八員外以新詩二十五首見寄郡樓月下吟玩通夕因題卷後封寄微之','白居易','唐','御定全唐诗','yuding','','[]','秦城南省清秋夜，江郡東樓明月時。去我三千六百里，',40,'御定全唐詩/json/446.json','["秦城南省清秋夜，江郡東樓明月時。去我三千六百里，", "坐到天明吟未足，重封轉寄與微之。"]'),
('yuding-7','酬微之','白居易','唐','御定全唐诗','yuding','','[]','滿帙填箱唱和詩，少年為戲老成悲。聲聲麗曲敲寒玉，',40,'御定全唐詩/json/446.json','["滿帙填箱唱和詩，少年為戲老成悲。聲聲麗曲敲寒玉，", "由來才命相磨折，天遣無兒欲怨誰。"]'),
('yuding-8','餘思未盡，加為六韻，重寄微之','白居易','唐','御定全唐诗','yuding','','[]','海內聲華並在身，篋中文字絕無倫。遙知獨對封章草，',48,'御定全唐詩/json/446.json','["海內聲華並在身，篋中文字絕無倫。遙知獨對封章草，", "制從長慶辭高古，詩到元和體變新。各有文姬才稚齒，"]'),
('yuding-9','答微之詠懷見寄','白居易','唐','御定全唐诗','yuding','','[]','合中同直前春事，船裏相逢昨日情。分袂二年勞夢寐，',40,'御定全唐詩/json/446.json','["合中同直前春事，船裏相逢昨日情。分袂二年勞夢寐，", "聚散窮通何足道，醉來一曲放歌行。"]'),
('yuding-10','酬微之誇鏡湖','白居易','唐','御定全唐诗','yuding','','[]','我嗟身老歲方徂，君更官高興轉孤。軍門郡閣曾閑否，',40,'御定全唐詩/json/446.json','["我嗟身老歲方徂，君更官高興轉孤。軍門郡閣曾閑否，", "一泓鏡水誰能羨，自有胸中萬頃湖。"]'),
('yuding-11','雪中即事答微之','白居易','唐','御定全唐诗','yuding','','[]','連夜江雲黃慘澹，平明山雪白模糊。銀河沙漲三千里，',88,'御定全唐詩/json/446.json','["連夜江雲黃慘澹，平明山雪白模糊。銀河沙漲三千里，", "誰家高士關門戶，何處行人失道途。舞鶴庭前毛稍定，", "壓瘴一州除疾苦，呈豐萬井盡歡娛。潤含玉德懷君子，", "越中地暖多成雨，還有瑤台瓊樹無。"]'),
('yuding-12','醉封詩筒寄微之','白居易','唐','御定全唐诗','yuding','','[]','一生休戚與窮通，處處相隨事事同。未死又憐滄海郡，',40,'御定全唐詩/json/446.json','["一生休戚與窮通，處處相隨事事同。未死又憐滄海郡，", "為向兩州郵吏道，莫辭來去遞詩筒。"]'),
('yuding-13','除夜寄微之','白居易','唐','御定全唐诗','yuding','','[]','鬢毛不覺白毿毿，一事無成百不堪。共惜盛時辭闕下，',40,'御定全唐詩/json/446.json','["鬢毛不覺白毿毿，一事無成百不堪。共惜盛時辭闕下，", "老校於君合先退，明年半百又加三。"]'),
('yuding-14','蘇州李中丞以元日郡齋感懷詩寄微之及予輒依來篇七言八韻走筆奉答兼呈微之','白居易','唐','御定全唐诗','yuding','','[]','白首餘杭白太守，落魄拋名來已久。一辭渭北故園春，',72,'御定全唐詩/json/446.json','["白首餘杭白太守，落魄拋名來已久。一辭渭北故園春，", "領郡慚當潦倒年，鄰州喜得平生友。長洲草接松江岸，", "憑鶯傳語報李六，倩雁將書與元九。莫嗟一日日催人，"]'),
('yuding-15','早春西湖閒遊悵然興懷憶與微之同賞因思在越官重事殷鏡湖之遊或恐未暇偶成十八韻寄微之','白居易','唐','御定全唐诗','yuding','','[]','上馬複呼賓，湖邊景氣新。管弦三數事，騎從十餘人。',216,'御定全唐詩/json/446.json','["上馬複呼賓，湖邊景氣新。管弦三數事，騎從十餘人。", "立換登山屐，行攜漉酒巾。逢花看當妓，遇草坐為茵。", "西日籠黃柳，東風蕩白蘋。小橋裝雁齒，輕浪甃魚鱗。", "畫舫牽徐轉，銀船酌慢巡。野情遺世累，醉態任天真。", "彼此年將老，平生分最親。高天從所願，遠地得為鄰。", "雲樹分三驛，煙波限一津。翻嗟寸步隔，卻厭尺書頻。", "浙右稱雄鎮，山陰委重臣。貴垂長紫綬，榮駕大朱輪。", "出動刀槍隊，歸生道路塵。雁驚弓易散，鷗怕鼓難馴。", "百吏瞻相面，千夫捧擁身。自然閑興少，應負鏡湖春。"]'),
('yuding-16','答微之見寄','白居易','唐','御定全唐诗','yuding','','[]','可憐風景浙東西，先數餘杭次會稽。禹廟未勝天竺寺，',40,'御定全唐詩/json/446.json','["可憐風景浙東西，先數餘杭次會稽。禹廟未勝天竺寺，", "更對雪樓君愛否，紅欄碧甃點銀泥。"]'),
('yuding-17','祭社宵興燈前偶作','白居易','唐','御定全唐诗','yuding','','[]','城頭傳鼓角，燈下整衣冠。夜鏡藏須白，秋泉漱齒寒。',48,'御定全唐詩/json/446.json','["城頭傳鼓角，燈下整衣冠。夜鏡藏須白，秋泉漱齒寒。", "欲將閑送老，須著病辭官。更待年終後，支持歸計看。"]'),
('yuding-18','閑臥','白居易','唐','御定全唐诗','yuding','','[]','盡日前軒臥，神閑境亦空。有山當枕上，無事到心中。',48,'御定全唐詩/json/446.json','["盡日前軒臥，神閑境亦空。有山當枕上，無事到心中。", "簾卷侵床日，屏遮入座風。望春春未到，應在海門東。"]'),
('yuding-19','新春江次','白居易','唐','御定全唐诗','yuding','','[]','浦幹潮未應，堤濕凍初銷。粉片妝梅朵，金絲刷柳條。',48,'御定全唐詩/json/446.json','["浦幹潮未應，堤濕凍初銷。粉片妝梅朵，金絲刷柳條。", "鴨頭新綠水，雁齒小紅橋。莫怪珂聲碎，春來五馬驕。"]'),
('yuding-20','春題湖上','白居易','唐','御定全唐诗','yuding','','[]','湖上春來似畫圖，亂峰圍繞水準鋪。松排山面千重翠，',40,'御定全唐詩/json/446.json','["湖上春來似畫圖，亂峰圍繞水準鋪。松排山面千重翠，", "未能拋得杭州去，一半句留是此湖。"]'),
('yuding-21','早春憶微之','白居易','唐','御定全唐诗','yuding','','[]','昏昏老與病相和，感物思君歎複歌。聲早雞先知夜短，',40,'御定全唐詩/json/446.json','["昏昏老與病相和，感物思君歎複歌。聲早雞先知夜短，", "可道眼前光景惡，其如難見故人何。"]'),
('yuding-22','失鶴','白居易','唐','御定全唐诗','yuding','','[]','失為庭前雪，飛因海上風。九霄應得侶，三夜不歸籠。',48,'御定全唐詩/json/446.json','["失為庭前雪，飛因海上風。九霄應得侶，三夜不歸籠。", "聲斷碧雲外，影沉明月中。郡齋從此後，誰伴白頭翁。"]'),
('yuding-23','自感','白居易','唐','御定全唐诗','yuding','','[]','宴遊寢食漸無味，杯酒管弦徒繞身。',32,'御定全唐詩/json/446.json','["宴遊寢食漸無味，杯酒管弦徒繞身。", "賓客歡娛僮僕飽，始知官職為他人。"]'),
('yuding-24','得湖州崔十八使君書喜與杭越鄰郡因成長句代賀兼寄微之','白居易','唐','御定全唐诗','yuding','','[]','三郡何因此結緣，貞元科第忝同年。故情歡喜開書後，',40,'御定全唐詩/json/446.json','["三郡何因此結緣，貞元科第忝同年。故情歡喜開書後，", "吳興卑小君應屈，為是蓬萊最後仙。"]'),
('yuding-25','同諸客攜酒早看櫻桃花','白居易','唐','御定全唐诗','yuding','','[]','曉報櫻桃發，春攜酒客過。綠餳粘盞杓，紅雪壓枝柯。',48,'御定全唐詩/json/446.json','["曉報櫻桃發，春攜酒客過。綠餳粘盞杓，紅雪壓枝柯。", "天色晴明少，人生事故多。停杯替花語，不醉擬如何。"]'),
('yuding-26','柳絮','白居易','唐','御定全唐诗','yuding','','[]','三月儘是頭白日，與春老別更依依。',32,'御定全唐詩/json/446.json','["三月儘是頭白日，與春老別更依依。", "憑鶯為向楊花道，絆惹春風莫放歸。"]'),
('yuding-27','早飲湖州酒，寄崔使君','白居易','唐','御定全唐诗','yuding','','[]','一榼扶頭酒，泓澄瀉玉壺。十分蘸甲酌，瀲豔滿銀盂。',72,'御定全唐詩/json/446.json','["一榼扶頭酒，泓澄瀉玉壺。十分蘸甲酌，瀲豔滿銀盂。", "捧出光華動，嘗看氣味殊。手中稀琥珀，舌上冷醍醐。", "瓶裏有時盡，江邊無處沽。不知崔太守，更有寄來無。"]'),
('yuding-28','病中書事','白居易','唐','御定全唐诗','yuding','','[]','三載臥山城，閑知節物情。鶯多過春語，蟬不待秋鳴。',48,'御定全唐詩/json/446.json','["三載臥山城，閑知節物情。鶯多過春語，蟬不待秋鳴。", "氣嗽因寒發，風痰欲雨生。病身無所用，唯解卜陰晴。"]'),
('yuding-29','與微之唱和來去常以竹筒貯詩陳協律美而成篇因以此答','白居易','唐','御定全唐诗','yuding','','[]','揀得琅玕截作筒，緘題章句寫心胸。隨風每喜飛如鳥，',40,'御定全唐詩/json/446.json','["揀得琅玕截作筒，緘題章句寫心胸。隨風每喜飛如鳥，", "煩君贊詠心知愧，魚目驪珠同一封。"]'),
('yuding-30','醉戲諸妓','白居易','唐','御定全唐诗','yuding','','[]','席上爭飛使君酒，歌中多唱舍人詩。',32,'御定全唐詩/json/446.json','["席上爭飛使君酒，歌中多唱舍人詩。", "不知明日休官後，逐我東山去是誰。"]'),
('yuding-31','北院','白居易','唐','御定全唐诗','yuding','','[]','北院人稀到，東窗事最偏。竹煙行灶上，石壁臥房前。',48,'御定全唐詩/json/446.json','["北院人稀到，東窗事最偏。竹煙行灶上，石壁臥房前。", "性拙身多暇，心慵事少緣。還如病居士，唯置一床眠。"]'),
('yuding-32','酬周協律','白居易','唐','御定全唐诗','yuding','','[]','五十錢唐守，應為送老官。濫蒙辭客愛，猶作近臣看。',48,'御定全唐詩/json/446.json','["五十錢唐守，應為送老官。濫蒙辭客愛，猶作近臣看。", "鑿落愁須飲，琵琶悶遣彈。白頭雖強醉，不似少年歡。"]'),
('yuding-33','題石山人','白居易','唐','御定全唐诗','yuding','','[]','騰騰兀兀在人間，貴賤賢愚盡往還。膻膩筵中唯飲酒，',40,'御定全唐詩/json/446.json','["騰騰兀兀在人間，貴賤賢愚盡往還。膻膩筵中唯飲酒，", "除卻餘杭白太守，何人更解愛君閑。"]'),
('yuding-34','詩解','白居易','唐','御定全唐诗','yuding','','[]','新篇日日成，不是愛聲名。舊句時時改，無妨悅性情。',48,'御定全唐詩/json/446.json','["新篇日日成，不是愛聲名。舊句時時改，無妨悅性情。", "但令長守郡，不覺卻歸城。只擬江湖上，吟哦過一生。"]'),
('yuding-35','潮','白居易','唐','御定全唐诗','yuding','','[]','早潮才落晚潮來，一月周流六十回。',32,'御定全唐詩/json/446.json','["早潮才落晚潮來，一月周流六十回。", "不獨光陰朝複暮，杭州老去被潮催。"]'),
('yuding-36','聞歌妓唱嚴郎中詩，因以絕句寄之','白居易','唐','御定全唐诗','yuding','','[]','已留舊政布中和，又付新詞與豔歌。',32,'御定全唐詩/json/446.json','["已留舊政布中和，又付新詞與豔歌。", "但是人家有遺愛，就中蘇小感恩多。"]'),
('yuding-37','柘枝妓','白居易','唐','御定全唐诗','yuding','','[]','平鋪一合錦筵開，連擊三聲畫鼓催。紅蠟燭移桃葉起，',40,'御定全唐詩/json/446.json','["平鋪一合錦筵開，連擊三聲畫鼓催。紅蠟燭移桃葉起，", "看即曲終留不住，雲飄雨送向陽臺。"]'),
('yuding-38','《急樂世辭','白居易','唐','御定全唐诗','yuding','','[]','正抽碧線繡紅羅，忽聽黃鶯斂翠蛾。',32,'御定全唐詩/json/446.json','["正抽碧線繡紅羅，忽聽黃鶯斂翠蛾。", "秋思冬愁春悵望，大都不稱意時多。"]'),
('yuding-39','天竺寺送堅上人歸廬山','白居易','唐','御定全唐诗','yuding','','[]','錫杖登高寺，香爐憶舊峰。偶來舟不系，忽去鳥無蹤。',48,'御定全唐詩/json/446.json','["錫杖登高寺，香爐憶舊峰。偶來舟不系，忽去鳥無蹤。", "豈要留離偈，甯勞動別容。與師俱是夢，夢裏暫相逢。"]'),
('yuding-40','除官赴闕，留贈微之','白居易','唐','御定全唐诗','yuding','','[]','去年十月半，君來過浙東。今年五月盡，我發向關中。',48,'御定全唐詩/json/446.json','["去年十月半，君來過浙東。今年五月盡，我發向關中。", "兩鄉默默心相別，一水盈盈路不通。從此津人應省事，"]'),
('yuding-41','留題郡齋','白居易','唐','御定全唐诗','yuding','','[]','吟山歌水嘲風月，便是三年官滿時。春為醉眠多閉合，',24,'御定全唐詩/json/446.json','["吟山歌水嘲風月，便是三年官滿時。春為醉眠多閉合，"]'),
('yuding-42','別州民','白居易','唐','御定全唐诗','yuding','','[]','耆老遮歸路，壺漿滿別筵。甘棠無一樹，那得淚潸然。',48,'御定全唐詩/json/446.json','["耆老遮歸路，壺漿滿別筵。甘棠無一樹，那得淚潸然。", "稅重多貧戶，農饑足旱田。唯留一湖水，與汝救凶年。"]'),
('yuding-43','留題天竺、靈隱兩寺','白居易','唐','御定全唐诗','yuding','','[]','在郡六百日，入山十二回。宿因月桂落，醉為海榴開。',96,'御定全唐詩/json/446.json','["在郡六百日，入山十二回。宿因月桂落，醉為海榴開。", "黃紙除書到，青宮詔命催。僧徒多悵望，賓從亦裴回。", "寺闇煙埋竹，林香雨落梅。別橋憐白石，辭洞戀青苔。", "漸出松間路，猶飛馬上杯。誰教冷泉水，送我下山來。"]'),
('yuding-44','西湖留別','白居易','唐','御定全唐诗','yuding','','[]','征途行色慘風煙，祖帳離聲咽管弦。翠黛不須留五馬，',40,'御定全唐詩/json/446.json','["征途行色慘風煙，祖帳離聲咽管弦。翠黛不須留五馬，", "處處回頭盡堪戀，就中難別是湖邊。"]'),
('yuding-45','重寄別微之','白居易','唐','御定全唐诗','yuding','','[]','憑仗江波寄一辭，不須惆悵報微之。',32,'御定全唐詩/json/446.json','["憑仗江波寄一辭，不須惆悵報微之。", "猶勝往歲峽中別，灩澦堆邊招手時。"]'),
('yuding-46','重題別東樓','白居易','唐','御定全唐诗','yuding','','[]','東樓勝事我偏知，氣象多隨昏旦移。湖卷衣裳白重疊，',48,'御定全唐詩/json/446.json','["東樓勝事我偏知，氣象多隨昏旦移。湖卷衣裳白重疊，", "春雨星攢尋蟹火，秋風霞颭弄濤旗。宴宜雲髻新梳後，"]'),
('yuding-47','別周軍事','白居易','唐','御定全唐诗','yuding','','[]','主人頭白官仍冷，去後憐君是底人。',32,'御定全唐詩/json/446.json','["主人頭白官仍冷，去後憐君是底人。", "試謁會稽元相去，不妨相見卻殷勤。"]'),
('yuding-48','看常州柘枝，贈賈使君','白居易','唐','御定全唐诗','yuding','','[]','莫惜新衣舞柘枝，也從塵汙汗沾垂。',32,'御定全唐詩/json/446.json','["莫惜新衣舞柘枝，也從塵汙汗沾垂。", "料君即卻歸朝去，不見銀泥衫故時。"]'),
('yuding-49','汴河路有感','白居易','唐','御定全唐诗','yuding','','[]','三十年前路，孤舟重往還。繞身新眷屬，舉目舊鄉關。',48,'御定全唐詩/json/446.json','["三十年前路，孤舟重往還。繞身新眷屬，舉目舊鄉關。", "事去唯留水，人非但見山。啼襟與愁鬢，此日兩成斑。"]'),
('yuding-50','埇橋舊業','白居易','唐','御定全唐诗','yuding','','[]','別業埇城北，拋來二十春。改移新徑路，變換舊村鄰。',48,'御定全唐詩/json/446.json','["別業埇城北，拋來二十春。改移新徑路，變換舊村鄰。", "有稅田疇薄，無官弟侄貧。田園何用問，強半屬他人。"]'),
('yuding-51','茅城驛','白居易','唐','御定全唐诗','yuding','','[]','汴河無景思，秋日又淒淒。地薄桑麻瘦，村貧屋舍低。',48,'御定全唐詩/json/446.json','["汴河無景思，秋日又淒淒。地薄桑麻瘦，村貧屋舍低。", "早苗多間草，濁水半和泥。最是蕭條處，茅城驛向西。"]'),
('yuding-52','河陰夜泊憶微之','白居易','唐','御定全唐诗','yuding','','[]','憶君我正泊行舟，望我君應上郡樓。',32,'御定全唐詩/json/446.json','["憶君我正泊行舟，望我君應上郡樓。", "萬里月明同此夜，黃河東面海西頭。"]'),
('yuding-53','杭州回舫','白居易','唐','御定全唐诗','yuding','','[]','自別錢塘山水後，不多飲酒懶吟詩。',32,'御定全唐詩/json/446.json','["自別錢塘山水後，不多飲酒懶吟詩。", "欲將此意憑回棹，報與西湖風月知。"]'),
('yuding-54','途中題山泉','白居易','唐','御定全唐诗','yuding','','[]','決決湧岩穴，濺濺出洞門。向東應入海，從此不歸源。',48,'御定全唐詩/json/446.json','["決決湧岩穴，濺濺出洞門。向東應入海，從此不歸源。", "似葉飄辭樹，如雲斷別根。吾身亦如此，何日返鄉園。"]'),
('yuding-55','欲到東洛，得楊使君書，因以此報','白居易','唐','御定全唐诗','yuding','','[]','向公心切向財疏，淮上休官洛下居。三郡政能從獨步，',40,'御定全唐詩/json/446.json','["向公心切向財疏，淮上休官洛下居。三郡政能從獨步，", "且喜平安又相見，其餘外事盡空虛。"]'),
('yuding-56','洛下寓居','白居易','唐','御定全唐诗','yuding','','[]','秋館清涼日，書因解悶看。夜窗幽獨處，琴不為人彈。',72,'御定全唐詩/json/446.json','["秋館清涼日，書因解悶看。夜窗幽獨處，琴不為人彈。", "遊宴慵多廢，趨朝老漸難。禪僧教斷酒，道士勸休官。", "渭曲莊猶在，錢唐俸尚殘。如能便歸去，亦不至饑寒。"]'),
('yuding-57','味道','白居易','唐','御定全唐诗','yuding','','[]','叩齒晨興秋院靜，焚香冥坐晚窗深。七篇真誥論仙事，',40,'御定全唐詩/json/446.json','["叩齒晨興秋院靜，焚香冥坐晚窗深。七篇真誥論仙事，", "自嫌習性猶殘處，愛詠閑詩好聽琴。"]'),
('yuding-58','好聽琴','白居易','唐','御定全唐诗','yuding','','[]','本性好絲桐，塵機聞即空。一聲來耳裏，萬事離心中。',48,'御定全唐詩/json/446.json','["本性好絲桐，塵機聞即空。一聲來耳裏，萬事離心中。", "清暢堪銷疾，恬和好養蒙。尤宜聽三樂，安慰白頭翁。"]'),
('yuding-59','愛詠詩','白居易','唐','御定全唐诗','yuding','','[]','辭章諷詠成千首，心行歸依向一乘。',32,'御定全唐詩/json/446.json','["辭章諷詠成千首，心行歸依向一乘。", "坐倚繩床閑自念，前生應是一詩僧。"]'),
('yuding-60','酬皇甫庶子見寄','白居易','唐','御定全唐诗','yuding','','[]','掌綸不稱吾應笑，典郡無能我自知。別詔忽驚新命出，',40,'御定全唐詩/json/446.json','["掌綸不稱吾應笑，典郡無能我自知。別詔忽驚新命出，", "獨佔二疏應未可，龍樓見擬覓分司。"]'),
('yuding-61','臥疾','白居易','唐','御定全唐诗','yuding','','[]','閑官臥疾絕經過，居處蕭條近洛河。',32,'御定全唐詩/json/446.json','["閑官臥疾絕經過，居處蕭條近洛河。", "水北水南秋月夜，管弦聲少杵聲多。"]'),
('yuding-62','遠師','白居易','唐','御定全唐诗','yuding','','[]','東宮白庶子，南寺遠禪師。何處遙相見，心無一事時。',24,'御定全唐詩/json/446.json','["東宮白庶子，南寺遠禪師。何處遙相見，心無一事時。"]'),
('yuding-63','問遠師','白居易','唐','御定全唐诗','yuding','','[]','葷膻停夜食，吟詠散秋懷。笑問東林老，詩應不破齋。',24,'御定全唐詩/json/446.json','["葷膻停夜食，吟詠散秋懷。笑問東林老，詩應不破齋。"]'),
('yuding-64','小院酒醒','白居易','唐','御定全唐诗','yuding','','[]','酒醒閑獨步，小院夜深涼。一領新秋簟，三間明月廊。',48,'御定全唐詩/json/446.json','["酒醒閑獨步，小院夜深涼。一領新秋簟，三間明月廊。", "未收殘盞杓，初換熱衣裳。好是幽眠處，松陰六尺床。"]'),
('yuding-65','贈侯三郎中','白居易','唐','御定全唐诗','yuding','','[]','老愛東都好寄身，足泉多竹少埃塵。年豐最喜唯貧客，',40,'御定全唐詩/json/446.json','["老愛東都好寄身，足泉多竹少埃塵。年豐最喜唯貧客，", "洛中縱未長居得，且與蘇田遊過春。"]'),
('yuding-66','求分司東都，寄牛相公十韻','白居易','唐','御定全唐诗','yuding','','[]','忽忽心如夢，星星鬢似絲。縱貧長有酒，雖老未拋詩。',120,'御定全唐詩/json/446.json','["忽忽心如夢，星星鬢似絲。縱貧長有酒，雖老未拋詩。", "儉薄身都慣，疏頑性頗宜。飯粗餐亦飽，被暖起常遲。", "萬里歸何得，三年伴是誰。華亭鶴不去，天竺石相隨。", "王尹貰將馬，田家賣與池。開門閑坐日，繞水獨行時。", "懶慢交遊許，衰羸相府知。官寮幸無事，可惜不分司。"]'),
('yuding-67','酬楊八','白居易','唐','御定全唐诗','yuding','','[]','君以曠懷宜靜境，我因蹇步稱閑官。',32,'御定全唐詩/json/446.json','["君以曠懷宜靜境，我因蹇步稱閑官。", "閉門足病非高士，勞作雲心鶴眼看。"]'),
('yuding-68','履道新居二十韻','白居易','唐','御定全唐诗','yuding','','[]','履道坊西角，官河曲北頭。林園四鄰好，風景一家秋。',240,'御定全唐詩/json/446.json','["履道坊西角，官河曲北頭。林園四鄰好，風景一家秋。", "門閉深沈樹，池通淺沮溝。拔青松直上，鋪碧水準流。", "籬菊黃金合，窗筠綠玉稠。疑連紫陽洞，似到白蘋洲。", "僧至多同宿，賓來輒少留。豈無詩引興，兼有酒銷憂。", "移榻臨平岸，攜茶上小舟。果穿聞鳥啄，萍破見魚遊。", "地與塵相遠，人將境共幽。泛潭菱點鏡，沉浦月生鉤。", "廚曉煙孤起，庭寒雨半收。老饑初愛粥，瘦冷早披裘。", "洛下招新隱，秦中忘舊遊。辭章留鳳閣，班籍寄龍樓。", "病愜官曹靜，閑慚俸祿優。琴書中有得，衣食外何求。", "濟世才無取，謀身智不周。應須共心語，萬事一時休。"]'),
('yuding-69','九日思杭州舊游，寄周判官及諸客','白居易','唐','御定全唐诗','yuding','','[]','忽憶郡南山頂上，昔時同醉是今辰。笙歌委曲聲延耳，',40,'御定全唐詩/json/446.json','["忽憶郡南山頂上，昔時同醉是今辰。笙歌委曲聲延耳，", "江山賓客皆如舊，唯是當筵換主人。"]'),
('yuding-70','秋晚','白居易','唐','御定全唐诗','yuding','','[]','煙景淡濛濛，池邊微有風。覺寒蛩近壁，知暝鶴歸籠。',48,'御定全唐詩/json/446.json','["煙景淡濛濛，池邊微有風。覺寒蛩近壁，知暝鶴歸籠。", "長貌隨年改，衰情與物同。夜來霜厚薄，梨葉半低紅。"]'),
('yuding-71','分司','白居易','唐','御定全唐诗','yuding','','[]','散秩留司殊有味，最宜病拙不才身。行香拜表為公事，',40,'御定全唐詩/json/446.json','["散秩留司殊有味，最宜病拙不才身。行香拜表為公事，", "錢唐五馬留三匹，還擬騎遊攪擾春。"]'),
('yuding-72','河南王尹初到，以詩代書先問之','白居易','唐','御定全唐诗','yuding','','[]','別來王閣老，三歲似須臾。鬢上斑多少，杯前興有無。',48,'御定全唐詩/json/446.json','["別來王閣老，三歲似須臾。鬢上斑多少，杯前興有無。", "官從分緊慢，情莫問榮枯。許入朱門否，籃輿一病夫。"]'),
('yuding-73','池西亭','白居易','唐','御定全唐诗','yuding','','[]','朱欄映晚樹，金魄落秋池。還似錢唐夜，西樓月出時。',24,'御定全唐詩/json/446.json','["朱欄映晚樹，金魄落秋池。還似錢唐夜，西樓月出時。"]'),
('yuding-74','臨池閑臥','白居易','唐','御定全唐诗','yuding','','[]','小竹圍庭匝，平池與砌連。閑多臨水坐，老愛向陽眠。',48,'御定全唐詩/json/446.json','["小竹圍庭匝，平池與砌連。閑多臨水坐，老愛向陽眠。", "營役拋身外，幽奇送枕前。誰家臥床腳，解系釣魚船。"]'),
('yuding-75','吾廬','白居易','唐','御定全唐诗','yuding','','[]','吾廬不獨貯妻兒，自覺年侵身力衰。眼下營求容足地，',40,'御定全唐詩/json/446.json','["吾廬不獨貯妻兒，自覺年侵身力衰。眼下營求容足地，", "莫道兩都空有宅，林泉風月是家資。"]'),
('yuding-76','題新居，寄宣州崔相公','白居易','唐','御定全唐诗','yuding','','[]','門庭有水巷無塵，好稱閑官作主人。冷似雀羅雖少客，',40,'御定全唐詩/json/446.json','["門庭有水巷無塵，好稱閑官作主人。冷似雀羅雖少客，", "濟世料君歸未得，南園北曲謾為鄰。"]'),
('yuding-77','憶杭州梅花，因敘舊游，寄蕭協律','白居易','唐','御定全唐诗','yuding','','[]','三年閑悶在餘杭，曾為梅花醉幾場。伍相廟邊繁似雪，',48,'御定全唐詩/json/446.json','["三年閑悶在餘杭，曾為梅花醉幾場。伍相廟邊繁似雪，", "賞自初開直至落，歡因小飲便成狂。薛劉相次埋新壟，"]'),
('yuding-78','病中辱張常侍題集賢院詩，因以繼和','白居易','唐','御定全唐诗','yuding','','[]','天祿閣門開，甘泉侍從回。圖書皆帝籍，寮友盡仙才。',48,'御定全唐詩/json/446.json','["天祿閣門開，甘泉侍從回。圖書皆帝籍，寮友盡仙才。", "騎省通中掖，龍樓隔上臺。猶憐病宮相，詩寄洛陽來。"]'),
('yuding-79','早春晚歸','白居易','唐','御定全唐诗','yuding','','[]','晚歸騎馬過天津，沙白橋紅返照新。草色連延多隙地，',40,'御定全唐詩/json/446.json','["晚歸騎馬過天津，沙白橋紅返照新。草色連延多隙地，", "金穀風光依舊在，無人管領石家春。"]'),
('yuding-80','贈楊使君','白居易','唐','御定全唐诗','yuding','','[]','曾嗟放逐同巴峽，且喜歸還會洛陽。時命到來須作用，',40,'御定全唐詩/json/446.json','["曾嗟放逐同巴峽，且喜歸還會洛陽。時命到來須作用，", "更待城東桃李發，共君沉醉兩三場。"]'),
('yuding-81','贈皇甫庶子','白居易','唐','御定全唐诗','yuding','','[]','何因散地共徘徊，人道君才我不才。騎少馬蹄生易蹶，',40,'御定全唐詩/json/446.json','["何因散地共徘徊，人道君才我不才。騎少馬蹄生易蹶，", "更愧小胥咨拜表，單衫沖雪夜深來。"]'),
('yuding-82','池上竹下作','白居易','唐','御定全唐诗','yuding','','[]','穿籬繞舍碧逶迤，十畝閒居半是池。食飽窗間新睡後，',40,'御定全唐詩/json/446.json','["穿籬繞舍碧逶迤，十畝閒居半是池。食飽窗間新睡後，", "何必悠悠人世上，勞心費目覓親知。"]'),
('yuding-83','閑出覓春，戲贈諸郎官','白居易','唐','御定全唐诗','yuding','','[]','年來數出覓風光，亦不全閑亦不忙。放鞚體安騎穩馬，',40,'御定全唐詩/json/446.json','["年來數出覓風光，亦不全閑亦不忙。放鞚體安騎穩馬，", "除卻髭須白一色，其餘未伏少年郎。"]'),
('yuding-84','別春爐','白居易','唐','御定全唐诗','yuding','','[]','暖閣春初入，溫爐興稍闌。晚風猶冷在，夜火且留看。',48,'御定全唐詩/json/446.json','["暖閣春初入，溫爐興稍闌。晚風猶冷在，夜火且留看。", "獨宿相依久，多情欲別難。誰能共天語，長遣四時寒。"]'),
('yuding-85','泛小fq二首','白居易','唐','御定全唐诗','yuding','','[]','水一塘，fq一隻。fq頭漾漾知風起，fq背蕭蕭聞雨滴。',83,'御定全唐詩/json/446.json','["水一塘，fq一隻。fq頭漾漾知風起，fq背蕭蕭聞雨滴。", "醉臥船中欲醒時，忽疑身是江南客。", "船緩進，水準流。一莖竹篙剔船尾，兩幅青幕覆船頭。", "亞竹亂藤多照岸，如從鳳口向湖州。"]'),
('yuding-86','夢行簡','白居易','唐','御定全唐诗','yuding','','[]','天氣妍和水色鮮，閑吟獨步小橋邊。',32,'御定全唐詩/json/446.json','["天氣妍和水色鮮，閑吟獨步小橋邊。", "池塘草綠無佳句，虛臥春窗夢阿憐。"]'),
('yuding-87','題新居呈王尹，兼簡府中三掾','白居易','唐','御定全唐诗','yuding','','[]','弊宅須重葺，貧家乏羨財。橋憑川守造，樹倩府僚栽。',48,'御定全唐詩/json/446.json','["弊宅須重葺，貧家乏羨財。橋憑川守造，樹倩府僚栽。", "朱板新猶濕，紅英暖漸開。仍期更攜酒，倚檻看花來。"]'),
('yuding-88','雲和','白居易','唐','御定全唐诗','yuding','','[]','非琴非瑟亦非箏，撥柱推弦調未成。',32,'御定全唐詩/json/446.json','["非琴非瑟亦非箏，撥柱推弦調未成。", "欲散白頭千萬恨，只消紅袖兩三聲。"]'),
('yuding-89','春老','白居易','唐','御定全唐诗','yuding','','[]','欲隨年少強遊春，自覺風光不屬身。',32,'御定全唐詩/json/446.json','["欲隨年少強遊春，自覺風光不屬身。", "歌舞屏風花障上，幾時曾畫白頭人。"]'),
('yuding-90','春雪過皇甫家','白居易','唐','御定全唐诗','yuding','','[]','晚來籃輿雪中回，喜遇君家門正開。',32,'御定全唐詩/json/446.json','["晚來籃輿雪中回，喜遇君家門正開。", "唯要主人青眼待，琴詩談笑自將來。"]'),
('yuding-91','崔侍禦以孩子三日示其所生詩見示因以二絕句和之','白居易','唐','御定全唐诗','yuding','','[]','洞房門上掛桑弧，香水盆中浴鳳雛。',64,'御定全唐詩/json/446.json','["洞房門上掛桑弧，香水盆中浴鳳雛。", "還似初生三日魄，嫦娥滿月即成珠。", "愛惜肯將同寶玉，喜歡應勝得王侯。", "弄璋詩句多才思，愁殺無兒老鄧攸。"]'),
('yuding-92','與皇甫庶子同遊城東','白居易','唐','御定全唐诗','yuding','','[]','閒遊何必多徒侶，相勸時時舉一杯。博望苑中無職役，',40,'御定全唐詩/json/446.json','["閒遊何必多徒侶，相勸時時舉一杯。博望苑中無職役，", "白馬朱衣兩宮相，可憐天氣出城來。"]'),
('yuding-93','洛城東花下作','白居易','唐','御定全唐诗','yuding','','[]','記得舊詩章，花多數洛陽。及逢枝似雪，已是鬢成霜。',72,'御定全唐詩/json/446.json','["記得舊詩章，花多數洛陽。及逢枝似雪，已是鬢成霜。", "向後光陰促，從前事意忙。無因重年少，何計駐時芳。", "欲送愁離面，須傾酒入腸。白頭無藉在，醉倒亦何妨。"]'),
('yuding-94','晚春寄微之並崔湖州','白居易','唐','御定全唐诗','yuding','','[]','洛陽陌上少交親，履道城邊欲暮春。',32,'御定全唐詩/json/446.json','["洛陽陌上少交親，履道城邊欲暮春。", "崔在吳興元在越，出門騎馬覓何人。"]'),
('yuding-95','城東閑行，因題尉遲司業水閣','白居易','唐','御定全唐诗','yuding','','[]','閑繞洛陽城，無人知姓名。病乘籃輿出，老著茜衫行。',48,'御定全唐詩/json/446.json','["閑繞洛陽城，無人知姓名。病乘籃輿出，老著茜衫行。", "處處花相引，時時酒一傾。借君溪閣上，醉詠兩三聲。"]'),
('yuding-96','寄皇甫七','白居易','唐','御定全唐诗','yuding','','[]','孟夏愛吾廬，陶潛語不虛。花樽飄落酒，風案展開書。',48,'御定全唐詩/json/446.json','["孟夏愛吾廬，陶潛語不虛。花樽飄落酒，風案展開書。", "鄰女偷新果，家僮漉小魚。不知皇甫七，池上興何如。"]'),
('yuding-97','訪皇甫七','白居易','唐','御定全唐诗','yuding','','[]','上馬行數裏，逢花傾一杯。更無停泊處，還是覓君來。',24,'御定全唐詩/json/446.json','["上馬行數裏，逢花傾一杯。更無停泊處，還是覓君來。"]'),
('yuding-0','除蘇州刺史，別洛城東花','白居易','唐','御定全唐诗','yuding','','[]','亂雪千花落，新絲兩鬢生。老除吳郡守，春別洛陽城。',48,'御定全唐詩/json/447.json','["亂雪千花落，新絲兩鬢生。老除吳郡守，春別洛陽城。", "江上今重去，城東更一行。別花何用伴，勸酒有殘鶯。"]'),
('yuding-1','奉和汴州令狐令公二十二韻','白居易','唐','御定全唐诗','yuding','','[]','客有東征者，夷門一落帆。二年方得到，五日未為淹。',264,'御定全唐詩/json/447.json','["客有東征者，夷門一落帆。二年方得到，五日未為淹。", "在浚旌重葺，游梁館更添。心因好善樂，貌為禮賢謙。", "俗阜知敦勸，民安見察廉。仁風扇道路，陰雨膏閭閻。", "文律操將柄，兵機釣得鈐。碧幢油葉葉，紅旆火襜襜。", "景象春加麗，威容曉助嚴。槍森赤豹尾，纛吒黑龍髯。", "門靜塵初斂，城昏日半銜。選幽開後院，占勝坐前簷。", "平展絲頭毯，高褰錦額簾。雷捶柘枝鼓，雪擺胡騰衫。", "發滑歌釵墜，妝光舞汗沾。回燈花簇簇，過酒玉纖纖。", "饌盛盤心殢，醅濃盞底黏。陸珍熊掌爛，海味蟹螯鹹。", "福履千夫祝，形儀四座瞻。羊公長在峴，傅說莫歸岩。", "眷愛人人遍，風情事事兼。猶嫌客不醉，同賦夜厭厭。"]'),
('yuding-2','船夜援琴','白居易','唐','御定全唐诗','yuding','','[]','鳥棲魚不動，月照夜江深。身外都無事，舟中只有琴。',48,'御定全唐詩/json/447.json','["鳥棲魚不動，月照夜江深。身外都無事，舟中只有琴。", "七弦為益友，兩耳是知音。心靜即聲淡，其間無古今。"]'),
('yuding-3','答劉和州禹錫','白居易','唐','御定全唐诗','yuding','','[]','換印雖頻命未通，曆陽湖上又秋風。不教才展休明代，',40,'御定全唐詩/json/447.json','["換印雖頻命未通，曆陽湖上又秋風。不教才展休明代，", "好相收拾為閑伴，年齒官班約略同。"]'),
('yuding-4','渡淮','白居易','唐','御定全唐诗','yuding','','[]','淮水東南闊，無風渡亦難。孤煙生乍直，遠樹望多圓。',48,'御定全唐詩/json/447.json','["淮水東南闊，無風渡亦難。孤煙生乍直，遠樹望多圓。", "春浪棹聲急，夕陽帆影殘。清流宜映月，今夜重吟看。"]'),
('yuding-5','赴蘇州至常州，答賈舍人','白居易','唐','御定全唐诗','yuding','','[]','杭城隔歲轉蘇台，還擁前時五馬回。厭見簿書先眼合，',40,'御定全唐詩/json/447.json','["杭城隔歲轉蘇台，還擁前時五馬回。厭見簿書先眼合，", "一別承明三領郡，甘從人道是粗才。"]'),
('yuding-6','去歲罷杭州今春領吳郡慚無善政聊寫鄙懷兼寄三相公','白居易','唐','御定全唐诗','yuding','','[]','為問三丞相，如何秉國鈞。那將最劇郡，付與苦慵人。',96,'御定全唐詩/json/447.json','["為問三丞相，如何秉國鈞。那將最劇郡，付與苦慵人。", "豈有吟詩客，堪為持節臣。不才空飽暖，無惠及饑貧。", "昨臥南城月，今行北境春。鉛刀磨欲盡，銀印換何頻。", "杭老遮車轍，吳童掃路塵。虛迎複虛送，慚見兩州民。"]'),
('yuding-7','宣武令狐相公以詩寄贈傳播吳中聊奉短草用申酬謝','白居易','唐','御定全唐诗','yuding','','[]','新詩傳詠忽紛紛，楚老吳娃耳遍聞。盡解呼為好才子，',40,'御定全唐詩/json/447.json','["新詩傳詠忽紛紛，楚老吳娃耳遍聞。盡解呼為好才子，", "謝脁篇章韓信鉞，一生雙得不如君。"]'),
('yuding-8','自詠','白居易','唐','御定全唐诗','yuding','','[]','形容瘦薄詩情苦，豈是人間有相人。只合一生眠白屋，',40,'御定全唐詩/json/447.json','["形容瘦薄詩情苦，豈是人間有相人。只合一生眠白屋，", "唯是無兒頭早白，被天磨折恰平均。"]'),
('yuding-9','吟前篇，因寄微之','白居易','唐','御定全唐诗','yuding','','[]','君顏貴茂不清羸，君句雄華不苦悲。',32,'御定全唐詩/json/447.json','["君顏貴茂不清羸，君句雄華不苦悲。", "何事遣君還似我，髭須早白亦無兒。"]'),
('yuding-10','紫薇花','白居易','唐','御定全唐诗','yuding','','[]','紫薇花對紫微翁，名目雖同貌不同。獨佔芳菲當夏景，',40,'御定全唐詩/json/447.json','["紫薇花對紫微翁，名目雖同貌不同。獨佔芳菲當夏景，", "何似蘇州安置處，花堂欄下月明中。"]'),
('yuding-11','自到郡齋僅經旬日方專公務未及宴遊偷閒走筆題二十四韻兼寄常州賈舍人湖州崔郎中仍呈吳中諸客','白居易','唐','御定全唐诗','yuding','','[]','渭北離鄉客，江南守土臣。涉途初改月，入境已經旬。',352,'御定全唐詩/json/447.json','["渭北離鄉客，江南守土臣。涉途初改月，入境已經旬。", "甲郡標天下，環封極海濱。版圖十萬戶，兵籍五千人。", "自顧才能少，何堪寵命頻。冒榮慚印綬，虛獎負絲綸。", "候病須通脈，防流要塞津。救煩無若靜，補拙莫如勤。", "削使科條簡，攤令賦役均。以茲為報效，安敢不躬親。", "襦袴提于手，韋弦佩在紳。敢辭稱俗吏，且願活疲民。", "常未征黃霸，湖猶借寇恂。愧無鐺腳政，徒忝犬牙鄰。", "制誥誇黃絹，詩篇占白蘋。銅符拋不得，瓊樹見無因。", "警寐鐘傳夜，催衙鼓報晨。唯知對胥吏，未暇接親賓。", "色變雲迎夏，聲殘鳥過春。麥風非逐扇，梅雨異隨輪。", "武寺山如故，王樓月自新。池塘閑長草，絲竹廢生塵。", "暑遣燒神酎，晴教z4舞茵。待還公事了，亦擬樂吾身。卷447_17《題籠鶴》白居易", "經旬不飲酒，逾月未聞歌。豈是風情少，其如塵事多。", "虎丘慚客問，娃館妒人過。莫笑籠中鶴，相看去幾何。"]'),
('yuding-12','答客問杭州','白居易','唐','御定全唐诗','yuding','','[]','為我踟躕停酒盞，與君約略說杭州。山名天竺堆青黛，',40,'御定全唐詩/json/447.json','["為我踟躕停酒盞，與君約略說杭州。山名天竺堆青黛，", "所嗟水路無三百，官系何因得再遊。"]'),
('yuding-13','登閶門閑望','白居易','唐','御定全唐诗','yuding','','[]','閶門四望鬱蒼蒼，始覺州雄土俗強。十萬夫家供課稅，',48,'御定全唐詩/json/447.json','["閶門四望鬱蒼蒼，始覺州雄土俗強。十萬夫家供課稅，", "處處樓前飄管吹，家家門外泊舟航。雲埋虎寺山藏色，"]'),
('yuding-14','代諸妓贈送周判官','白居易','唐','御定全唐诗','yuding','','[]','妓筵今夜別姑蘇，客棹明朝向鏡湖。莫泛扁舟尋範蠡，',40,'御定全唐詩/json/447.json','["妓筵今夜別姑蘇，客棹明朝向鏡湖。莫泛扁舟尋範蠡，", "好與使君為老伴，歸來休染白髭須。"]'),
('yuding-15','秋寄微之十二韻','白居易','唐','御定全唐诗','yuding','','[]','娃館松江北，稽城浙水東。屈君為長吏，伴我作衰翁。',144,'御定全唐詩/json/447.json','["娃館松江北，稽城浙水東。屈君為長吏，伴我作衰翁。", "旌旆知非遠，煙雲望不通。忙多對酒榼，興少閱詩筒。", "淡白秋來日，疏涼雨後風。餘霞數片綺，新月一張弓。", "影滿衰桐樹，香凋晚蕙叢。饑啼春穀鳥，寒怨絡絲蟲。", "覽鏡頭雖白，聽歌耳未聾。老愁從此遣，醉笑與誰同。", "清旦方堆案，黃昏始退公。可憐朝暮景，銷在兩衙中。"]'),
('yuding-16','池上早秋','白居易','唐','御定全唐诗','yuding','','[]','荷芰綠參差，新秋水滿池。早涼生北檻，殘照下東籬。',48,'御定全唐詩/json/447.json','["荷芰綠參差，新秋水滿池。早涼生北檻，殘照下東籬。", "露飽蟬聲懶，風乾柳意衰。過潘二十歲，何必更愁悲。"]'),
('yuding-17','郡西亭偶詠','白居易','唐','御定全唐诗','yuding','','[]','常愛西亭面北林，公私塵事不能侵。共閑作伴無如鶴，',40,'御定全唐詩/json/447.json','["常愛西亭面北林，公私塵事不能侵。共閑作伴無如鶴，", "可憐此道人皆見，但要修行功用深。"]'),
('yuding-18','故衫','白居易','唐','御定全唐诗','yuding','','[]','闇淡緋衫稱老身，半披半曳出朱門。袖中吳郡新詩本，',40,'御定全唐詩/json/447.json','["闇淡緋衫稱老身，半披半曳出朱門。袖中吳郡新詩本，", "曾經爛熳三年著，欲棄空箱似少恩。"]'),
('yuding-19','郡中夜聽李山人彈三樂','白居易','唐','御定全唐诗','yuding','','[]','風琴秋拂匣，月戶夜開關。榮啟先生樂，姑蘇太守閑。',48,'御定全唐詩/json/447.json','["風琴秋拂匣，月戶夜開關。榮啟先生樂，姑蘇太守閑。", "傳聲千古後，得意一時間。卻怪鐘期耳，唯聽水與山。"]'),
('yuding-20','東城桂三首','白居易','唐','御定全唐诗','yuding','','[]','子墮本從天竺寺，根盤今在闔閭城。',96,'御定全唐詩/json/447.json','["子墮本從天竺寺，根盤今在闔閭城。", "當時應逐南風落，落向人間取次生。", "霜雪壓多雖不死，荊榛長疾欲相埋。", "長憂落在樵人手，賣作蘇州一束柴。", "遙知天上桂花孤，試問嫦娥更要無。", "月宮幸有閒田地，何不中央種兩株。"]'),
('yuding-21','聞行簡恩賜章服，喜成長句寄之','白居易','唐','御定全唐诗','yuding','','[]','吾年五十加朝散，爾亦今年賜服章。齒發恰同知命歲，',40,'御定全唐詩/json/447.json','["吾年五十加朝散，爾亦今年賜服章。齒發恰同知命歲，", "大抵著緋宜老大，莫嫌秋鬢數莖霜。"]'),
('yuding-22','喚笙歌','白居易','唐','御定全唐诗','yuding','','[]','露墜萎花槿，風吹敗葉荷。老心歡樂少，秋眼感傷多。',48,'御定全唐詩/json/447.json','["露墜萎花槿，風吹敗葉荷。老心歡樂少，秋眼感傷多。", "芳歲今如此，衰翁可奈何。猶應不如醉，試遣喚笙歌。"]'),
('yuding-23','對酒吟','白居易','唐','御定全唐诗','yuding','','[]','一拋學士筆，三佩使君符。未換銀青綬，唯添雪白須。',96,'御定全唐詩/json/447.json','["一拋學士筆，三佩使君符。未換銀青綬，唯添雪白須。", "公門衙退掩，妓席客來鋪。履舄從相近，謳吟任所須。", "金銜嘶五馬，鈿帶舞雙姝。不得當年有，猶勝到老無。", "合聲歌漢月，齊手拍吳歈。今夜還先醉，應煩紅袖扶。"]'),
('yuding-24','偶飲','白居易','唐','御定全唐诗','yuding','','[]','三盞醺醺四體融，妓亭簷下夕陽中。千聲方響敲相續，',40,'御定全唐詩/json/447.json','["三盞醺醺四體融，妓亭簷下夕陽中。千聲方響敲相續，", "唯憎小吏樽前報，道去衙時水五筒。"]'),
('yuding-25','早發赴洞庭舟中作','白居易','唐','御定全唐诗','yuding','','[]','閶門曙色欲蒼蒼，星月高低宿水光。棹舉影搖燈燭動，',40,'御定全唐詩/json/447.json','["閶門曙色欲蒼蒼，星月高低宿水光。棹舉影搖燈燭動，", "出郭已行十五裏，唯消一曲慢霓裳。"]'),
('yuding-26','宿湖中','白居易','唐','御定全唐诗','yuding','','[]','水天向晚碧沉沉，樹影霞光重疊深。浸月冷波千頃練，',40,'御定全唐詩/json/447.json','["水天向晚碧沉沉，樹影霞光重疊深。浸月冷波千頃練，", "十隻畫船何處宿，洞庭山腳太湖心。"]'),
('yuding-27','揀貢橘書情','白居易','唐','御定全唐诗','yuding','','[]','洞庭貢橘揀宜精，太守勤王請自行。珠顆形容隨日長，',40,'御定全唐詩/json/447.json','["洞庭貢橘揀宜精，太守勤王請自行。珠顆形容隨日長，", "疏賤無由親跪獻，願憑朱實表丹誠。"]'),
('yuding-28','夜泛陽塢入明月灣即事，寄崔湖州','白居易','唐','御定全唐诗','yuding','','[]','湖山處處好淹留，最愛東灣北塢頭。掩映橘林千點火，',40,'御定全唐詩/json/447.json','["湖山處處好淹留，最愛東灣北塢頭。掩映橘林千點火，", "為報茶山崔太守，與君各是一家遊。"]'),
('yuding-29','泛太湖書事，寄微之','白居易','唐','御定全唐诗','yuding','','[]','煙渚雲帆處處通，飄然舟似入虛空。玉杯淺酌巡初匝，',72,'御定全唐詩/json/447.json','["煙渚雲帆處處通，飄然舟似入虛空。玉杯淺酌巡初匝，", "避旗飛鷺翩翻白，驚鼓跳魚撥剌紅。澗雪壓多松偃蹇，", "軍府威容從道盛，江山氣色定知同。報君一事君應羨，"]'),
('yuding-30','題新館','白居易','唐','御定全唐诗','yuding','','[]','曾為白社羈遊子，今作朱門醉飽身。十萬戶州尤覺貴，',40,'御定全唐詩/json/447.json','["曾為白社羈遊子，今作朱門醉飽身。十萬戶州尤覺貴，", "新館寒來多少客，欲回歌酒暖風塵。"]'),
('yuding-31','西樓喜雪命宴','白居易','唐','御定全唐诗','yuding','','[]','宿雲黃慘澹，曉雪白飄颻。散面遮槐市，堆花壓柳橋。',72,'御定全唐詩/json/447.json','["宿雲黃慘澹，曉雪白飄颻。散面遮槐市，堆花壓柳橋。", "四郊鋪縞素，萬室甃瓊瑤。銀榼攜桑落，金爐上麗譙。", "光迎舞妓動，寒近醉人銷。歌樂雖盈耳，慚無五袴謠。"]'),
('yuding-32','新栽梅','白居易','唐','御定全唐诗','yuding','','[]','池邊新種七株梅，欲到花時點檢來。',32,'御定全唐詩/json/447.json','["池邊新種七株梅，欲到花時點檢來。", "莫怕長洲桃李妒，今年好為使君開。"]'),
('yuding-33','酬劉和州戲贈','白居易','唐','御定全唐诗','yuding','','[]','錢唐山水接蘇台，兩地褰帷愧不才。政事素無爭學得，',40,'御定全唐詩/json/447.json','["錢唐山水接蘇台，兩地褰帷愧不才。政事素無爭學得，", "不似劉郎無景行，長拋春恨在天臺。"]'),
('yuding-34','戲和賈常州醉中二絕句','白居易','唐','御定全唐诗','yuding','','[]','聞道毗陵詩酒興，近來積漸學姑蘇。',64,'御定全唐詩/json/447.json','["聞道毗陵詩酒興，近來積漸學姑蘇。", "罨頭新令從偷去，刮骨清吟得似無。", "越調管吹留客曲，吳吟詩送暖寒杯。", "娃宮無限風流事，好遣孫心暫學來。"]'),
('yuding-35','歲暮寄微之三首','白居易','唐','御定全唐诗','yuding','','[]','微之別久能無歎，知退書稀豈免愁。甲子百年過半後，',120,'御定全唐詩/json/447.json','["微之別久能無歎，知退書稀豈免愁。甲子百年過半後，", "自覺歡情隨日減，蘇州心不及杭州。", "榮進雖頻退亦頻，與君才命不調勻。若不九重中掌事，", "唯欠結廬嵩洛下，一時歸去作閒人。", "白頭歲暮苦相思，除卻悲吟無可為。枕上從妨一夜睡，", "若並如今是全活，紆朱拖紫且開眉。"]'),
('yuding-36','歲日家宴戲示弟侄等兼呈張侍禦二十八丈殷判官二十三兄','白居易','唐','御定全唐诗','yuding','','[]','弟妹妻孥小侄甥，嬌癡弄我助歡情。歲盞後推藍尾酒，',40,'御定全唐詩/json/447.json','["弟妹妻孥小侄甥，嬌癡弄我助歡情。歲盞後推藍尾酒，", "猶有誇張少年處，笑呼張丈喚殷兄。"]'),
('yuding-37','正月三日閑行','白居易','唐','御定全唐诗','yuding','','[]','黃鸝巷口鶯欲語，烏鵲河頭冰欲銷。',64,'御定全唐詩/json/447.json','["黃鸝巷口鶯欲語，烏鵲河頭冰欲銷。", "綠浪東西南北水，紅欄三百九十橋。", "鴛鴦蕩漾雙雙翅，楊柳交加萬萬條。", "借問春風來早晚，只從前日到今朝。"]'),
('yuding-38','夜歸','白居易','唐','御定全唐诗','yuding','','[]','逐勝移朝宴，留歡放晚衙。賓寮多謝客，騎從半吳娃。',72,'御定全唐詩/json/447.json','["逐勝移朝宴，留歡放晚衙。賓寮多謝客，騎從半吳娃。", "到處銷春景，歸時及月華。城陰一道直，燭焰兩行斜。", "東吹先催柳，南霜不殺花。皋橋夜沽酒，燈火是誰家。"]'),
('yuding-39','自歎','白居易','唐','御定全唐诗','yuding','','[]','豈獨年相迫，兼為病所侵。春來痰氣動，老去嗽聲深。',48,'御定全唐詩/json/447.json','["豈獨年相迫，兼為病所侵。春來痰氣動，老去嗽聲深。", "眼暗猶操筆，頭斑未掛簪。因循過日月，真是俗人心。"]'),
('yuding-40','郡中閑獨，寄微之及崔湖州','白居易','唐','御定全唐诗','yuding','','[]','少年賓旅非吾輩，晚歲簪纓束我身。酒散更無同宿客，',40,'御定全唐詩/json/447.json','["少年賓旅非吾輩，晚歲簪纓束我身。酒散更無同宿客，", "兩處也應相憶在，官高年長少情親。"]'),
('yuding-41','小舫','白居易','唐','御定全唐诗','yuding','','[]','小舫一艘新造了，輕裝樑柱庳安篷。深坊靜岸游應遍，',40,'御定全唐詩/json/447.json','["小舫一艘新造了，輕裝樑柱庳安篷。深坊靜岸游應遍，", "慢牽欲傍櫻桃泊，借問誰家花最紅。"]'),
('yuding-42','馬墜強出，贈同座','白居易','唐','御定全唐诗','yuding','','[]','足傷遭馬墜，腰重倩人抬。只合窗間臥，何由花下來。',48,'御定全唐詩/json/447.json','["足傷遭馬墜，腰重倩人抬。只合窗間臥，何由花下來。", "坐依桃葉枝，行呷地黃杯。強出非他意，東風落盡梅。"]'),
('yuding-43','夜聞賈常州、崔湖州茶山境會想羨歡宴因寄此詩','白居易','唐','御定全唐诗','yuding','','[]','遙聞境會茶山夜，珠翠歌鐘俱繞身。盤下中分兩州界，',40,'御定全唐詩/json/447.json','["遙聞境會茶山夜，珠翠歌鐘俱繞身。盤下中分兩州界，", "自歎花時北窗下，蒲黃酒對病眠人。"]'),
('yuding-44','酬微之開拆新樓初畢相報末聯見戲之作','白居易','唐','御定全唐诗','yuding','','[]','海山鬱鬱石棱棱，新豁高居正好登。南臨贍部三千界，',40,'御定全唐詩/json/447.json','["海山鬱鬱石棱棱，新豁高居正好登。南臨贍部三千界，", "無妨卻有他心眼，妝點亭台即不能。"]'),
('yuding-45','病中多雨逢寒食','白居易','唐','御定全唐诗','yuding','','[]','水國多陰常懶出，老夫饒病愛閑眠。三旬臥度鶯花月，',40,'御定全唐詩/json/447.json','["水國多陰常懶出，老夫饒病愛閑眠。三旬臥度鶯花月，", "彩繩芳樹長如舊，唯是年年換少年。"]'),
('yuding-46','清明夜','白居易','唐','御定全唐诗','yuding','','[]','好風朧月清明夜，碧砌紅軒刺史家。',32,'御定全唐詩/json/447.json','["好風朧月清明夜，碧砌紅軒刺史家。", "獨繞回廊行複歇，遙聽弦管暗看花。"]'),
('yuding-47','蘇州柳','白居易','唐','御定全唐诗','yuding','','[]','金谷園中黃嫋娜，曲江亭畔碧婆娑。老來處處遊行遍，',24,'御定全唐詩/json/447.json','["金谷園中黃嫋娜，曲江亭畔碧婆娑。老來處處遊行遍，"]'),
('yuding-48','三月二十八日贈周判官','白居易','唐','御定全唐诗','yuding','','[]','一春惆悵殘三日，醉問周郎憶得無。',32,'御定全唐詩/json/447.json','["一春惆悵殘三日，醉問周郎憶得無。", "柳絮送人鶯勸酒，去年今日別東都。"]'),
('yuding-49','偶作','白居易','唐','御定全唐诗','yuding','','[]','紅杏初生葉，青梅已綴枝。闌珊花落後，寂寞酒醒時。',48,'御定全唐詩/json/447.json','["紅杏初生葉，青梅已綴枝。闌珊花落後，寂寞酒醒時。", "坐悶低眉久，行慵舉足遲。少年君莫怪，頭白自應知。"]'),
('yuding-50','重答劉和州','白居易','唐','御定全唐诗','yuding','','[]','分無佳麗敵西施，敢有文章替左司。隨分笙歌聊自樂，',40,'御定全唐詩/json/447.json','["分無佳麗敵西施，敢有文章替左司。隨分笙歌聊自樂，", "可惜當時好風景，吳王應不解吟詩。"]'),
('yuding-51','奉送三兄','白居易','唐','御定全唐诗','yuding','','[]','少年曾管二千兵，晝聽笙歌夜斫營。自反丘園頭盡白，',40,'御定全唐詩/json/447.json','["少年曾管二千兵，晝聽笙歌夜斫營。自反丘園頭盡白，", "自愧阿連官職慢，只教兄作使君兄。"]'),
('yuding-52','城上夜宴','白居易','唐','御定全唐诗','yuding','','[]','留春不住登城望，惜夜相將秉燭遊。風月萬家河兩岸，',40,'御定全唐詩/json/447.json','["留春不住登城望，惜夜相將秉燭遊。風月萬家河兩岸，", "從道人生都是夢，夢中歡笑亦勝愁。"]'),
('yuding-53','重題小舫，贈周從事，兼戲微之','白居易','唐','御定全唐诗','yuding','','[]','細篷青篾織魚鱗，小眼紅窗襯麹塵。闊狹才容從事座，',40,'御定全唐詩/json/447.json','["細篷青篾織魚鱗，小眼紅窗襯麹塵。闊狹才容從事座，", "不似鏡湖廉使出，高檣大艑鬧驚春。"]'),
('yuding-54','吳櫻桃','白居易','唐','御定全唐诗','yuding','','[]','含桃最說出東吳，香色鮮穠氣味殊。洽恰舉頭千萬顆，',40,'御定全唐詩/json/447.json','["含桃最說出東吳，香色鮮穠氣味殊。洽恰舉頭千萬顆，", "可惜風吹兼雨打，明朝後日即應無。"]'),
('yuding-55','春盡勸客酒','白居易','唐','御定全唐诗','yuding','','[]','林下春將盡，池邊日半斜。櫻桃落砌顆，夜合隔簾花。',48,'御定全唐詩/json/447.json','["林下春將盡，池邊日半斜。櫻桃落砌顆，夜合隔簾花。", "嘗酒留閑客，行茶使小娃。殘杯勸不飲，留醉向誰家。"]'),
('yuding-56','仲夏齋居，偶題八韻，寄微之及崔湖州','白居易','唐','御定全唐诗','yuding','','[]','腥血與葷蔬，停來一月餘。肌膚雖瘦損，方寸任清虛。',96,'御定全唐詩/json/447.json','["腥血與葷蔬，停來一月餘。肌膚雖瘦損，方寸任清虛。", "體適通宵坐，頭慵隔日梳。眼前無俗物，身外即僧居。", "水榭風來遠，松廊雨過初。褰簾放巢燕，投食施池魚。", "久別閒遊伴，頻勞問疾書。不知湖與越，吏隱興何如。"]'),
('yuding-57','官宅','白居易','唐','御定全唐诗','yuding','','[]','紅紫共紛紛，祗承老使君。移舟木蘭棹，行酒石榴裙。',48,'御定全唐詩/json/447.json','["紅紫共紛紛，祗承老使君。移舟木蘭棹，行酒石榴裙。", "水色窗窗見，花香院院聞。戀他官舍住，雙鬢白如雲。"]'),
('yuding-58','六月三日夜聞蟬','白居易','唐','御定全唐诗','yuding','','[]','荷香清露墜，柳動好風生。微月初三夜，新蟬第一聲。',60,'御定全唐詩/json/447.json','["荷香清露墜，柳動好風生。微月初三夜，新蟬第一聲。", "乍聞愁北客，靜聽憶東京。我有竹林宅，別來蟬再鳴。", "不知池上月，誰撥小船行。"]'),
('yuding-59','蓮石','白居易','唐','御定全唐诗','yuding','','[]','青石一兩片，白蓮三四枝。寄將東洛去，心與物相隨。',72,'御定全唐詩/json/447.json','["青石一兩片，白蓮三四枝。寄將東洛去，心與物相隨。", "石倚風前樹，蓮栽月下池。遙知安置處，預想發榮時。", "領郡來何遠，還鄉去已遲。莫言千里別，歲晚有心期。"]'),
('yuding-60','眼病二首','白居易','唐','御定全唐诗','yuding','','[]','散亂空中千片雪，蒙籠物上一重紗。縱逢晴景如看霧，',80,'御定全唐詩/json/447.json','["散亂空中千片雪，蒙籠物上一重紗。縱逢晴景如看霧，", "兩頭治療何曾瘥，藥力微茫佛力賒。", "眼藏損傷來已久，病根牢固去應難。醫師盡勸先停酒，", "人間方藥應無益，爭得金篦試刮看。"]'),
('yuding-61','題東武丘寺六韻','白居易','唐','御定全唐诗','yuding','','[]','香刹看非遠，祇園入始深。龍蟠松矯矯，玉立竹森森。',72,'御定全唐詩/json/447.json','["香刹看非遠，祇園入始深。龍蟠松矯矯，玉立竹森森。", "怪石千僧坐，靈池一劍沉。海當亭兩面，山在寺中心。", "酒熟憑花勸，詩成倩鳥吟。寄言軒冕客，此地好抽簪。"]'),
('yuding-62','夜遊西武丘寺八韻','白居易','唐','御定全唐诗','yuding','','[]','不厭西丘寺，閑來即一過。舟船轉雲島，樓閣出煙蘿。',96,'御定全唐詩/json/447.json','["不厭西丘寺，閑來即一過。舟船轉雲島，樓閣出煙蘿。", "路入青松影，門臨白月波。魚跳驚秉燭，猿覷怪鳴珂。", "搖曳雙紅旆，娉婷十翠娥。香花助羅綺，鐘梵避笙歌。", "領郡時將久，遊山數幾何。一年十二度，非少亦非多。"]'),
('yuding-63','詠懷','白居易','唐','御定全唐诗','yuding','','[]','蘇杭自昔稱名郡，牧守當今當好官。兩地江山蹋得遍，',40,'御定全唐詩/json/447.json','["蘇杭自昔稱名郡，牧守當今當好官。兩地江山蹋得遍，", "白髮滿頭歸得也，詩情酒興漸闌珊。"]'),
('yuding-64','重詠','白居易','唐','御定全唐诗','yuding','','[]','日覺雙眸暗，年驚兩鬢蒼。病應無處避，老更不宜忙。',48,'御定全唐詩/json/447.json','["日覺雙眸暗，年驚兩鬢蒼。病應無處避，老更不宜忙。", "徇俗心情少，休官道理長。今秋歸去定，何必重思量。"]'),
('yuding-65','百日假滿','白居易','唐','御定全唐诗','yuding','','[]','心中久有歸田計，身上都無濟世才。長告初從百日滿，',40,'御定全唐詩/json/447.json','["心中久有歸田計，身上都無濟世才。長告初從百日滿，", "但拂衣行莫回顧，的無官職趁人來。"]'),
('yuding-66','九日寄微之','白居易','唐','御定全唐诗','yuding','','[]','眼闇頭風事事妨，繞籬新菊為誰黃。閒遊日久心慵倦，',48,'御定全唐詩/json/447.json','["眼闇頭風事事妨，繞籬新菊為誰黃。閒遊日久心慵倦，", "怕飛杯酒多分數，厭聽笙歌舊曲章。蟋蟀聲寒初過雨，"]'),
('yuding-67','題報恩寺','白居易','唐','御定全唐诗','yuding','','[]','好是清涼地，都無系絆身。晚晴宜野寺，秋景屬閒人。',48,'御定全唐詩/json/447.json','["好是清涼地，都無系絆身。晚晴宜野寺，秋景屬閒人。", "淨石堪敷坐，寒泉可濯巾。自慚容鬢上，猶帶郡庭塵。"]'),
('yuding-68','晚起','白居易','唐','御定全唐诗','yuding','','[]','臥聽冬冬衙鼓聲，起遲睡足長心情。華簪脫後頭雖白，',40,'御定全唐詩/json/447.json','["臥聽冬冬衙鼓聲，起遲睡足長心情。華簪脫後頭雖白，", "明朝更濯塵纓去，聞道松江水最清。"]'),
('yuding-69','自思益寺次楞伽寺作','白居易','唐','御定全唐诗','yuding','','[]','朝從思益峰遊後，晚到楞伽寺歇時。照水姿容雖已老，',24,'御定全唐詩/json/447.json','["朝從思益峰遊後，晚到楞伽寺歇時。照水姿容雖已老，"]'),
('yuding-70','松江亭攜樂觀漁宴宿','白居易','唐','御定全唐诗','yuding','','[]','震澤平蕪岸，松江落葉波。在官常夢想，為客始經過。',72,'御定全唐詩/json/447.json','["震澤平蕪岸，松江落葉波。在官常夢想，為客始經過。", "水面排罾網，船頭簇綺羅。朝盤鱠紅鯉，夜燭舞青娥。", "雁斷知風急，潮平見月多。繁絲與促管，不解和漁歌。"]'),
('yuding-71','宿靈岩寺上院','白居易','唐','御定全唐诗','yuding','','[]','高高白月上青林，客去僧歸獨夜深。葷血屏除唯對酒，',40,'御定全唐詩/json/447.json','["高高白月上青林，客去僧歸獨夜深。葷血屏除唯對酒，", "最愛曉亭東望好，太湖煙水綠沉沉。"]'),
('yuding-72','酬別周從事二首','白居易','唐','御定全唐诗','yuding','','[]','腰痛拜迎人客倦，眼昏勾押簿書難。',64,'御定全唐詩/json/447.json','["腰痛拜迎人客倦，眼昏勾押簿書難。", "辭官歸去緣衰病，莫作陶潛範蠡看。", "洛下田園久拋擲，吳中歌酒莫留連。", "嵩陽雲樹伊川月，已校歸遲四五年。"]'),
('yuding-73','武丘寺路','白居易','唐','御定全唐诗','yuding','','[]','自開山寺路，水陸往來頻。銀勒牽驕馬，花船載麗人。',48,'御定全唐詩/json/447.json','["自開山寺路，水陸往來頻。銀勒牽驕馬，花船載麗人。", "芰荷生欲遍，桃李種仍新。好住湖堤上，長留一道春。"]'),
('yuding-74','齊雲樓晚望偶題十韻兼呈馮侍禦，周、殷二協律','白居易','唐','御定全唐诗','yuding','','[]','潦倒宦情盡，蕭條芳歲闌。欲辭南國去，重上北城看。',120,'御定全唐詩/json/447.json','["潦倒宦情盡，蕭條芳歲闌。欲辭南國去，重上北城看。", "複疊江山壯，平鋪井邑寬。人稠過楊府，坊鬧半長安。", "插霧峰頭沒，穿霞日腳殘。水光紅漾漾，樹色綠漫漫。", "約略留遺愛，殷勤念舊歡。病拋官職易，老別友朋難。", "九月全無熱，西風亦未寒。齊雲樓北面，半日憑欄幹。"]'),
('yuding-75','河亭晴望','白居易','唐','御定全唐诗','yuding','','[]','風轉雲頭斂，煙銷水面開。晴虹橋影出，秋雁櫓聲來。',48,'御定全唐詩/json/447.json','["風轉雲頭斂，煙銷水面開。晴虹橋影出，秋雁櫓聲來。", "郡靜官初罷，鄉遙信未回。明朝是重九，誰勸菊花杯。"]'),
('yuding-76','留別微之','白居易','唐','御定全唐诗','yuding','','[]','幹時久與本心違，悟道深知前事非。猶厭勞形辭郡印，',40,'御定全唐詩/json/447.json','["幹時久與本心違，悟道深知前事非。猶厭勞形辭郡印，", "少室雲邊伊水畔，比君校老合先歸。"]'),
('yuding-77','自喜','白居易','唐','御定全唐诗','yuding','','[]','自喜天教我少緣，家徒行計兩翩翩。身兼妻子都三口，',40,'御定全唐詩/json/447.json','["自喜天教我少緣，家徒行計兩翩翩。身兼妻子都三口，", "攜將貯作丘中費，猶免饑寒得數年。"]'),
('yuding-78','武丘寺路宴留別諸妓','白居易','唐','御定全唐诗','yuding','','[]','銀泥裙映錦障泥，畫舸停橈馬簇蹄。清管曲終鸚鵡語，',40,'御定全唐詩/json/447.json','["銀泥裙映錦障泥，畫舸停橈馬簇蹄。清管曲終鸚鵡語，", "莫忘使君吟詠處，女墳湖北武丘西。"]'),
('yuding-79','江上對酒二首','白居易','唐','御定全唐诗','yuding','','[]','酒助疏頑性，琴資緩慢情。有慵將送老，無智可勞生。',96,'御定全唐詩/json/447.json','["酒助疏頑性，琴資緩慢情。有慵將送老，無智可勞生。", "忽忽忘機坐，倀倀任運行。家鄉安處是，那獨在神京。", "久貯滄浪意，初辭桎梏身。昏昏常帶酒，默默不應人。", "坐穩便箕踞，眠多愛欠伸。客來存禮數，始著白綸巾。"]'),
('yuding-80','望亭驛酬別周判官','白居易','唐','御定全唐诗','yuding','','[]','何事出長洲，連宵飲不休。醒應難作別，歡漸少於愁。',48,'御定全唐詩/json/447.json','["何事出長洲，連宵飲不休。醒應難作別，歡漸少於愁。", "燈火穿村市，笙歌上驛樓。何言五十裏，已不屬蘇州。"]'),
('yuding-81','見小侄龜兒詠燈詩並臘娘制衣，因寄行簡','白居易','唐','御定全唐诗','yuding','','[]','已知臘子能裁服，複報龜兒解詠燈。',32,'御定全唐詩/json/447.json','["已知臘子能裁服，複報龜兒解詠燈。", "巧婦才人常薄命，莫教男女苦多能。"]'),
('yuding-82','酒筵上答張居士','白居易','唐','御定全唐诗','yuding','','[]','但要前塵減，無妨外相同。雖過酒肆上，不離道場中。',48,'御定全唐詩/json/447.json','["但要前塵減，無妨外相同。雖過酒肆上，不離道場中。", "弦管聲非實，花鈿色是空。何人知此義，唯有淨名翁。"]'),
('yuding-83','鸚鵡','白居易','唐','御定全唐诗','yuding','','[]','隴西鸚鵡到江東，養得經年觜漸紅。常恐思歸先剪翅，',40,'御定全唐詩/json/447.json','["隴西鸚鵡到江東，養得經年觜漸紅。常恐思歸先剪翅，", "應似朱門歌舞妓，深藏牢閉後房中。"]'),
('yuding-84','聽琵琶妓彈略略','白居易','唐','御定全唐诗','yuding','','[]','腕軟撥頭輕，新教略略成。四弦千遍語，一曲萬重情。',48,'御定全唐詩/json/447.json','["腕軟撥頭輕，新教略略成。四弦千遍語，一曲萬重情。", "法向師邊得，能從意上生。莫欺江外手，別是一家聲。"]'),
('yuding-85','寫新詩寄微之，偶題卷後','白居易','唐','御定全唐诗','yuding','','[]','寫了吟看滿卷愁，淺紅箋紙小銀鉤。',32,'御定全唐詩/json/447.json','["寫了吟看滿卷愁，淺紅箋紙小銀鉤。", "未容寄與微之去，已被人傳到越州。"]'),
('yuding-86','寶曆二年八月三十日夜夢後作','白居易','唐','御定全唐诗','yuding','','[]','塵纓忽解誠堪喜，世網重來未可知。',32,'御定全唐詩/json/447.json','["塵纓忽解誠堪喜，世網重來未可知。", "莫忘全吳館中夢，嶺南泥雨步行時。"]'),
('yuding-87','與夢得同登棲靈塔','白居易','唐','御定全唐诗','yuding','','[]','半月悠悠在廣陵，何樓何塔不同登。',32,'御定全唐詩/json/447.json','["半月悠悠在廣陵，何樓何塔不同登。", "共憐筋力猶堪在，上到棲靈第九層。"]'),
('yuding-88','夢蘇州水閣，寄馮侍禦','白居易','唐','御定全唐诗','yuding','','[]','揚州驛裏夢蘇州，夢到花橋水閣頭。',32,'御定全唐詩/json/447.json','["揚州驛裏夢蘇州，夢到花橋水閣頭。", "覺後不知馮侍禦，此中昨夜共誰遊。"]'),
('yuding-89','喜罷郡','白居易','唐','御定全唐诗','yuding','','[]','五年兩郡亦堪嗟，偷出遊山走看花。自此光陰為己有，',40,'御定全唐詩/json/447.json','["五年兩郡亦堪嗟，偷出遊山走看花。自此光陰為己有，", "睡到午時歡到夜，回看官職是泥沙。"]'),
('yuding-90','答次休上人','白居易','唐','御定全唐诗','yuding','','[]','姓白使君無麗句，名休座主有新文。',32,'御定全唐詩/json/447.json','["姓白使君無麗句，名休座主有新文。", "禪心不合生分別，莫愛餘霞嫌碧雲。"]'),
('yuding-0','感悟妄緣，題如上人壁','白居易','唐','御定全唐诗','yuding','','[]','自從為騃童，直至作衰翁。所好隨年異，為忙終日同。',72,'御定全唐詩/json/448.json','["自從為騃童，直至作衰翁。所好隨年異，為忙終日同。", "弄沙成佛塔，鏘玉謁王宮。彼此皆兒戲，須臾即色空。", "有營非了義，無著是真宗。兼恐勤修道，猶應在妄中。"]'),
('yuding-1','思子台有感二首','白居易','唐','御定全唐诗','yuding','','[]','曾家機上聞投杼，尹氏園中見掇蜂。',64,'御定全唐詩/json/448.json','["曾家機上聞投杼，尹氏園中見掇蜂。", "但以恩情生隙罅，何人不解作江充。", "闇生魑魅蠹生蟲，何異讒生疑阻中。", "但使武皇心似燭，江充不敢作江充。"]'),
('yuding-2','賦得邊城角','白居易','唐','御定全唐诗','yuding','','[]','邊角兩三枝，霜天隴上兒。望鄉相並立，向月一時吹。',48,'御定全唐詩/json/448.json','["邊角兩三枝，霜天隴上兒。望鄉相並立，向月一時吹。", "戰馬頭皆舉，征人手盡垂。嗚嗚三奏罷，城上展旌旗。"]'),
('yuding-3','憶洛中所居','白居易','唐','御定全唐诗','yuding','','[]','忽憶東都宅，春來事宛然。雪銷行徑裏，水上臥房前。',84,'御定全唐詩/json/448.json','["忽憶東都宅，春來事宛然。雪銷行徑裏，水上臥房前。", "厭綠栽黃竹，嫌紅種白蓮。醉教鶯送酒，閑遣鶴看船。", "幸是林園主，慚為食祿牽。宦情薄似紙，鄉思爭於弦。", "豈合姑蘇守，歸休更待年。"]'),
('yuding-4','想歸田園','白居易','唐','御定全唐诗','yuding','','[]','戀他朝市求何事，想取丘園樂此身。千首惡詩吟過日，',40,'御定全唐詩/json/448.json','["戀他朝市求何事，想取丘園樂此身。千首惡詩吟過日，", "快活不知如我者，人間能有幾多人。"]'),
('yuding-5','琴茶','白居易','唐','御定全唐诗','yuding','','[]','兀兀寄形群動內，陶陶任性一生間。自拋官後春多醉，',40,'御定全唐詩/json/448.json','["兀兀寄形群動內，陶陶任性一生間。自拋官後春多醉，", "窮通行止長相伴，誰道吾今無往還。"]'),
('yuding-6','贈楚州郭使君','白居易','唐','御定全唐诗','yuding','','[]','淮水東南第一州，山圍雉堞月當樓。黃金印綬懸腰底，',40,'御定全唐詩/json/448.json','["淮水東南第一州，山圍雉堞月當樓。黃金印綬懸腰底，", "當家美事堆身上，何啻林宗與細侯。"]'),
('yuding-7','和郭使君題枸杞','白居易','唐','御定全唐诗','yuding','','[]','山陽太守政嚴明，吏靜人安無犬驚。',32,'御定全唐詩/json/448.json','["山陽太守政嚴明，吏靜人安無犬驚。", "不知靈藥根成狗，怪得時聞吠夜聲。"]'),
('yuding-8','初到洛下閒遊','白居易','唐','御定全唐诗','yuding','','[]','漢庭重少身宜退，洛下閒居跡可逃。趁伴入朝應老醜，',40,'御定全唐詩/json/448.json','["漢庭重少身宜退，洛下閒居跡可逃。趁伴入朝應老醜，", "曾在東方千騎上，至今躞蹀馬頭高。"]'),
('yuding-9','醉贈劉二十八使君','白居易','唐','御定全唐诗','yuding','','[]','為我引杯添酒飲，與君把箸擊盤歌。詩稱國手徒為爾，',40,'御定全唐詩/json/448.json','["為我引杯添酒飲，與君把箸擊盤歌。詩稱國手徒為爾，", "亦知合被才名折，二十三年折太多。"]'),
('yuding-10','太湖石','白居易','唐','御定全唐诗','yuding','','[]','煙翠三秋色，波濤萬古痕。削成青玉片，截斷碧雲根。',48,'御定全唐詩/json/448.json','["煙翠三秋色，波濤萬古痕。削成青玉片，截斷碧雲根。", "風氣通岩穴，苔文護洞門。三峰具體小，應是華山孫。"]'),
('yuding-11','過敷水','白居易','唐','御定全唐诗','yuding','','[]','垂鞭欲渡羅敷水，處分鳴騶且緩驅。秦氏雙蛾久冥漠，',24,'御定全唐詩/json/448.json','["垂鞭欲渡羅敷水，處分鳴騶且緩驅。秦氏雙蛾久冥漠，"]'),
('yuding-12','南院','白居易','唐','御定全唐诗','yuding','','[]','林院無情緒，經春不一開。楊花飛作穗，榆莢落成堆。',48,'御定全唐詩/json/448.json','["林院無情緒，經春不一開。楊花飛作穗，榆莢落成堆。", "壯氣從中減，流年逐後催。只應如過客，病去老迎來。"]'),
('yuding-13','閑詠','白居易','唐','御定全唐诗','yuding','','[]','步月憐清景，眠松愛綠陰。早年詩思苦，晚歲道情深。',48,'御定全唐詩/json/448.json','["步月憐清景，眠松愛綠陰。早年詩思苦，晚歲道情深。", "夜學禪多坐，秋牽興暫吟。悠然兩事外，無處更留心。"]'),
('yuding-14','初授秘監，拜賜金紫，閑吟小酌，偶寫所懷','白居易','唐','御定全唐诗','yuding','','[]','紫袍新秘監，白首舊書生。鬢雪人間壽，腰金世上榮。',72,'御定全唐詩/json/448.json','["紫袍新秘監，白首舊書生。鬢雪人間壽，腰金世上榮。", "子孫無可念，產業不能營。酒引眼前興，詩留身後名。", "閑傾三數酌，醉詠十餘聲。便是羲皇代，先從心太平。"]'),
('yuding-15','新昌閒居，招楊郎中兄弟','白居易','唐','御定全唐诗','yuding','','[]','紗巾角枕病眠翁，忙少閑多誰與同。但有雙松當砌下，',40,'御定全唐詩/json/448.json','["紗巾角枕病眠翁，忙少閑多誰與同。但有雙松當砌下，", "暑月貧家何所有，客來唯贈北窗風。"]'),
('yuding-16','秘省後廳','白居易','唐','御定全唐诗','yuding','','[]','槐花雨潤新秋地，桐葉風翻欲夜天。',32,'御定全唐詩/json/448.json','["槐花雨潤新秋地，桐葉風翻欲夜天。", "盡日後廳無一事，白頭老監枕書眠。"]'),
('yuding-17','松齋偶興','白居易','唐','御定全唐诗','yuding','','[]','置心思慮外，滅跡是非間。約俸為生計，隨官換往還。',48,'御定全唐詩/json/448.json','["置心思慮外，滅跡是非間。約俸為生計，隨官換往還。", "耳煩聞曉角，眼醒見秋山。賴此松簷下，朝回半日閑。"]'),
('yuding-18','和楊郎中賀楊僕射致仕後楊侍郎門生合宴席上作','白居易','唐','御定全唐诗','yuding','','[]','業重關西繼大名，恩深闕下遂高情。祥鱣降伴趨庭鯉，',40,'御定全唐詩/json/448.json','["業重關西繼大名，恩深闕下遂高情。祥鱣降伴趨庭鯉，", "可憐玉樹連桃李，從古無如此會榮。"]'),
('yuding-19','松下琴贈客','白居易','唐','御定全唐诗','yuding','','[]','松寂風初定，琴清夜欲闌。偶因群動息，試撥一聲看。',48,'御定全唐詩/json/448.json','["松寂風初定，琴清夜欲闌。偶因群動息，試撥一聲看。", "寡鶴當徽怨，秋泉應指寒。慚君此傾聽，本不為君彈。"]'),
('yuding-20','秋齋','白居易','唐','御定全唐诗','yuding','','[]','晨起秋齋冷，蕭條稱病容。清風兩窗竹，白露一庭松。',48,'御定全唐詩/json/448.json','["晨起秋齋冷，蕭條稱病容。清風兩窗竹，白露一庭松。", "阮籍謀身拙，嵇康向事慵。生涯別有處，浩氣在心胸。"]'),
('yuding-21','塗山寺獨遊','白居易','唐','御定全唐诗','yuding','','[]','野徑行無伴，僧房宿有期。塗山來去熟，唯是馬蹄知。',24,'御定全唐詩/json/448.json','["野徑行無伴，僧房宿有期。塗山來去熟，唯是馬蹄知。"]'),
('yuding-22','登觀音台望城','白居易','唐','御定全唐诗','yuding','','[]','百千家似圍棋局，十二街如種菜畦。',32,'御定全唐詩/json/448.json','["百千家似圍棋局，十二街如種菜畦。", "遙認微微入朝火，一條星宿五門西。"]'),
('yuding-23','登靈應臺北望','白居易','唐','御定全唐诗','yuding','','[]','臨高始見人寰小，對遠方知色界空。',32,'御定全唐詩/json/448.json','["臨高始見人寰小，對遠方知色界空。", "回首卻歸朝市去，一稊米落太倉中。"]'),
('yuding-24','酬裴相公題興化小池見招長句','白居易','唐','御定全唐诗','yuding','','[]','為愛小塘招散客，不嫌老監與新詩。山公倒載無妨學，',40,'御定全唐詩/json/448.json','["為愛小塘招散客，不嫌老監與新詩。山公倒載無妨學，", "敢辭課拙酬高韻，一勺爭禁萬頃陂。"]'),
('yuding-25','閑行','白居易','唐','御定全唐诗','yuding','','[]','五十年來思慮熟，忙人應未勝閒人。林園傲逸真成貴，',40,'御定全唐詩/json/448.json','["五十年來思慮熟，忙人應未勝閒人。林園傲逸真成貴，", "儻年七十猶強健，尚得閒行十五春。"]'),
('yuding-26','閑出','白居易','唐','御定全唐诗','yuding','','[]','兀兀出門何處去，新昌街晚樹陰斜。',32,'御定全唐詩/json/448.json','["兀兀出門何處去，新昌街晚樹陰斜。", "馬蹄知意緣行熟，不向楊家即庾家。"]'),
('yuding-27','與僧智如夜話','白居易','唐','御定全唐诗','yuding','','[]','懶鈍尤知命，幽棲漸得朋。門閑無謁客，室靜有禪僧。',48,'御定全唐詩/json/448.json','["懶鈍尤知命，幽棲漸得朋。門閑無謁客，室靜有禪僧。", "爐向初冬火，籠停半夜燈。憂勞緣智巧，自喜百無能。"]'),
('yuding-28','憶廬山舊隱及洛下新居','白居易','唐','御定全唐诗','yuding','','[]','形骸黽勉班行內，骨肉句留俸祿中。無奈攀緣隨手長，',40,'御定全唐詩/json/448.json','["形骸黽勉班行內，骨肉句留俸祿中。無奈攀緣隨手長，", "自是未能歸去得，世間誰要白須翁。"]'),
('yuding-29','晚寒','白居易','唐','御定全唐诗','yuding','','[]','急景流如箭，淒風利似刀。暝催雞翅斂，寒束樹枝高。',48,'御定全唐詩/json/448.json','["急景流如箭，淒風利似刀。暝催雞翅斂，寒束樹枝高。", "縮水濃和酒，加綿厚絮袍。可憐冬計畢，暖臥醉陶陶。"]'),
('yuding-30','偶眠','白居易','唐','御定全唐诗','yuding','','[]','放杯書案上，枕臂火爐前。老愛尋思事，慵多取次眠。',48,'御定全唐詩/json/448.json','["放杯書案上，枕臂火爐前。老愛尋思事，慵多取次眠。", "妻教卸烏帽，婢與展青氈。便是屏風樣，何勞畫古賢。"]'),
('yuding-31','華城西北雉堞最高崔相公首創樓臺錢左丞繼種花果合為勝境題在雅篇歲暮獨遊悵然成詠','白居易','唐','御定全唐诗','yuding','','[]','高居稱君子，瀟灑四無鄰。丞相棟樑久，使君桃李新。',48,'御定全唐詩/json/448.json','["高居稱君子，瀟灑四無鄰。丞相棟樑久，使君桃李新。", "凝情看麗句，駐步想清塵。況是寒天客，樓空無主人。"]'),
('yuding-32','奉使途中，戲贈張常侍','白居易','唐','御定全唐诗','yuding','','[]','早風吹土滿長衢，驛騎星軺盡疾驅。',32,'御定全唐詩/json/448.json','["早風吹土滿長衢，驛騎星軺盡疾驅。", "共笑籃舁亦稱使，日馳一驛向東都。"]'),
('yuding-33','有小白馬乘馭多時奉使東行至稠桑驛溘然而斃足可驚傷不能忘情題二十韻','白居易','唐','御定全唐诗','yuding','','[]','能驟複能馳，翩翩白馬兒。毛寒一團雪，鬃薄萬條絲。',240,'御定全唐詩/json/448.json','["能驟複能馳，翩翩白馬兒。毛寒一團雪，鬃薄萬條絲。", "皂蓋春行日，驪駒曉從時。雙旌前獨步，五馬內偏騎。", "芳草承蹄葉，垂楊拂頂枝。跨將迎好客，惜不換妖姬。", "慢鞚游蕭寺，閑驅醉習池。睡來乘作夢，興發倚成詩。", "鞭為馴難下，鞍緣穩不離。北歸還共到，東使亦相隨。", "赭白何曾變，玄黃豈得知。嘶風覺聲急，踏雪怪行遲。", "昨夜猶芻秣，今朝尚縶維。臥槽應不起，顧主遂長辭。", "塵滅駸駸跡，霜留皎皎姿。度關形未改，過隙影難追。", "念倍燕求駿，情深項別騅。銀收鉤臆帶，金卸絡頭羈。", "何處埋奇骨，誰家覓弊帷。稠桑驛門外，吟罷涕雙垂。"]'),
('yuding-34','題噴玉泉','白居易','唐','御定全唐诗','yuding','','[]','泉噴聲如玉，潭澄色似空。練垂青嶂上，珠瀉綠盆中。',48,'御定全唐詩/json/448.json','["泉噴聲如玉，潭澄色似空。練垂青嶂上，珠瀉綠盆中。", "溜滴三秋雨，寒生六月風。何時此岩下，來作濯纓翁。"]'),
('yuding-35','酬皇甫賓客','白居易','唐','御定全唐诗','yuding','','[]','閑官兼慢使，著處易停輪。況欲逢新歲，仍初見故人。',48,'御定全唐詩/json/448.json','["閑官兼慢使，著處易停輪。況欲逢新歲，仍初見故人。", "冒寒尋到洛，待暖始歸秦。亦擬同攜手，城東略看春。"]'),
('yuding-36','種白蓮','白居易','唐','御定全唐诗','yuding','','[]','吳中白藕洛中栽，莫戀江南花懶開。',32,'御定全唐詩/json/448.json','["吳中白藕洛中栽，莫戀江南花懶開。", "萬里攜歸爾知否，紅蕉朱槿不將來。"]'),
('yuding-37','答蘇庶子','白居易','唐','御定全唐诗','yuding','','[]','偶作關東使，重陪洛下游。病來從斷酒，老去可禁愁。',48,'御定全唐詩/json/448.json','["偶作關東使，重陪洛下游。病來從斷酒，老去可禁愁。", "款曲偏青眼，蹉跎各白頭。蓬山閒氣味，依約似龍樓。"]'),
('yuding-38','答尉遲少監水閣重宴','白居易','唐','御定全唐诗','yuding','','[]','人情依舊歲華新，今日重招往日賓。雞黍重回千里駕，',40,'御定全唐詩/json/448.json','["人情依舊歲華新，今日重招往日賓。雞黍重回千里駕，", "聞道經營費心力，忍教成後屬他人。"]'),
('yuding-39','和劉郎中傷鄂姬','白居易','唐','御定全唐诗','yuding','','[]','不獨君嗟我亦嗟，西風北雪殺南花。',32,'御定全唐詩/json/448.json','["不獨君嗟我亦嗟，西風北雪殺南花。", "不知月夜魂歸處，鸚鵡洲頭第幾家。"]'),
('yuding-40','贈東鄰王十三','白居易','唐','御定全唐诗','yuding','','[]','攜手池邊月，開襟竹下風。驅愁知酒力，破睡見茶功。',48,'御定全唐詩/json/448.json','["攜手池邊月，開襟竹下風。驅愁知酒力，破睡見茶功。", "居處東西接，年顏老少同。能來為伴否，伊上作漁翁。"]'),
('yuding-41','早春同劉郎中寄宣武令狐相公','白居易','唐','御定全唐诗','yuding','','[]','梁園不到一年強，遙想清吟對綠觴。更有何人能飲酌，',40,'御定全唐詩/json/448.json','["梁園不到一年強，遙想清吟對綠觴。更有何人能飲酌，", "誰引相公開口笑，不逢白監與劉郎。"]'),
('yuding-42','寄太原李相公','白居易','唐','御定全唐诗','yuding','','[]','聞道北都今一變，政和軍樂萬人安。綺羅二八圍賓榻，',40,'御定全唐詩/json/448.json','["聞道北都今一變，政和軍樂萬人安。綺羅二八圍賓榻，", "世間大有虛榮貴，百歲無君一日歡。"]'),
('yuding-43','雪中寄令狐相公，兼呈夢得','白居易','唐','御定全唐诗','yuding','','[]','兔園春雪梁王會，想對金罍詠玉塵。',32,'御定全唐詩/json/448.json','["兔園春雪梁王會，想對金罍詠玉塵。", "今日相如身在此，不知客右坐何人。"]'),
('yuding-44','出使在途所騎馬死改乘肩輿將歸長安偶詠旅懷寄太原李相公','白居易','唐','御定全唐诗','yuding','','[]','驛路崎嶇泥雪寒，欲登籃輿一長歎。風光不見桃花騎，',40,'御定全唐詩/json/448.json','["驛路崎嶇泥雪寒，欲登籃輿一長歎。風光不見桃花騎，", "並州好馬應無數，不怕旌旄試覓看。"]'),
('yuding-45','有雙鶴留在洛中忽見劉郎中依然鳴顧劉因為鶴嘆二篇寄予予以二絕句答之','白居易','唐','御定全唐诗','yuding','','[]','辭鄉遠隔華亭水，逐我來棲緱嶺雲。',64,'御定全唐詩/json/448.json','["辭鄉遠隔華亭水，逐我來棲緱嶺雲。", "慚愧稻粱長不飽，未曾回眼向雞群。", "荒草院中池水畔，銜恩不去又經春。", "見君驚喜雙回顧，應為吟聲似主人。"]'),
('yuding-46','宿竇使君莊水亭','白居易','唐','御定全唐诗','yuding','','[]','使君何在在江東，池柳初黃杏欲紅。',32,'御定全唐詩/json/448.json','["使君何在在江東，池柳初黃杏欲紅。", "有興即來閑便宿，不知誰是主人翁。"]'),
('yuding-47','龍門下作','白居易','唐','御定全唐诗','yuding','','[]','龍門澗下濯塵纓，擬作閒人過此生。',32,'御定全唐詩/json/448.json','["龍門澗下濯塵纓，擬作閒人過此生。", "筋力不將諸處用，登山臨水詠詩行。"]'),
('yuding-48','姚侍禦見過，戲贈','白居易','唐','御定全唐诗','yuding','','[]','晚起春寒慵裹頭，客來池上偶同遊。',32,'御定全唐詩/json/448.json','["晚起春寒慵裹頭，客來池上偶同遊。", "東台禦史多提舉，莫按金章系布裘。"]'),
('yuding-49','履道春居','白居易','唐','御定全唐诗','yuding','','[]','微雨灑園林，新晴好一尋。低風洗池面，斜日拆花心。',48,'御定全唐詩/json/448.json','["微雨灑園林，新晴好一尋。低風洗池面，斜日拆花心。", "暝助嵐陰重，春添水色深。不如陶省事，猶抱有弦琴。"]'),
('yuding-50','題洛中第宅','白居易','唐','御定全唐诗','yuding','','[]','水木誰家宅，門高占地寬。懸魚掛青甃，行馬護朱欄。',72,'御定全唐詩/json/448.json','["水木誰家宅，門高占地寬。懸魚掛青甃，行馬護朱欄。", "春榭籠煙暖，秋庭鎖月寒。松膠黏琥珀，筠粉撲琅玕。", "試問池台主，多為將相官。終身不曾到，唯展宅圖看。"]'),
('yuding-51','寄殷協律','白居易','唐','御定全唐诗','yuding','','[]','五歲優遊同過日，一朝消散似浮雲。琴詩酒伴皆拋我，',40,'御定全唐詩/json/448.json','["五歲優遊同過日，一朝消散似浮雲。琴詩酒伴皆拋我，", "吳娘暮雨蕭蕭曲，自別江南更不聞。"]'),
('yuding-52','洛下諸客就宅相送，偶題西亭','白居易','唐','御定全唐诗','yuding','','[]','幾榻臨池坐，軒車冒雪過。交親致杯酒，僮僕解笙歌。',48,'御定全唐詩/json/448.json','["幾榻臨池坐，軒車冒雪過。交親致杯酒，僮僕解笙歌。", "流歲行將晚，浮榮得幾多。林泉應問我，不住意如何。"]'),
('yuding-53','答林泉','白居易','唐','御定全唐诗','yuding','','[]','好住舊林泉，回頭一悵然。漸知吾潦倒，深愧爾留連。',48,'御定全唐詩/json/448.json','["好住舊林泉，回頭一悵然。漸知吾潦倒，深愧爾留連。", "欲作棲雲計，須營種黍錢。更容求一郡，不得亦歸田。"]'),
('yuding-54','將發洛中枉令狐相公手劄兼辱二篇寵行以長句答之','白居易','唐','御定全唐诗','yuding','','[]','尺素忽驚來梓澤，雙金不惜送蓬山。八行落泊飛雲雨，',40,'御定全唐詩/json/448.json','["尺素忽驚來梓澤，雙金不惜送蓬山。八行落泊飛雲雨，", "收藏便作終身寶，何啻三年懷袖間。"]'),
('yuding-55','臨都驛答夢得六言二首','白居易','唐','御定全唐诗','yuding','','[]','揚子津頭月下，臨都驛裏燈前。',56,'御定全唐詩/json/448.json','["揚子津頭月下，臨都驛裏燈前。", "昨日老於前日，去年春似今年。", "謝守歸為秘監，馮公老作郎官。", "前事不須問著，新詩且更吟看。"]'),
('yuding-56','喜錢左丞再除華州，以詩伸賀','白居易','唐','御定全唐诗','yuding','','[]','左轄輟中台，門東委上才。彤襜經宿到，絳帳及春開。',48,'御定全唐詩/json/448.json','["左轄輟中台，門東委上才。彤襜經宿到，絳帳及春開。", "民望懇難奪，天心慈易回。那知不隔歲，重借寇恂來。"]'),
('yuding-57','和錢華州題少華清光絕句','白居易','唐','御定全唐诗','yuding','','[]','高情雅韻三峰守，主領清光管白雲。',32,'御定全唐詩/json/448.json','["高情雅韻三峰守，主領清光管白雲。", "自笑亦曾為刺史，蘇州肥膩不如君。"]'),
('yuding-58','送陝府王大夫','白居易','唐','御定全唐诗','yuding','','[]','金馬門前回劍佩，鐵牛城下擁旌旗。',32,'御定全唐詩/json/448.json','["金馬門前回劍佩，鐵牛城下擁旌旗。", "他時萬一為交代，留取甘棠三兩枝。"]'),
('yuding-59','代迎春花招劉郎中','白居易','唐','御定全唐诗','yuding','','[]','幸與松筠相近栽，不隨桃李一時開。',32,'御定全唐詩/json/448.json','["幸與松筠相近栽，不隨桃李一時開。", "杏園豈敢妨君去，未有花時且看來。"]'),
('yuding-60','玩迎春花贈楊郎中','白居易','唐','御定全唐诗','yuding','','[]','金英翠萼帶春寒，黃色花中有幾般。',32,'御定全唐詩/json/448.json','["金英翠萼帶春寒，黃色花中有幾般。", "恁君與向遊人道，莫作蔓菁花眼看。"]'),
('yuding-61','閑出','白居易','唐','御定全唐诗','yuding','','[]','身外無羈束，心中少是非。被花留便住，逢酒醉方歸。',48,'御定全唐詩/json/448.json','["身外無羈束，心中少是非。被花留便住，逢酒醉方歸。", "人事行時少，官曹入日稀。春寒游正好，穩馬薄綿衣。"]'),
('yuding-62','座上贈盧判官','白居易','唐','御定全唐诗','yuding','','[]','把酒承花花落頻，花香酒味相和春。',32,'御定全唐詩/json/448.json','["把酒承花花落頻，花香酒味相和春。", "莫言不是江南會，虛白亭中舊主人。"]'),
('yuding-63','曲江有感','白居易','唐','御定全唐诗','yuding','','[]','曲江西岸又春風，萬樹花前一老翁。',32,'御定全唐詩/json/448.json','["曲江西岸又春風，萬樹花前一老翁。", "遇酒逢花還且醉，若論惆悵事何窮。"]'),
('yuding-64','杏園花下贈劉郎中','白居易','唐','御定全唐诗','yuding','','[]','怪君把酒偏惆悵，曾是貞元花下人。',32,'御定全唐詩/json/448.json','["怪君把酒偏惆悵，曾是貞元花下人。", "自別花來多少事，東風二十四回春。"]'),
('yuding-65','花前有感，兼呈崔相公、劉郎中','白居易','唐','御定全唐诗','yuding','','[]','落花如雪鬢如霜，醉把花看益自傷。少日為名多檢束，',40,'御定全唐詩/json/448.json','["落花如雪鬢如霜，醉把花看益自傷。少日為名多檢束，", "何事同生壬子歲，老于崔相及劉郎。"]'),
('yuding-66','微之就拜尚書居易續除刑部因書賀意兼詠離懷','白居易','唐','御定全唐诗','yuding','','[]','我為憲部入南宮，君作尚書鎮浙東。老去一時成白首，',40,'御定全唐詩/json/448.json','["我為憲部入南宮，君作尚書鎮浙東。老去一時成白首，", "遠地官高親故少，些些談笑與誰同。"]'),
('yuding-67','喜與韋左丞同入南省，因敘舊以贈之','白居易','唐','御定全唐诗','yuding','','[]','早年同遇陶鈞主，利鈍精粗共在熔。金劍淬來長透匣，',40,'御定全唐詩/json/448.json','["早年同遇陶鈞主，利鈍精粗共在熔。金劍淬來長透匣，", "跛鱉雖遲騏驥疾，何妨中路亦相逢。"]'),
('yuding-68','伊州','白居易','唐','御定全唐诗','yuding','','[]','老去將何散老愁，新教小玉唱伊州。',32,'御定全唐詩/json/448.json','["老去將何散老愁，新教小玉唱伊州。", "亦應不得多年聽，未教成時已白頭。"]'),
('yuding-69','早朝','白居易','唐','御定全唐诗','yuding','','[]','鼓動出新昌，雞鳴赴建章。翩翩穩鞍馬，楚楚健衣裳。',72,'御定全唐詩/json/448.json','["鼓動出新昌，雞鳴赴建章。翩翩穩鞍馬，楚楚健衣裳。", "宮漏傳殘夜，城陰送早涼。月堤槐露氣，風燭樺煙香。", "雙闕龍相對，千官雁一行。漢庭方尚少，慚歎鬢如霜。"]'),
('yuding-70','答裴相公乞鶴','白居易','唐','御定全唐诗','yuding','','[]','警露聲音好，沖天相貌殊。終宜向遼廓，不稱在泥塗。',48,'御定全唐詩/json/448.json','["警露聲音好，沖天相貌殊。終宜向遼廓，不稱在泥塗。", "白首勞為伴，朱門幸見呼。不知疏野性，解愛鳳池無。"]'),
('yuding-71','晚從省歸','白居易','唐','御定全唐诗','yuding','','[]','朝回北闕值清晨，晚出南宮送暮春。入去丞郎非散秩，',40,'御定全唐詩/json/448.json','["朝回北闕值清晨，晚出南宮送暮春。入去丞郎非散秩，", "終是不如山下去，心頭眼底兩無塵。"]'),
('yuding-72','北窗閑坐','白居易','唐','御定全唐诗','yuding','','[]','虛窗兩叢竹，靜室一爐香。門外紅塵合，城中白日忙。',48,'御定全唐詩/json/448.json','["虛窗兩叢竹，靜室一爐香。門外紅塵合，城中白日忙。", "無煩尋道士，不要學仙方。自有延年術，心閑歲月長。"]'),
('yuding-73','酬嚴給事','白居易','唐','御定全唐诗','yuding','','[]','嬴女偷乘鳳去時，洞中潛歇弄瓊枝。',32,'御定全唐詩/json/448.json','["嬴女偷乘鳳去時，洞中潛歇弄瓊枝。", "不緣啼鳥春饒舌，青瑣仙郎可得知。"]'),
('yuding-74','京路','白居易','唐','御定全唐诗','yuding','','[]','西來為看秦山雪，東去緣尋洛苑春。',32,'御定全唐詩/json/448.json','["西來為看秦山雪，東去緣尋洛苑春。", "來去騰騰兩京路，閑行除我更無人。"]'),
('yuding-75','華州西','白居易','唐','御定全唐诗','yuding','','[]','每逢人靜慵多歇，不計程行困即眠。',32,'御定全唐詩/json/448.json','["每逢人靜慵多歇，不計程行困即眠。", "上得籃輿未能去，春風敷水店門前。"]'),
('yuding-76','從陝至東京','白居易','唐','御定全唐诗','yuding','','[]','從陝至東京，山低路漸平。風光四百里，車馬十三程。',48,'御定全唐詩/json/448.json','["從陝至東京，山低路漸平。風光四百里，車馬十三程。", "花共垂鞭看，杯多並轡傾。笙歌與談笑，隨分自將行。"]'),
('yuding-77','送春','白居易','唐','御定全唐诗','yuding','','[]','銀花鑿落從君勸，金屑琵琶為我彈。',32,'御定全唐詩/json/448.json','["銀花鑿落從君勸，金屑琵琶為我彈。", "不獨送春兼送老，更嘗一著更聽看。"]'),
('yuding-78','宿杜曲花下','白居易','唐','御定全唐诗','yuding','','[]','覓得花千樹，攜來酒一壺。懶歸兼擬宿，未醉豈勞扶。',96,'御定全唐詩/json/448.json','["覓得花千樹，攜來酒一壺。懶歸兼擬宿，未醉豈勞扶。", "但惜春將晚，寧愁日漸晡。籃輿為臥舍，漆盝是行廚。", "斑竹盛茶櫃，紅泥罨飯爐。眼前無所闕，身外更何須。", "小面琵琶婢，蒼頭觱篥奴。從君飽富貴，曾作此遊無。"]'),
('yuding-79','逢舊','白居易','唐','御定全唐诗','yuding','','[]','久別偶相逢，俱疑是夢中。即今歡樂事，放醆又成空。',24,'御定全唐詩/json/448.json','["久別偶相逢，俱疑是夢中。即今歡樂事，放醆又成空。"]'),
('yuding-80','繡婦歎','白居易','唐','御定全唐诗','yuding','','[]','連枝花樣繡羅襦，本擬新年餉小姑。自覺逢春饒悵望，',40,'御定全唐詩/json/448.json','["連枝花樣繡羅襦，本擬新年餉小姑。自覺逢春饒悵望，", "雖憑繡床都不繡，同床繡伴得知無。"]'),
('yuding-81','春詞','白居易','唐','御定全唐诗','yuding','','[]','低花樹映小妝樓，春入眉心兩點愁。',32,'御定全唐詩/json/448.json','["低花樹映小妝樓，春入眉心兩點愁。", "斜倚欄幹背鸚鵡，思量何事不回頭。"]'),
('yuding-82','恨詞','白居易','唐','御定全唐诗','yuding','','[]','翠黛眉低斂，紅珠淚暗銷。從來恨人意，不省似今朝。',24,'御定全唐詩/json/448.json','["翠黛眉低斂，紅珠淚暗銷。從來恨人意，不省似今朝。"]'),
('yuding-83','山石榴花十二韻','白居易','唐','御定全唐诗','yuding','','[]','曄曄複煌煌，花中無比方。豔夭宜小院，條短稱低廊。',144,'御定全唐詩/json/448.json','["曄曄複煌煌，花中無比方。豔夭宜小院，條短稱低廊。", "本是山頭物，今為砌下芳。千叢相向背，萬朵互低昂。", "照灼連朱檻，玲瓏映粉牆。風來添意態，日出助晶光。", "漸綻胭脂萼，猶含琴軫房。離披亂剪綵，斑駁未勻妝。", "絳焰燈千炷，紅裙妓一行。此時逢國色，何處覓天香。", "恐合栽金闕，思將獻玉皇。好差青鳥使，封作百花王。"]'),
('yuding-84','送敏中歸豳寧幕','白居易','唐','御定全唐诗','yuding','','[]','六十衰翁兒女悲，傍人應笑爾應知。弟兄垂老相逢日，',40,'御定全唐詩/json/448.json','["六十衰翁兒女悲，傍人應笑爾應知。弟兄垂老相逢日，", "司徒知我難為別，直過秋歸未訝遲。"]'),
('yuding-85','宴散','白居易','唐','御定全唐诗','yuding','','[]','小宴追涼散，平橋步月回。笙歌歸院落，燈火下樓臺。',48,'御定全唐詩/json/448.json','["小宴追涼散，平橋步月回。笙歌歸院落，燈火下樓臺。", "殘暑蟬催盡，新秋雁帶來。將何迎睡興，臨臥舉殘杯。"]'),
('yuding-86','人定','白居易','唐','御定全唐诗','yuding','','[]','人定月朧明，香消枕簟清。翠屏遮燭影，紅袖下簾聲。',48,'御定全唐詩/json/448.json','["人定月朧明，香消枕簟清。翠屏遮燭影，紅袖下簾聲。", "坐久吟方罷，眠初夢未成。誰家教鸚鵡，故故語相驚。"]'),
('yuding-87','池上','白居易','唐','御定全唐诗','yuding','','[]','褭褭涼風動，淒淒寒露零。蘭衰花始白，荷破葉猶青。',48,'御定全唐詩/json/448.json','["褭褭涼風動，淒淒寒露零。蘭衰花始白，荷破葉猶青。", "獨立棲沙鶴，雙飛照水螢。若為寥落境，仍值酒初醒。"]'),
('yuding-88','池窗','白居易','唐','御定全唐诗','yuding','','[]','池晚蓮芳謝，窗秋竹意深。更無人作伴，唯對一張琴。',24,'御定全唐詩/json/448.json','["池晚蓮芳謝，窗秋竹意深。更無人作伴，唯對一張琴。"]'),
('yuding-89','花酒','白居易','唐','御定全唐诗','yuding','','[]','香醅淺酌浮如蟻，雪鬢新梳薄似蟬。',32,'御定全唐詩/json/448.json','["香醅淺酌浮如蟻，雪鬢新梳薄似蟬。", "為報洛城花酒道，莫辭送老二三年。"]'),
('yuding-90','題崔常侍濟源莊','白居易','唐','御定全唐诗','yuding','','[]','穀口誰家住，雲扃鎖竹泉。主人何處去，蘿薜換貂蟬。',48,'御定全唐詩/json/448.json','["穀口誰家住，雲扃鎖竹泉。主人何處去，蘿薜換貂蟬。", "籍在金閨內，班排玉扆前。誠知憶山水，歸得是何年。"]'),
('yuding-91','認春戲呈馮少尹、李郎中、陳主簿','白居易','唐','御定全唐诗','yuding','','[]','認得春風先到處，西園南面水東頭。柳初變後條猶重，',40,'御定全唐詩/json/448.json','["認得春風先到處，西園南面水東頭。柳初變後條猶重，", "知君未別陽和意，直待春深始擬遊。"]'),
('yuding-92','魏堤有懷','白居易','唐','御定全唐诗','yuding','','[]','魏王堤下水，聲似使君灘。惆悵回頭聽，躊躕立馬看。',48,'御定全唐詩/json/448.json','["魏王堤下水，聲似使君灘。惆悵回頭聽，躊躕立馬看。", "蕩風波眼急，翻雪浪心寒。憶得瞿唐事，重吟行路難。"]'),
('yuding-93','柘枝詞','白居易','唐','御定全唐诗','yuding','','[]','柳闇長廊合，花深小院開。蒼頭鋪錦褥，皓腕捧銀盃。',48,'御定全唐詩/json/448.json','["柳闇長廊合，花深小院開。蒼頭鋪錦褥，皓腕捧銀盃。", "繡帽珠稠綴，香衫袖窄裁。將軍拄球杖，看按柘枝來。"]'),
('yuding-94','代夢得吟','白居易','唐','御定全唐诗','yuding','','[]','後來變化三分貴，同輩凋零太半無。世上爭先從盡汝，',40,'御定全唐詩/json/448.json','["後來變化三分貴，同輩凋零太半無。世上爭先從盡汝，", "不見山苗與林葉，迎春先綠亦先枯。"]'),
('yuding-95','寄答周協律','白居易','唐','御定全唐诗','yuding','','[]','故人敘舊寄新篇，惆悵江南到眼前。闇想樓臺萬餘裏，',40,'御定全唐詩/json/448.json','["故人敘舊寄新篇，惆悵江南到眼前。闇想樓臺萬餘裏，", "最憶後庭杯酒散，紅屏風掩綠窗眠。"]'),
('yuding-0','太和戊申歲大有年詔賜百寮出城觀稼謹書盛事以俟采詩','白居易','唐','御定全唐诗','yuding','','[]','清晨承詔命，豐歲閱田閭。膏雨抽苗足，涼風吐穗初。',72,'御定全唐詩/json/449.json','["清晨承詔命，豐歲閱田閭。膏雨抽苗足，涼風吐穗初。", "早禾黃錯落，晚稻綠扶疏。好入詩家詠，宜令史館書。", "散為萬姓食，堆作九年儲。莫道如雲稼，今秋雲不如。"]'),
('yuding-1','贈悼懷太子挽歌辭二首','白居易','唐','御定全唐诗','yuding','','[]','竹馬書薨歲，銅龍表葬時。永言窀穸事，全用少陽儀。',96,'御定全唐詩/json/449.json','["竹馬書薨歲，銅龍表葬時。永言窀穸事，全用少陽儀。", "壽夭由天命，哀榮出聖慈。恭聞褒贈詔，軫念在與夷。", "剪葉藩封早，承華冊命尊。笙歌辭洛苑，風雪蔽梁園。", "鹵簿淩霜宿，銘旌向月翻。宮寮不逮事，哭送出都門。"]'),
('yuding-2','雨中招張司業宿','白居易','唐','御定全唐诗','yuding','','[]','過夏衣香潤，迎秋簟色鮮。斜支花石枕，臥詠蕊珠篇。',48,'御定全唐詩/json/449.json','["過夏衣香潤，迎秋簟色鮮。斜支花石枕，臥詠蕊珠篇。", "泥濘非遊日，陰沉好睡天。能來同宿否，聽雨對床眠。"]'),
('yuding-3','和集賢劉學士早朝作','白居易','唐','御定全唐诗','yuding','','[]','吟君昨日早朝詩，金禦爐前喚仗時。煙吐白龍頭宛轉，',40,'御定全唐詩/json/449.json','["吟君昨日早朝詩，金禦爐前喚仗時。煙吐白龍頭宛轉，", "從此摩霄去非晚，鬢邊未有一莖絲。"]'),
('yuding-4','送陝州王司馬建赴任','白居易','唐','御定全唐诗','yuding','','[]','陝州司馬去何如，養靜資貧兩有餘。公事閑忙同少尹，',40,'御定全唐詩/json/449.json','["陝州司馬去何如，養靜資貧兩有餘。公事閑忙同少尹，", "自有鐵牛無詠者，料君投刃必應虛。"]'),
('yuding-5','對琴待月','白居易','唐','御定全唐诗','yuding','','[]','竹院新晴夜，松窗未臥時。共琴為老伴，與月有秋期。',48,'御定全唐詩/json/449.json','["竹院新晴夜，松窗未臥時。共琴為老伴，與月有秋期。", "玉軫臨風久，金波出霧遲。幽音待清景，唯是我心知。"]'),
('yuding-6','楊家南亭','白居易','唐','御定全唐诗','yuding','','[]','小亭門向月斜開，滿地涼風滿地苔。',32,'御定全唐詩/json/449.json','["小亭門向月斜開，滿地涼風滿地苔。", "此院好彈秋思處，終須一夜抱琴來。"]'),
('yuding-7','早寒','白居易','唐','御定全唐诗','yuding','','[]','黃葉聚牆角，青苔圍柱根。被經霜後薄，鏡遇雨來昏。',48,'御定全唐詩/json/449.json','["黃葉聚牆角，青苔圍柱根。被經霜後薄，鏡遇雨來昏。", "半卷寒簷幕，斜開暖閣門。迎冬兼送老，只仰酒盈尊。"]'),
('yuding-8','齋月靜居','白居易','唐','御定全唐诗','yuding','','[]','病來心靜一無思，老去身閑百不為。忽忽眼塵猶愛睡，',40,'御定全唐詩/json/449.json','["病來心靜一無思，老去身閑百不為。忽忽眼塵猶愛睡，", "萬慮消停百神泰，唯應寂寞殺三屍。"]'),
('yuding-9','宿裴相公興化池亭','白居易','唐','御定全唐诗','yuding','','[]','林亭一出宿風塵，忘卻平津是要津。松閣晴看山色近，',40,'御定全唐詩/json/449.json','["林亭一出宿風塵，忘卻平津是要津。松閣晴看山色近，", "何似掄才濟川外，別開池館待交親。"]'),
('yuding-10','和劉郎中望終南山秋雪','白居易','唐','御定全唐诗','yuding','','[]','遍覽古今集，都無秋雪詩。陽春先唱後，陰嶺未消時。',48,'御定全唐詩/json/449.json','["遍覽古今集，都無秋雪詩。陽春先唱後，陰嶺未消時。", "草訝霜凝重，松疑鶴散遲。清光莫獨佔，亦對白雲司。"]'),
('yuding-11','廣府胡尚書頻寄詩，因答絕句','白居易','唐','御定全唐诗','yuding','','[]','尚書清白臨南海，雖飲貪泉心不回。',32,'御定全唐詩/json/449.json','["尚書清白臨南海，雖飲貪泉心不回。", "唯向詩中得珠玉，時時寄到帝鄉來。"]'),
('yuding-12','送鶴與裴相臨別贈詩','白居易','唐','御定全唐诗','yuding','','[]','司空愛爾爾須知，不信聽吟送鶴詩。羽翮勢高寧惜別，',40,'御定全唐詩/json/449.json','["司空愛爾爾須知，不信聽吟送鶴詩。羽翮勢高寧惜別，", "穩上青雲勿回顧，的應勝在白家時。"]'),
('yuding-13','令狐相公拜尚書後有喜從鎮歸朝之作劉郎中先和因以繼之','白居易','唐','御定全唐诗','yuding','','[]','車騎新從梁苑回，履聲佩響入中台。鳳池望在終重去，',40,'御定全唐詩/json/449.json','["車騎新從梁苑回，履聲佩響入中台。鳳池望在終重去，", "尚書首唱郎中和，不計官資只計才。"]'),
('yuding-14','送河南尹馮學士赴任','白居易','唐','御定全唐诗','yuding','','[]','石渠金谷中間路，軒騎翩翩十日程。清洛飲冰添苦節，',40,'御定全唐詩/json/449.json','["石渠金谷中間路，軒騎翩翩十日程。清洛飲冰添苦節，", "何似府寮京令外，別教三十六峰迎。"]'),
('yuding-15','讀鄂公傳','白居易','唐','御定全唐诗','yuding','','[]','高臥深居不見人，功名鬥藪似灰塵。',32,'御定全唐詩/json/449.json','["高臥深居不見人，功名鬥藪似灰塵。", "唯留一部清商樂，月下風前伴老身。"]'),
('yuding-16','烏夜啼','白居易','唐','御定全唐诗','yuding','','[]','城上歸時晚，庭前宿處危。月明無葉樹，霜滑有風枝。',48,'御定全唐詩/json/449.json','["城上歸時晚，庭前宿處危。月明無葉樹，霜滑有風枝。", "啼澀饑喉咽，飛低凍翅垂。畫堂鸚鵡鳥，冷暖不相知。"]'),
('yuding-17','鏡換杯','白居易','唐','御定全唐诗','yuding','','[]','欲將珠匣青銅鏡，換取金尊白玉卮。鏡裏老來無避處，',40,'御定全唐詩/json/449.json','["欲將珠匣青銅鏡，換取金尊白玉卮。鏡裏老來無避處，", "不似杜康神用速，十分一盞便開眉。"]'),
('yuding-18','冬夜聞蟲','白居易','唐','御定全唐诗','yuding','','[]','蟲聲冬思苦於秋，不解愁人聞亦愁。',32,'御定全唐詩/json/449.json','["蟲聲冬思苦於秋，不解愁人聞亦愁。", "我是老翁聽不畏，少年莫聽白君頭。"]'),
('yuding-19','雙鸚鵡','白居易','唐','御定全唐诗','yuding','','[]','綠衣整頓雙棲起，紅觜分明對語時。始覺琵琶弦莽鹵，',40,'御定全唐詩/json/449.json','["綠衣整頓雙棲起，紅觜分明對語時。始覺琵琶弦莽鹵，", "若稱白家鸚鵡鳥，籠中兼合解吟詩。"]'),
('yuding-20','贈朱道士','白居易','唐','御定全唐诗','yuding','','[]','儀容白皙上仙郎，方寸清虛內道場。兩翼化生因服藥，',40,'御定全唐詩/json/449.json','["儀容白皙上仙郎，方寸清虛內道場。兩翼化生因服藥，", "盡日窗間更無事，唯燒一炷降真香。"]'),
('yuding-21','昨以拙詩十首寄西川杜相公相公亦以新作十首惠然報示首數雖等工拙不倫重以一章用伸答謝','白居易','唐','御定全唐诗','yuding','','[]','詩家律手在成都，權與尋常將相殊。剪截五言兼用鉞，',40,'御定全唐詩/json/449.json','["詩家律手在成都，權與尋常將相殊。剪截五言兼用鉞，", "篇數雖同光價異，十魚目換十驪珠。"]'),
('yuding-22','和汴州令狐相公新於郡內栽竹百竿拆壁開軒旦夕對玩偶題七言五韻','白居易','唐','御定全唐诗','yuding','','[]','梁園修竹舊傳名，園廢年深竹不生。千畝荒涼尋未得，',48,'御定全唐詩/json/449.json','["梁園修竹舊傳名，園廢年深竹不生。千畝荒涼尋未得，", "煙葉蒙籠侵夜色，風枝蕭颯欲秋聲。更登樓望尤堪重，"]'),
('yuding-23','重答汝州李六使君見和憶吳中舊遊五首','白居易','唐','御定全唐诗','yuding','','[]','為憶娃宮與虎丘，玩君新作不能休。蜀箋寫出篇篇好，',40,'御定全唐詩/json/449.json','["為憶娃宮與虎丘，玩君新作不能休。蜀箋寫出篇篇好，", "由來事過多堪惜，何況蘇州勝汝州。"]'),
('yuding-24','見殷堯藩侍御憶江南詩三十首詩中多敘蘇杭勝事余嘗典二郡因繼和之','白居易','唐','御定全唐诗','yuding','','[]','江南名郡數蘇杭，寫在殷家三十章。君是旅人猶苦憶，',40,'御定全唐詩/json/449.json','["江南名郡數蘇杭，寫在殷家三十章。君是旅人猶苦憶，", "為念舊遊終一去，扁舟直擬到滄浪。"]'),
('yuding-25','聞新蟬贈劉二十八','白居易','唐','御定全唐诗','yuding','','[]','蟬發一聲時，槐花帶兩枝。只應催我老，兼遣報君知。',48,'御定全唐詩/json/449.json','["蟬發一聲時，槐花帶兩枝。只應催我老，兼遣報君知。", "白髮生頭速，青雲入手遲。無過一杯酒，相勸數開眉。"]'),
('yuding-26','贈王山人','白居易','唐','御定全唐诗','yuding','','[]','玉芝觀裏王居士，服氣餐霞善養身。夜後不聞龜喘息，',40,'御定全唐詩/json/449.json','["玉芝觀裏王居士，服氣餐霞善養身。夜後不聞龜喘息，", "貴重榮華輕壽命，知君悶見世間人。"]'),
('yuding-27','和劉郎中學士題集賢閣','白居易','唐','御定全唐诗','yuding','','[]','朱閣青山高庳齊，與君才子作詩題。傍聞大內笙歌近，',40,'御定全唐詩/json/449.json','["朱閣青山高庳齊，與君才子作詩題。傍聞大內笙歌近，", "欲知丞相優賢意，百步新廊不蹋泥。"]'),
('yuding-28','觀幻','白居易','唐','御定全唐诗','yuding','','[]','有起皆因滅，無暌不暫同。從歡終作戚，轉苦又成空。',48,'御定全唐詩/json/449.json','["有起皆因滅，無暌不暫同。從歡終作戚，轉苦又成空。", "次第花生眼，須臾燭過風。更無尋覓處，鳥跡印空中。"]'),
('yuding-29','病假中龐少尹攜魚酒相過','白居易','唐','御定全唐诗','yuding','','[]','宦情牢落年將暮，病假聯綿日漸深。被老相催雖白首，',40,'御定全唐詩/json/449.json','["宦情牢落年將暮，病假聯綿日漸深。被老相催雖白首，", "勞動故人龐閣老，提魚攜酒遠相尋。"]'),
('yuding-30','聽田順兒歌','白居易','唐','御定全唐诗','yuding','','[]','戛玉敲冰聲未停，嫌雲不遏入青冥。',32,'御定全唐詩/json/449.json','["戛玉敲冰聲未停，嫌雲不遏入青冥。", "爭得黃金滿衫袖，一時拋與斷年聽。"]'),
('yuding-31','聽曹剛琵琶兼示重蓮','白居易','唐','御定全唐诗','yuding','','[]','撥撥弦弦意不同，胡啼番語兩玲瓏。',32,'御定全唐詩/json/449.json','["撥撥弦弦意不同，胡啼番語兩玲瓏。", "誰能截得曹剛手，插向重蓮衣袖中。"]'),
('yuding-32','酬令狐相公春日尋花見寄六韻','白居易','唐','御定全唐诗','yuding','','[]','病臥帝王州，花時不得遊。老應隨日至，春肯為人留。',72,'御定全唐詩/json/449.json','["病臥帝王州，花時不得遊。老應隨日至，春肯為人留。", "粉壞杏將謝，火繁桃尚稠。白飄僧院地，紅落酒家樓。", "空裏雪相似，晚來風不休。吟君悵望句，如到曲江頭。"]'),
('yuding-33','和劉郎中曲江春望見示','白居易','唐','御定全唐诗','yuding','','[]','芳景多遊客，衰翁獨在家。肺傷妨飲酒，眼痛忌看花。',48,'御定全唐詩/json/449.json','["芳景多遊客，衰翁獨在家。肺傷妨飲酒，眼痛忌看花。", "寺路隨江曲，宮牆夾道斜。羨君猶壯健，不枉度年華。"]'),
('yuding-34','送東都留守令狐尚書赴任','白居易','唐','御定全唐诗','yuding','','[]','翠華黃屋未東巡，碧洛青嵩付大臣。地稱高情多水竹，',40,'御定全唐詩/json/449.json','["翠華黃屋未東巡，碧洛青嵩付大臣。地稱高情多水竹，", "歌酒家家花處處，莫空管領上陽春。"]'),
('yuding-35','自題新昌居止，因招楊郎中小飲','白居易','唐','御定全唐诗','yuding','','[]','地偏坊遠巷仍斜，最近東頭是白家。宿雨長齊鄰舍柳，',40,'御定全唐詩/json/449.json','["地偏坊遠巷仍斜，最近東頭是白家。宿雨長齊鄰舍柳，", "能到南園同醉否，笙歌隨分有些些。"]'),
('yuding-36','南園試小樂','白居易','唐','御定全唐诗','yuding','','[]','小園斑駁花初發，新樂錚摐教欲成。紅萼紫房皆手植，',40,'御定全唐詩/json/449.json','["小園斑駁花初發，新樂錚摐教欲成。紅萼紫房皆手植，", "不飲一杯聽一曲，將何安慰老心情。"]'),
('yuding-37','和微之春日投簡陽明洞天五十韻','白居易','唐','御定全唐诗','yuding','','[]','青陽行已半，白日坐將徂。越國強仍大，稽城高且孤。',576,'御定全唐詩/json/449.json','["青陽行已半，白日坐將徂。越國強仍大，稽城高且孤。", "利饒鹽煮海，名勝水澄湖。牛鬥天垂象，台明地展圖。", "瑰奇填市井，佳麗溢闉闍。勾踐遺風霸，西施舊俗姝。", "船頭龍夭矯，橋腳獸睢盱。鄉味珍蟛蚏，時鮮貴鷓鴣。", "語言諸夏異，衣服一方殊。搗練蛾眉婢，鳴榔蛙角奴。", "江清敵伊洛，山翠勝荊巫。華表雙棲鶴，聯檣幾點烏。", "煙波分渡口，雲樹接城隅。澗遠松如畫，洲平水似鋪。", "綠科秧早稻，紫筍折新蘆。暖蹋泥中藕，香尋石上蒲。", "雨來萌盡達，雷後蟄全蘇。柳眼黃絲纇，花房絳蠟珠。", "林風新竹折，野燒老桑枯。帶嚲長枝蕙，錢穿短貫榆。", "暄和生野菜，卑濕長街蕪。女浣紗相伴，兒烹鯉一呼。", "山魈啼稚子，林狖掛山都。產業論蠶蟻，孳生計鴨雛。", "泉岩雪飄灑，苔壁錦漫糊。堰限舟航路，堤通車馬途。", "耶溪岸回合，禹廟徑盤紆。洞穴何因鑿，星槎誰與刳。", "石凹仙藥臼，峰峭佛香爐。去為投金簡，來因挈玉壺。", "貴仍招客宿，健未要人扶。聞望賢丞相，儀形美丈夫。", "前驅駐旌旆，偏坐列笙竽。刺史旟翻隼，尚書履曳鳧。", "學禪超後有，觀妙造虛無。髻裏傳僧寶，環中得道樞。", "登樓詩八詠，置硯賦三都。捧擁羅將綺，趨蹌紫與朱。", "廟謨藏稷契，兵略貯孫吳。令下三軍整，風高四海趨。", "千家得慈母，六郡事嚴姑。重士過三哺，輕財抵一銖。", "送觥歌宛轉，嘲妓笑盧胡。佐飲時炮鱉，蠲酲數鱠鱸。", "醉鄉雖咫尺，樂事亦須臾。若不中賢聖，何由外智愚。", "伊予一生志，我爾百年軀。江上三千里，城中十二衢。"]'),
('yuding-38','酬鄭侍禦多雨春空過詩三十韻','白居易','唐','御定全唐诗','yuding','','[]','南雨來多滯，東風動即狂。月行離畢急，龍走召雲忙。',360,'御定全唐詩/json/449.json','["南雨來多滯，東風動即狂。月行離畢急，龍走召雲忙。", "鬼轉雷車響，蛇騰電策光。浸淫天似漏，沮洳地成瘡。", "慘澹陰煙白，空蒙宿霧黃。暗遮千里目，悶結九回腸。", "寂寞羈臣館，深沉思婦房。鏡昏鸞滅影，衣潤麝消香。", "蘭濕難紉佩，花凋易落妝。沾黃鶯翅重，滋綠草心長。", "紫陌皆泥濘，黃汙共淼茫。恐霖成怪沴，望霽劇禎祥。", "楚柳腰肢嚲，湘筠涕淚滂。晝昏疑是夜，陰盛勝於陽。", "居士巾皆墊，行人蓋盡張。跳蛙還屢出，移蟻欲深藏。", "端坐交遊廢，閑行去步妨。愁生垂白叟，惱殺蹋青娘。", "變海常須慮，為魚慎勿忘。此時方共懼，何處可相將。", "已望東溟禱，仍封北戶禳。卻思逢旱魃，誰喜見商羊。", "預怕為蠶病，先憂作麥傷。惠應施浹洽，政豈假揄揚。", "祀典修咸秩，農書振滿床。丹誠期懇苦，白日會昭彰。", "賑廩賙饑戶，苫城備壞牆。且當營歲事，寧暇惜年芳。", "德勝令災弭，人安在吏良。尚書心若此，不枉系金章。"]'),
('yuding-39','和春深二十首','白居易','唐','御定全唐诗','yuding','','[]','何處春深好，春深富貴家。馬為中路鳥，妓作後庭花。',576,'御定全唐詩/json/449.json','["何處春深好，春深富貴家。馬為中路鳥，妓作後庭花。", "羅綺驅論隊，金銀用斷車。眼前何所苦，唯苦日西斜。", "何處春深好，春深貧賤家。荒涼三徑草，冷落四鄰花。", "奴困歸傭力，妻愁出賃車。途窮平路險，舉足劇褒斜。", "何處春深好，春深執政家。鳳池添硯水，雞樹落衣花。", "詔借當衢宅，恩容上殿車。延英開對久，門與日西斜。", "何處春深好，春深方鎮家。通犀排帶胯，瑞鶻勘袍花。", "飛絮沖球馬，垂楊拂妓車。戎裝拜春設，左握寶刀斜。", "何處春深好，春深刺史家。陰繁棠布葉，岐秀麥分花。", "五匹鳴珂馬，雙輪畫軾車。和風引行樂，葉葉隼旟斜。", "何處春深好，春深學士家。鳳書裁五色，馬鬣剪三花。", "蠟炬開明火，銀台賜物車。相逢不敢揖，彼此帽低斜。", "何處春深好，春深女學家。慣看溫室樹，飽識浴堂花。", "禦印提隨仗，香箋把下車。宋家宮樣髻，一片綠雲斜。", "何處春深好，春深禦史家。絮縈驄馬尾，蝶繞繡衣花。", "破柱行持斧，埋輪立駐車。入班遙認得，魚貫一行斜。", "何處春深好，春深遷客家。一杯寒食酒，萬里故園花。", "炎瘴蒸如火，光陰走似車。為憂鵩鳥至，只恐日光斜。", "何處春深好，春深經業家。唯求太常第，不管曲江花。", "折桂名慚郤，收螢志慕車。官場泥補處，最怕寸陰斜。", "何處春深好，春深隱士家。野衣裁薜葉，山飯曬松花。", "蘭索紉幽佩，蒲輪駐軟車。林間箕踞坐，白眼向人斜。", "何處春深好，春深漁父家。松灣隨棹月，桃浦落船花。", "投餌移輕楫，牽輪轉小車。蕭蕭蘆葉裏，風起釣絲斜。"]'),
('yuding-40','詠家醞十韻','白居易','唐','御定全唐诗','yuding','','[]','獨醒從古笑靈均，長醉如今斅伯倫。舊法依稀傳自杜，',88,'御定全唐詩/json/449.json','["獨醒從古笑靈均，長醉如今斅伯倫。舊法依稀傳自杜，", "釀糯豈勞炊範黍，撇篘何假漉陶巾。常嫌竹葉猶凡濁，", "捧疑明水從空化，飲似陽和滿腹春。色洞玉壺無表裏，", "應是世間賢聖物，與君還往擬終身。"]'),
('yuding-41','池鶴二首','白居易','唐','御定全唐诗','yuding','','[]','高竹籠前無伴侶，亂雞群裏有風標。低頭乍恐丹砂落，',80,'御定全唐詩/json/449.json','["高竹籠前無伴侶，亂雞群裏有風標。低頭乍恐丹砂落，", "臨風一唳思何事，悵望青田雲水遙。", "池中此鶴鶴中稀，恐是遼東老令威。帶雪松枝翹膝脛，", "若問故巢知處在，主人相戀未能歸。"]'),
('yuding-42','對酒五首','白居易','唐','御定全唐诗','yuding','','[]','巧拙賢愚相是非，何如一醉盡忘機。',160,'御定全唐詩/json/449.json','["巧拙賢愚相是非，何如一醉盡忘機。", "君知天地中寬窄，雕鶚鸞皇各自飛。", "蝸牛角上爭何事，石火光中寄此身。", "隨富隨貧且歡樂，不開口笑是癡人。", "丹砂見火去無跡，白髮泥人來不休。", "賴有酒仙相暖熱，松喬醉即到前頭。", "百歲無多時壯健，一春能幾日晴明。", "相逢且莫推辭醉，聽唱陽關第四聲。", "昨日低眉問疾來，今朝收淚吊人回。", "眼前流例君看取，且遣琵琶送一杯。"]'),
('yuding-43','僧院花','白居易','唐','御定全唐诗','yuding','','[]','欲悟色空為佛事，故栽芳樹在僧家。',32,'御定全唐詩/json/449.json','["欲悟色空為佛事，故栽芳樹在僧家。", "細看便是華嚴偈，方便風開智慧花。"]'),
('yuding-44','老戒','白居易','唐','御定全唐诗','yuding','','[]','我有白頭戒，聞于韓侍郎。老多憂活計，病更戀班行。',48,'御定全唐詩/json/449.json','["我有白頭戒，聞于韓侍郎。老多憂活計，病更戀班行。", "矍鑠誇身健，周遮說話長。不知吾免否，兩鬢已成霜。"]'),
('yuding-45','洛橋寒食日作十韻','白居易','唐','御定全唐诗','yuding','','[]','上苑風煙好，中橋道路平。蹴球塵不起，潑火雨新晴。',120,'御定全唐詩/json/449.json','["上苑風煙好，中橋道路平。蹴球塵不起，潑火雨新晴。", "宿醉頭仍重，晨遊眼乍明。老慵雖省事，春誘尚多情。", "遇客踟躕立，尋花取次行。連錢嚼金勒，鑿落寫銀罌。", "府醞傷教送，官娃豈要迎。舞腰那及柳，歌舌不如鶯。", "鄉國真堪戀，光陰可合輕。三年遇寒食，盡在洛陽城。"]'),
('yuding-46','快活','白居易','唐','御定全唐诗','yuding','','[]','可惜鶯啼花落處，一壺濁酒送殘春。可憐月好風涼夜，',40,'御定全唐詩/json/449.json','["可惜鶯啼花落處，一壺濁酒送殘春。可憐月好風涼夜，", "誰知將相王侯外，別有優遊快活人。"]'),
('yuding-47','送令狐相公赴太原','白居易','唐','御定全唐诗','yuding','','[]','六纛雙旌萬鐵衣，並汾舊路滿光輝。青衫書記何年去，',40,'御定全唐詩/json/449.json','["六纛雙旌萬鐵衣，並汾舊路滿光輝。青衫書記何年去，", "此都莫作多時計，再為蒼生入紫微。"]'),
('yuding-48','不出','白居易','唐','御定全唐诗','yuding','','[]','簷前新葉覆殘花，席上餘杯對早茶。',32,'御定全唐詩/json/449.json','["簷前新葉覆殘花，席上餘杯對早茶。", "好是老身銷日處，誰能騎馬傍人家。"]'),
('yuding-49','惜落花','白居易','唐','御定全唐诗','yuding','','[]','夜來風雨急，無復舊花林。枝上三分落，園中二寸深。',48,'御定全唐詩/json/449.json','["夜來風雨急，無復舊花林。枝上三分落，園中二寸深。", "日斜啼鳥思，春盡老人心。莫怪添杯飲，情多酒不禁。"]'),
('yuding-50','老病','白居易','唐','御定全唐诗','yuding','','[]','晝聽笙歌夜醉眠，若非月下即花前。',32,'御定全唐詩/json/449.json','["晝聽笙歌夜醉眠，若非月下即花前。", "如今老病須知分，不負春來二十年。"]'),
('yuding-51','憶晦叔','白居易','唐','御定全唐诗','yuding','','[]','游山弄水攜詩卷，看月尋花把酒杯。',32,'御定全唐詩/json/449.json','["游山弄水攜詩卷，看月尋花把酒杯。", "六事盡思君作伴，幾時歸到洛陽來。"]'),
('yuding-52','送徐州高僕射赴鎮','白居易','唐','御定全唐诗','yuding','','[]','大紅旆引碧幢旌，新拜將軍指點行。戰將易求何足貴，',40,'御定全唐詩/json/449.json','["大紅旆引碧幢旌，新拜將軍指點行。戰將易求何足貴，", "應笑蹉跎白頭尹，風塵唯管洛陽城。"]'),
('yuding-53','琴酒','白居易','唐','御定全唐诗','yuding','','[]','耳根得聽琴初暢，心地忘機酒半酣。',32,'御定全唐詩/json/449.json','["耳根得聽琴初暢，心地忘機酒半酣。", "若使啟期兼解醉，應言四樂不言三。"]'),
('yuding-54','聽幽蘭','白居易','唐','御定全唐诗','yuding','','[]','琴中古曲是幽蘭，為我殷勤更弄看。',32,'御定全唐詩/json/449.json','["琴中古曲是幽蘭，為我殷勤更弄看。", "欲得身心俱靜好，自彈不及聽人彈。"]'),
('yuding-55','六年秋重題白蓮','白居易','唐','御定全唐诗','yuding','','[]','素房含露玉冠鮮，紺葉搖風鈿扇圓。本是吳州供進藕，',40,'御定全唐詩/json/449.json','["素房含露玉冠鮮，紺葉搖風鈿扇圓。本是吳州供進藕，", "不獨池中花故舊，兼乘舊日采花船。"]'),
('yuding-56','元相公挽歌詞三首','白居易','唐','御定全唐诗','yuding','','[]','銘旌官重威儀盛，騎吹聲繁鹵簿長。',96,'御定全唐詩/json/449.json','["銘旌官重威儀盛，騎吹聲繁鹵簿長。", "後魏帝孫唐宰相，六年七月葬咸陽。", "墓門已閉笳簫去，唯有夫人哭不休。", "蒼蒼露草咸陽壟，此是千秋第一秋。", "送葬萬人皆慘澹，反虞駟馬亦悲鳴。", "琴書劍佩誰收拾，三歲遺孤新學行。"]'),
('yuding-57','臥聽法曲霓裳','白居易','唐','御定全唐诗','yuding','','[]','金磬玉笙調已久，牙床角枕睡常遲。朦朧閑夢初成後，',40,'御定全唐詩/json/449.json','["金磬玉笙調已久，牙床角枕睡常遲。朦朧閑夢初成後，", "起嘗殘酌聽餘曲，斜背銀缸半下帷。"]'),
('yuding-58','結之','白居易','唐','御定全唐诗','yuding','','[]','歡愛今何在，悲啼亦是空。同為一夜夢，共過十年中。',24,'御定全唐詩/json/449.json','["歡愛今何在，悲啼亦是空。同為一夜夢，共過十年中。"]'),
('yuding-59','五鳳樓晚望','白居易','唐','御定全唐诗','yuding','','[]','晴陽晚照濕煙銷，五鳳樓高天泬寥。野綠全經朝雨洗，',40,'御定全唐詩/json/449.json','["晴陽晚照濕煙銷，五鳳樓高天泬寥。野綠全經朝雨洗，", "自入秋來風景好，就中最好是今朝。"]'),
('yuding-60','寄劉蘇州','白居易','唐','御定全唐诗','yuding','','[]','去年八月哭微之，今年八月哭敦詩。何堪老淚交流日，',40,'御定全唐詩/json/449.json','["去年八月哭微之，今年八月哭敦詩。何堪老淚交流日，", "同年同病同心事，除卻蘇州更是誰。"]'),
('yuding-61','送客','白居易','唐','御定全唐诗','yuding','','[]','病上籃輿相送來，衰容秋思兩悠哉。',32,'御定全唐詩/json/449.json','["病上籃輿相送來，衰容秋思兩悠哉。", "涼風嫋嫋吹槐子，卻請行人勸一杯。"]'),
('yuding-62','秋思','白居易','唐','御定全唐诗','yuding','','[]','夕照紅於燒，晴空碧勝藍。獸形雲不一，弓勢月初三。',48,'御定全唐詩/json/449.json','["夕照紅於燒，晴空碧勝藍。獸形雲不一，弓勢月初三。", "雁思來天北，砧愁滿水南。蕭條秋氣味，未老已深諳。"]'),
('yuding-63','酬夢得秋夕不寐見寄','白居易','唐','御定全唐诗','yuding','','[]','碧簟絳紗帳，夜涼風景清。病聞和藥氣，渴聽碾茶聲。',48,'御定全唐詩/json/449.json','["碧簟絳紗帳，夜涼風景清。病聞和藥氣，渴聽碾茶聲。", "露竹偷燈影，煙松護月明。何言千里隔，秋思一時生。"]'),
('yuding-64','題周家歌者','白居易','唐','御定全唐诗','yuding','','[]','清緊如敲玉，深圓似轉簧。一聲腸一斷，能有幾多腸。',24,'御定全唐詩/json/449.json','["清緊如敲玉，深圓似轉簧。一聲腸一斷，能有幾多腸。"]'),
('yuding-65','憶夢得','白居易','唐','御定全唐诗','yuding','','[]','齒發各蹉跎，疏慵與病和。愛花心在否，見酒興如何。',48,'御定全唐詩/json/449.json','["齒發各蹉跎，疏慵與病和。愛花心在否，見酒興如何。", "年長風情少，官高俗慮多。幾時紅燭下，聞唱竹枝歌。"]'),
('yuding-66','贈同座','白居易','唐','御定全唐诗','yuding','','[]','春黛雙蛾嫩，秋蓬兩鬢侵。謀歡身太晚，恨老意彌深。',48,'御定全唐詩/json/449.json','["春黛雙蛾嫩，秋蓬兩鬢侵。謀歡身太晚，恨老意彌深。", "薄解燈前舞，尤能酒後吟。花叢便不入，猶自未甘心。"]'),
('yuding-67','失婢','白居易','唐','御定全唐诗','yuding','','[]','宅院小牆庳，坊門帖榜遲。舊恩慚自薄，前事悔難追。',48,'御定全唐詩/json/449.json','["宅院小牆庳，坊門帖榜遲。舊恩慚自薄，前事悔難追。", "籠鳥無常主，風花不戀枝。今宵在何處，唯有月明知。"]'),
('yuding-68','夜招晦叔','白居易','唐','御定全唐诗','yuding','','[]','庭草留霜池結冰，黃昏鐘絕凍雲凝。碧氈帳上正飄雪，',40,'御定全唐詩/json/449.json','["庭草留霜池結冰，黃昏鐘絕凍雲凝。碧氈帳上正飄雪，", "為君更奏湘神曲，夜就儂來能不能。"]'),
('yuding-69','戲答皇甫監','白居易','唐','御定全唐诗','yuding','','[]','寒宵勸酒君須飲，君是孤眠七十身。',32,'御定全唐詩/json/449.json','["寒宵勸酒君須飲，君是孤眠七十身。", "莫道非人身不暖，十分一醆暖於人。"]'),
('yuding-70','和楊師皋傷小姬英英','白居易','唐','御定全唐诗','yuding','','[]','自從嬌騃一相依，共見楊花七度飛。玳瑁床空收枕席，',40,'御定全唐詩/json/449.json','["自從嬌騃一相依，共見楊花七度飛。玳瑁床空收枕席，", "墳上少啼留取淚，明年寒食更沾衣。"]'),
('yuding-71','池邊即事','白居易','唐','御定全唐诗','yuding','','[]','氈帳胡琴出塞曲，蘭塘越棹弄潮聲。',32,'御定全唐詩/json/449.json','["氈帳胡琴出塞曲，蘭塘越棹弄潮聲。", "何言此處同風月，薊北江南萬里情。"]'),
('yuding-72','聞樂感鄰','白居易','唐','御定全唐诗','yuding','','[]','老去親朋零落盡，秋來弦管感傷多。尚書宅畔悲鄰笛，',40,'御定全唐詩/json/449.json','["老去親朋零落盡，秋來弦管感傷多。尚書宅畔悲鄰笛，", "歡娛未足身先去，爭奈書生薄命何。"]'),
('yuding-0','戊申歲暮詠懷三首','白居易','唐','御定全唐诗','yuding','','[]','窮冬月末兩三日，半百年過六七時。龍尾趁朝無氣力，',120,'御定全唐詩/json/450.json','["窮冬月末兩三日，半百年過六七時。龍尾趁朝無氣力，", "猶被妻兒教漸退，莫求致仕且分司。", "唯生一女才十二，只欠三年未六旬。婚嫁累輕何怕老，", "更擬踟躕覓何事，不歸嵩洛作閒人。", "七年囚閉作籠禽，但願開籠便入林。幸得展張今日翅，", "萬一差池似前事，又應追悔不抽簪。"]'),
('yuding-1','贈夢得','白居易','唐','御定全唐诗','yuding','','[]','心中萬事不思量，坐倚屏風臥向陽。漸覺詠詩猶老醜，',40,'御定全唐詩/json/450.json','["心中萬事不思量，坐倚屏風臥向陽。漸覺詠詩猶老醜，", "只有今春相伴在，花前剩醉兩三場。"]'),
('yuding-2','想東遊五十韻','白居易','唐','御定全唐诗','yuding','','[]','海內時無事，江南歲有秋。生民皆樂業，地主盡賢侯。',576,'御定全唐詩/json/450.json','["海內時無事，江南歲有秋。生民皆樂業，地主盡賢侯。", "郊靜銷戎馬，城高逼鬥牛。平河七百里，沃壤二三州。", "坐有湖山趣，行無風浪憂。食甯妨解纜，寢不廢乘流。", "泉石諳天竺，煙霞識虎丘。餘芳認蘭澤，遺詠思蘋洲。", "菡萏紅塗粉，菰蒲綠潑油。鱗差漁戶舍，綺錯稻田溝。", "紫洞藏仙窟，玄泉貯怪湫。精神昂老鶴，姿彩媚潛虯。", "靜閱天工妙，閑窺物狀幽。投竿出比目，擲果下獼猴。", "味苦蓮心小，漿甜蔗節稠。橘苞從自結，藕孔是誰鎪。", "逐日移潮信，隨風變棹謳。遞夫交烈火，候吏次鳴騶。", "梵塔形疑踴，閶門勢欲浮。客迎攜酒榼，僧待置茶甌。", "小宴閒談笑，初筵雅獻酬。稍催朱蠟炬，徐動碧牙籌。", "圓醆飛蓮子，長裾曳石榴。柘枝隨畫鼓，調笑從香球。", "幕颺雲飄檻，簾褰月露鉤。舞繁紅袖凝，歌切翠眉愁。", "弦管甯容歇，杯盤未許收。良辰宜酩酊，卒歲好優遊。", "鱠縷鮮仍細，蓴絲滑且柔。飽餐為日計，穩睡是身謀。", "名愧空虛得，官知止足休。自嫌猶屑屑，眾笑大悠悠。", "物表疏形役，人寰足悔尤。蛾須遠燈燭，兔勿近罝罘。", "幻世春來夢，浮生水上漚。百憂中莫入，一醉外何求。", "未死癡王湛，無兒老鄧攸。蜀琴安膝上，周易在床頭。", "去去無程客，行行不系舟。勞君頻問訊，勸我少淹留。", "雲雨多分散，關山苦阻修。一吟江月別，七見日星周。", "珠玉傳新什，鵷鸞念故儔。懸旌心宛轉，束楚意綢繆。", "驛舫妝青雀，官槽秣紫騮。鏡湖期遠泛，禹穴約冥搜。", "預掃題詩壁，先開望海樓。飲思親履舄，宿憶並衾裯。"]'),
('yuding-3','病免後喜除賓客','白居易','唐','御定全唐诗','yuding','','[]','臥在漳濱滿十旬，起為商皓伴三人。',32,'御定全唐詩/json/450.json','["臥在漳濱滿十旬，起為商皓伴三人。", "從今且莫嫌身病，不病何由索得身。"]'),
('yuding-4','長樂亭留別','白居易','唐','御定全唐诗','yuding','','[]','灞滻風煙函谷路，曾經幾度別長安。昔時蹙促為遷客，',40,'御定全唐詩/json/450.json','["灞滻風煙函谷路，曾經幾度別長安。昔時蹙促為遷客，", "塵纓世網重重縛，回顧方知出得難。"]'),
('yuding-5','陝府王大夫相迎偶贈','白居易','唐','御定全唐诗','yuding','','[]','紫微閣老自多情，白首園公豈要迎。伴我綠槐陰下歇，',40,'御定全唐詩/json/450.json','["紫微閣老自多情，白首園公豈要迎。伴我綠槐陰下歇，", "但問主人留幾日，分司賓客去無程。"]'),
('yuding-6','別陝州王司馬','白居易','唐','御定全唐诗','yuding','','[]','笙歌惆悵欲為別，風景闌珊初過春。',32,'御定全唐詩/json/450.json','["笙歌惆悵欲為別，風景闌珊初過春。", "爭得遣君詩不苦，黃河岸上白頭人。"]'),
('yuding-7','將至東都先寄令狐留守','白居易','唐','御定全唐诗','yuding','','[]','黃鳥無聲葉滿枝，閑吟想到洛城時。惜逢金穀三春盡，',40,'御定全唐詩/json/450.json','["黃鳥無聲葉滿枝，閑吟想到洛城時。惜逢金穀三春盡，", "東都添個狂賓客，先報壺觴風月知。"]'),
('yuding-8','答崔十八見寄','白居易','唐','御定全唐诗','yuding','','[]','明朝欲見琴尊伴，洗拭金杯拂玉徽。君乞曹州刺史替，',40,'御定全唐詩/json/450.json','["明朝欲見琴尊伴，洗拭金杯拂玉徽。君乞曹州刺史替，", "豈料洛陽風月夜，故人垂老得相依。"]'),
('yuding-9','贈皇甫賓客','白居易','唐','御定全唐诗','yuding','','[]','輕衣穩馬槐陰路，漸近東來漸少塵。耳鬧久憎聞俗事，',40,'御定全唐詩/json/450.json','["輕衣穩馬槐陰路，漸近東來漸少塵。耳鬧久憎聞俗事，", "始信淡交宜久遠，與君轉老轉相親。"]'),
('yuding-10','歸履道宅','白居易','唐','御定全唐诗','yuding','','[]','驛吏引藤輿，家童開竹扉。往時多暫住，今日是長歸。',48,'御定全唐詩/json/450.json','["驛吏引藤輿，家童開竹扉。往時多暫住，今日是長歸。", "眼下有衣食，耳邊無是非。不論貧與富，飲水亦應肥。"]'),
('yuding-11','問江南物','白居易','唐','御定全唐诗','yuding','','[]','歸來未及問生涯，先問江南物在耶。引手摩挲青石筍，',40,'御定全唐詩/json/450.json','["歸來未及問生涯，先問江南物在耶。引手摩挲青石筍，", "別有夜深惆悵事，月明雙鶴在裴家。"]'),
('yuding-12','蕭庶子相過','白居易','唐','御定全唐诗','yuding','','[]','半日停車馬，何人在白家。殷勤蕭庶子，愛酒不嫌茶。',24,'御定全唐詩/json/450.json','["半日停車馬，何人在白家。殷勤蕭庶子，愛酒不嫌茶。"]'),
('yuding-13','答尉遲少尹問所須','白居易','唐','御定全唐诗','yuding','','[]','乍到頻勞問所須，所須非玉亦非珠。',32,'御定全唐詩/json/450.json','["乍到頻勞問所須，所須非玉亦非珠。", "愛君水閣宜閑詠，每有詩成許去無。"]'),
('yuding-14','詠閑','白居易','唐','御定全唐诗','yuding','','[]','但有閑銷日，都無事系懷。朝眠因客起，午飯伴僧齋。',48,'御定全唐詩/json/450.json','["但有閑銷日，都無事系懷。朝眠因客起，午飯伴僧齋。", "樹合陰交戶，池分水夾階。就中今夜好，風月似江淮。"]'),
('yuding-15','同崔十八寄元浙東王陝州','白居易','唐','御定全唐诗','yuding','','[]','未能同隱雲林下，且複相招祿仕間。隨月有錢勝賣藥，',40,'御定全唐詩/json/450.json','["未能同隱雲林下，且複相招祿仕間。隨月有錢勝賣藥，", "惆悵八科殘四在，兩人榮鬧兩人閑。"]'),
('yuding-16','答蘇庶子月夜聞家僮奏樂見贈','白居易','唐','御定全唐诗','yuding','','[]','牆西明月水東亭，一曲霓裳按小伶。',32,'御定全唐詩/json/450.json','["牆西明月水東亭，一曲霓裳按小伶。", "不敢邀君無別意，弦生管澀未堪聽。"]'),
('yuding-17','偶吟','白居易','唐','御定全唐诗','yuding','','[]','裏巷多通水，林園盡不扃。松身為外戶，池面是中庭。',48,'御定全唐詩/json/450.json','["裏巷多通水，林園盡不扃。松身為外戶，池面是中庭。", "元氏詩三帙，陳家酒一瓶。醉來狂發詠，鄰女映籬聽。"]'),
('yuding-18','白蓮池泛舟','白居易','唐','御定全唐诗','yuding','','[]','白藕新花照水開，紅窗小舫信風回。',32,'御定全唐詩/json/450.json','["白藕新花照水開，紅窗小舫信風回。", "誰教一片江南興，逐我殷勤萬里來。"]'),
('yuding-19','池上即事','白居易','唐','御定全唐诗','yuding','','[]','行尋甃石引新泉，坐看修橋補釣船。綠竹掛衣涼處歇，',40,'御定全唐詩/json/450.json','["行尋甃石引新泉，坐看修橋補釣船。綠竹掛衣涼處歇，", "林下水邊無厭日，便堪終老豈論年。"]'),
('yuding-20','酬裴相公見寄二絕','白居易','唐','御定全唐诗','yuding','','[]','習靜心方泰，勞生事漸稀。可憐安穩地，舍此欲何歸。',48,'御定全唐詩/json/450.json','["習靜心方泰，勞生事漸稀。可憐安穩地，舍此欲何歸。", "一雙垂翅鶴，數首解嘲文。總是迂閑物，爭堪伴相君。"]'),
('yuding-21','答夢得聞蟬見寄','白居易','唐','御定全唐诗','yuding','','[]','開緘思浩然，獨詠晚風前。人貌非前日，蟬聲似去年。',48,'御定全唐詩/json/450.json','["開緘思浩然，獨詠晚風前。人貌非前日，蟬聲似去年。", "槐花新雨後，柳影欲秋天。聽罷無他計，相思又一篇。"]'),
('yuding-22','令狐尚書許過弊居先贈長句','白居易','唐','御定全唐诗','yuding','','[]','不矜軒冕愛林泉，許到池頭一醉眠。已遣平治行藥徑，',40,'御定全唐詩/json/450.json','["不矜軒冕愛林泉，許到池頭一醉眠。已遣平治行藥徑，", "只候高情無別物，蒼苔石筍白花蓮。"]'),
('yuding-23','自題','白居易','唐','御定全唐诗','yuding','','[]','老宜官冷靜，貧賴俸優饒。熱月無堆案，寒天不趁朝。',48,'御定全唐詩/json/450.json','["老宜官冷靜，貧賴俸優饒。熱月無堆案，寒天不趁朝。", "傍看應寂寞，自覺甚逍遙。徒對盈尊酒，兼無愁可銷。"]'),
('yuding-24','答崔十八','白居易','唐','御定全唐诗','yuding','','[]','勞將白叟比黃公，今古由來事不同。',32,'御定全唐詩/json/450.json','["勞將白叟比黃公，今古由來事不同。", "我有商山君未見，清泉白石在胸中。"]'),
('yuding-25','偶詠','白居易','唐','御定全唐诗','yuding','','[]','禦熱蕉衣健，扶羸竹杖輕。誦經憑檻立，散藥繞廊行。',48,'御定全唐詩/json/450.json','["禦熱蕉衣健，扶羸竹杖輕。誦經憑檻立，散藥繞廊行。", "暝槿無風落，秋蟲欲雨鳴。身閑當將息，病亦有心情。"]'),
('yuding-26','答蘇六','白居易','唐','御定全唐诗','yuding','','[]','但喜暑隨三伏去，不知秋送二毛來。',32,'御定全唐詩/json/450.json','["但喜暑隨三伏去，不知秋送二毛來。", "更無別計相寬慰，故遣陽關勸一杯。"]'),
('yuding-27','秋遊','白居易','唐','御定全唐诗','yuding','','[]','下馬閑行伊水頭，涼風清景勝春遊。',32,'御定全唐詩/json/450.json','["下馬閑行伊水頭，涼風清景勝春遊。", "何事古今詩句裏，不多說著洛陽秋。"]'),
('yuding-28','偶作','白居易','唐','御定全唐诗','yuding','','[]','張翰一杯酒，榮期三樂歌。聰明傷混沌，煩惱汙頭陀。',48,'御定全唐詩/json/450.json','["張翰一杯酒，榮期三樂歌。聰明傷混沌，煩惱汙頭陀。", "簟冷秋生早，階閑日上多。近來門更靜，無雀可張羅。"]'),
('yuding-29','游平原贈晦叔','白居易','唐','御定全唐诗','yuding','','[]','照水容雖老，登山力未衰。欲眠先命酒，暫歇亦吟詩。',48,'御定全唐詩/json/450.json','["照水容雖老，登山力未衰。欲眠先命酒，暫歇亦吟詩。", "且喜身無縛，終慚鬢有絲。回頭語閑伴，閑校十年遲。"]'),
('yuding-30','不出門','白居易','唐','御定全唐诗','yuding','','[]','不出門來又數旬，將何銷日與誰親。鶴籠開處見君子，',40,'御定全唐詩/json/450.json','["不出門來又數旬，將何銷日與誰親。鶴籠開處見君子，", "能行便是真修道，何必降魔調伏身。"]'),
('yuding-31','歎鶴病','白居易','唐','御定全唐诗','yuding','','[]','右翅低垂左脛傷，可憐風貌甚昂藏。',32,'御定全唐詩/json/450.json','["右翅低垂左脛傷，可憐風貌甚昂藏。", "亦知白日青天好，未要高飛且養瘡。"]'),
('yuding-32','臨都驛送崔十八','白居易','唐','御定全唐诗','yuding','','[]','勿言臨都五六裏，扶病出城相送來。莫道長安一步地，',24,'御定全唐詩/json/450.json','["勿言臨都五六裏，扶病出城相送來。莫道長安一步地，"]'),
('yuding-33','對鏡','白居易','唐','御定全唐诗','yuding','','[]','三分鬢髮二分絲，曉鏡秋容相對時。去作忙官應太老，',40,'御定全唐詩/json/450.json','["三分鬢髮二分絲，曉鏡秋容相對時。去作忙官應太老，", "若使至今黃綺在，聞吾此語亦分司。"]'),
('yuding-34','勸酒十四首：何處難忘酒七首','白居易','唐','御定全唐诗','yuding','','[]','何處難忘酒，長安喜氣新。初登高第後，乍作好官人。',336,'御定全唐詩/json/450.json','["何處難忘酒，長安喜氣新。初登高第後，乍作好官人。", "省壁明張榜，朝衣穩稱身。此時無一醆，爭奈帝城春。", "何處難忘酒，天涯話舊情。青雲俱不達，白髮遞相驚。", "二十年前別，三千里外行。此時無一醆，何以敘平生。", "何處難忘酒，朱門羨少年。春分花發後，寒食月明前。", "小院回羅綺，深房理管弦。此時無一醆，爭過豔陽天。", "何處難忘酒，霜庭老病翁。暗聲啼蟋蟀，幹葉落梧桐。", "鬢為愁先白，顏因醉暫紅。此時無一醆，何計奈秋風。", "何處難忘酒，軍功第一高。還鄉隨露布，半路授旌旄。", "玉柱剝蔥手，金章爛椹袍。此時無一醆，何以騁雄豪。", "何處難忘酒，青門送別多。斂襟收涕淚，簇馬聽笙歌。", "煙樹灞陵岸，風塵長樂坡。此時無一醆，爭奈去留何。", "何處難忘酒，逐臣歸故園。赦書逢驛騎，賀客出都門。", "半面瘴煙色，滿衫鄉淚痕。此時無一醆，何物可招魂。"]'),
('yuding-35','勸酒十四首：不如來飲酒七首','白居易','唐','御定全唐诗','yuding','','[]','莫隱深山去，君應到自嫌。齒傷朝水冷，貌苦夜霜嚴。',336,'御定全唐詩/json/450.json','["莫隱深山去，君應到自嫌。齒傷朝水冷，貌苦夜霜嚴。", "漁去風生浦，樵歸雪滿岩。不如來飲酒，相對醉厭厭。", "莫作農夫去，君應見自愁。迎春犁瘦地，趁晚喂羸牛。", "數被官加稅，稀逢歲有秋。不如來飲酒，酒伴醉悠悠。", "莫作商人去，恓惶君未諳。雪霜行塞北，風水宿江南。", "藏鏹百千萬，沉舟十二三。不如來飲酒，仰面醉酣酣。", "莫事長征去，辛勤難具論。何曾畫麟閣，只是老轅門。", "蟣虱衣中物，刀槍面上痕。不如來飲酒，合眼醉昏昏。", "莫學長生去，仙方誤殺君。那將薤上露，擬待鶴邊雲。", "矻矻皆燒藥，累累盡作墳。不如來飲酒，閑坐醉醺醺。", "莫上青雲去，青雲足愛憎。自賢誇智慧，相糾鬥功能。", "魚爛緣吞餌，蛾焦為撲燈。不如來飲酒，任性醉騰騰。", "莫入紅塵去，令人心力勞。相爭兩蝸角，所得一牛毛。", "且滅嗔中火，休磨笑裏刀。不如來飲酒，穩臥醉陶陶。"]'),
('yuding-36','和令狐相公寄劉郎中兼見示長句','白居易','唐','御定全唐诗','yuding','','[]','日月天衢仰面看，尚淹池鳳滯台鸞。碧幢千里空移鎮，',40,'御定全唐詩/json/450.json','["日月天衢仰面看，尚淹池鳳滯台鸞。碧幢千里空移鎮，", "酒軍詩敵如相遇，臨老猶能一據鞍。"]'),
('yuding-37','即事','白居易','唐','御定全唐诗','yuding','','[]','見月連宵坐，聞風盡日眠。室香羅藥氣，籠暖焙茶煙。',48,'御定全唐詩/json/450.json','["見月連宵坐，聞風盡日眠。室香羅藥氣，籠暖焙茶煙。", "鶴啄新晴地，雞棲薄暮天。自看淘酒米，倚杖小池前。"]'),
('yuding-38','期宿客不至','白居易','唐','御定全唐诗','yuding','','[]','風飄雨灑簾帷故，竹映松遮燈火深。',32,'御定全唐詩/json/450.json','["風飄雨灑簾帷故，竹映松遮燈火深。", "宿客不來嫌冷落，一尊酒對一張琴。"]'),
('yuding-39','問移竹','白居易','唐','御定全唐诗','yuding','','[]','問君移竹意如何，慎勿排行但間窠。',32,'御定全唐詩/json/450.json','["問君移竹意如何，慎勿排行但間窠。", "多種少栽皆有意，大都少校不如多。"]'),
('yuding-40','重陽席上賦白菊','白居易','唐','御定全唐诗','yuding','','[]','滿園花菊鬱金黃，中有孤叢色似霜。',32,'御定全唐詩/json/450.json','["滿園花菊鬱金黃，中有孤叢色似霜。", "還似今朝歌酒席，白頭翁入少年場。"]'),
('yuding-41','偶吟二首','白居易','唐','御定全唐诗','yuding','','[]','眼下有衣兼有食，心中無喜亦無憂。正如身後有何事，',80,'御定全唐詩/json/450.json','["眼下有衣兼有食，心中無喜亦無憂。正如身後有何事，", "猶殘少許雲泉興，一歲龍門數度遊。", "晴教曬藥泥茶灶，閑看科松洗竹林。活計縱貧長淨潔，", "老去生涯只如此，更無餘事可勞心。"]'),
('yuding-42','何處春先到','白居易','唐','御定全唐诗','yuding','','[]','何處春先到，橋東水北亭。凍花開未得，冷酒酌難醒。',48,'御定全唐詩/json/450.json','["何處春先到，橋東水北亭。凍花開未得，冷酒酌難醒。", "就日移輕榻，遮風展小屏。不勞人勸醉，鶯語漸丁寧。"]'),
('yuding-43','勉閒遊','白居易','唐','御定全唐诗','yuding','','[]','天時人事常多故，一歲春能幾處遊。不是塵埃便風雨，',40,'御定全唐詩/json/450.json','["天時人事常多故，一歲春能幾處遊。不是塵埃便風雨，", "唯有分司官恰好，閒遊雖老未能休。"]'),
('yuding-44','寄兩銀榼與裴侍郎，因題兩絕句','白居易','唐','御定全唐诗','yuding','','[]','貧無好物堪為信，雙榼雖輕意不輕。',64,'御定全唐詩/json/450.json','["貧無好物堪為信，雙榼雖輕意不輕。", "願奉謝公池上酌，丹心綠酒一時傾。", "慣和麹糵堪盛否，重用鹽梅試洗看。", "小器不知容幾許，襄陽米賤酒升寬。"]'),
('yuding-45','小橋柳','白居易','唐','御定全唐诗','yuding','','[]','細水涓涓似淚流，日西惆悵小橋頭。',32,'御定全唐詩/json/450.json','["細水涓涓似淚流，日西惆悵小橋頭。", "衰楊葉盡空枝在，猶被霜風吹不休。"]'),
('yuding-46','哭微之二首','白居易','唐','御定全唐诗','yuding','','[]','八月涼風吹白幕，寢門廊下哭微之。',64,'御定全唐詩/json/450.json','["八月涼風吹白幕，寢門廊下哭微之。", "妻孥朋友來相吊，唯道皇天無所知。", "文章卓犖生無敵，風骨英靈歿有神。", "哭送咸陽北原上，可能隨例作灰塵。"]'),
('yuding-47','馬上晚吟','白居易','唐','御定全唐诗','yuding','','[]','人少街荒已寂寥，風多塵起重蕭條。上陽落葉飄宮樹，',40,'御定全唐詩/json/450.json','["人少街荒已寂寥，風多塵起重蕭條。上陽落葉飄宮樹，", "如今不是閑行日，日短天陰坊曲遙。"]'),
('yuding-48','醉中重留夢得','白居易','唐','御定全唐诗','yuding','','[]','劉郎劉郎莫先起，蘇台蘇台隔雲水。',32,'御定全唐詩/json/450.json','["劉郎劉郎莫先起，蘇台蘇台隔雲水。", "酒醆來從一百分，馬頭去便三千里。"]'),
('yuding-49','雪夜喜李郎中見訪，兼酬所贈','白居易','唐','御定全唐诗','yuding','','[]','可憐今夜鵝毛雪，引得高情鶴氅人。紅蠟燭前明似晝，',40,'御定全唐詩/json/450.json','["可憐今夜鵝毛雪，引得高情鶴氅人。紅蠟燭前明似晝，", "對此欲留君便宿，詩情酒分合相親。"]'),
('yuding-50','任老','白居易','唐','御定全唐诗','yuding','','[]','不愁陌上春光盡，亦任庭前日影斜。',32,'御定全唐詩/json/450.json','["不愁陌上春光盡，亦任庭前日影斜。", "面黑眼昏頭雪白，老應無可更增加。"]'),
('yuding-51','勸歡','白居易','唐','御定全唐诗','yuding','','[]','火急歡娛慎勿遲，眼看老病悔難追。',32,'御定全唐詩/json/450.json','["火急歡娛慎勿遲，眼看老病悔難追。", "尊前花下歌筵裏，會有求來不得時。"]'),
('yuding-52','答王尚書問履道池舊橋','白居易','唐','御定全唐诗','yuding','','[]','虹梁雁齒隨年換，素板朱欄逐日修。但恨尚書能久別，',40,'御定全唐詩/json/450.json','["虹梁雁齒隨年換，素板朱欄逐日修。但恨尚書能久別，", "李郭小船何足問，待君乘過濟川舟。"]'),
('yuding-53','晚歸府','白居易','唐','御定全唐诗','yuding','','[]','晚從履道來歸府，街路雖長尹不嫌。',32,'御定全唐詩/json/450.json','["晚從履道來歸府，街路雖長尹不嫌。", "馬上涼於床上坐，綠槐風透紫蕉衫。"]'),
('yuding-54','從龍潭寺至少林寺，題贈同遊者','白居易','唐','御定全唐诗','yuding','','[]','山屐田衣六七賢，搴芳蹋翠弄潺湲。九龍潭月落杯酒，',40,'御定全唐詩/json/450.json','["山屐田衣六七賢，搴芳蹋翠弄潺湲。九龍潭月落杯酒，", "始知駕鶴乘雲外，別有逍遙地上仙。"]'),
('yuding-55','夜從法王寺下歸嶽寺','白居易','唐','御定全唐诗','yuding','','[]','雙刹夾虛空，緣雲一徑通。似從忉利下，如過劍門中。',48,'御定全唐詩/json/450.json','["雙刹夾虛空，緣雲一徑通。似從忉利下，如過劍門中。", "燈火光初合，笙歌曲未終。可憐獅子座，舁出淨名翁。"]'),
('yuding-56','宿龍潭寺','白居易','唐','御定全唐诗','yuding','','[]','夜上九潭誰是伴，雲隨飛蓋月隨杯。',32,'御定全唐詩/json/450.json','["夜上九潭誰是伴，雲隨飛蓋月隨杯。", "明年尚作三川守，此地兼將歌舞來。"]'),
('yuding-57','嵩陽觀夜奏霓裳','白居易','唐','御定全唐诗','yuding','','[]','開元遺曲自淒涼，況近秋天調是商。愛者誰人唯白尹，',40,'御定全唐詩/json/450.json','["開元遺曲自淒涼，況近秋天調是商。愛者誰人唯白尹，", "子晉少姨聞定怪，人間亦便有霓裳。"]'),
('yuding-58','過元家履信宅','白居易','唐','御定全唐诗','yuding','','[]','雞犬喪家分散後，林園失主寂寥時。落花不語空辭樹，',40,'御定全唐詩/json/450.json','["雞犬喪家分散後，林園失主寂寥時。落花不語空辭樹，", "前庭後院傷心事，唯是春風秋月知。"]'),
('yuding-59','和杜錄事題紅葉','白居易','唐','御定全唐诗','yuding','','[]','寒山十月旦，霜葉一時新。似燒非因火，如花不待春。',48,'御定全唐詩/json/450.json','["寒山十月旦，霜葉一時新。似燒非因火，如花不待春。", "連行排絳帳，亂落剪紅巾。解駐籃輿看，風前唯兩人。"]'),
('yuding-60','題崔常侍濟上別墅','白居易','唐','御定全唐诗','yuding','','[]','求榮爭寵任紛紛，脫葉金貂只有君。散員疏去未為貴，',40,'御定全唐詩/json/450.json','["求榮爭寵任紛紛，脫葉金貂只有君。散員疏去未為貴，", "主人憶爾爾知否，拋卻青雲歸白雲。"]'),
('yuding-61','過溫尚書舊莊','白居易','唐','御定全唐诗','yuding','','[]','白石清泉拋濟口，碧幢紅旆照河陽。',32,'御定全唐詩/json/450.json','["白石清泉拋濟口，碧幢紅旆照河陽。", "村人都不知時事，猶自呼為處士莊。"]'),
('yuding-62','天壇峰下贈杜錄事','白居易','唐','御定全唐诗','yuding','','[]','年顏氣力漸衰殘，王屋中峰欲上難。頂上將探小有洞，',40,'御定全唐詩/json/450.json','["年顏氣力漸衰殘，王屋中峰欲上難。頂上將探小有洞，", "他日藥成分一粒，與君先去掃天壇。"]'),
('yuding-63','贈僧五首：缽塔院如大師','白居易','唐','御定全唐诗','yuding','','[]','百千萬劫菩提種，八十三年功德林。若不秉持僧行苦，',40,'御定全唐詩/json/450.json','["百千萬劫菩提種，八十三年功德林。若不秉持僧行苦，", "每歲八關蒙九授，殷勤一戒重千金。"]'),
('yuding-64','贈僧五首：神照上人','白居易','唐','御定全唐诗','yuding','','[]','心如定水隨形應，口似懸河逐病治。',32,'御定全唐詩/json/450.json','["心如定水隨形應，口似懸河逐病治。", "曾向眾中先禮拜，西方去日莫相遺。"]'),
('yuding-65','贈僧五首：自遠禪師','白居易','唐','御定全唐诗','yuding','','[]','自出家來長自在，緣身一衲一繩床。',32,'御定全唐詩/json/450.json','["自出家來長自在，緣身一衲一繩床。", "令人見即心無事，每一相逢是道場。"]'),
('yuding-66','贈僧五首：宗實上人','白居易','唐','御定全唐诗','yuding','','[]','榮華恩愛棄成唾，戒定真如和作香。',32,'御定全唐詩/json/450.json','["榮華恩愛棄成唾，戒定真如和作香。", "今古雖殊同一法，瞿曇拋卻轉輪王。"]'),
('yuding-67','贈僧五首：清閒上人','白居易','唐','御定全唐诗','yuding','','[]','梓潼眷屬何年別，長壽壇場近日開。',32,'御定全唐詩/json/450.json','["梓潼眷屬何年別，長壽壇場近日開。", "應是蜀人皆度了，法輪移向洛中來。"]'),
('yuding-68','彈秋思','白居易','唐','御定全唐诗','yuding','','[]','信意閑彈秋思時，調清聲直韻疏遲。',32,'御定全唐詩/json/450.json','["信意閑彈秋思時，調清聲直韻疏遲。", "近來漸喜無人聽，琴格高低心自知。"]'),
('yuding-69','自詠','白居易','唐','御定全唐诗','yuding','','[]','隨宜飲食聊充腹，取次衣裘亦暖身。未必得年非瘦薄，',40,'御定全唐詩/json/450.json','["隨宜飲食聊充腹，取次衣裘亦暖身。未必得年非瘦薄，", "隨分自安心自斷，是非何用問閒人。"]'),
('yuding-70','分司初到洛中，偶題六韻，兼戲呈馮尹','白居易','唐','御定全唐诗','yuding','','[]','相府念多病，春宮容不才。官銜依口得，俸料逐身來。',72,'御定全唐詩/json/450.json','["相府念多病，春宮容不才。官銜依口得，俸料逐身來。", "白首林園在，紅塵車馬回。招呼新客侶，掃掠舊池台。", "小舫宜攜樂，新荷好蓋杯。不知金穀主，早晚賀筵開。"]'),
('yuding-71','春風','白居易','唐','御定全唐诗','yuding','','[]','春風先發苑中梅，櫻杏桃梨次第開。',32,'御定全唐詩/json/450.json','["春風先發苑中梅，櫻杏桃梨次第開。", "薺花榆莢深村裏，亦道春風為我來。"]'),
('yuding-0','洛陽春','白居易','唐','御定全唐诗','yuding','','[]','洛陽陌上春長在，惜別今來二十年。',32,'御定全唐詩/json/451.json','["洛陽陌上春長在，惜別今來二十年。", "唯覓少年心不得，其餘萬事盡依然。"]'),
('yuding-1','恨去年','白居易','唐','御定全唐诗','yuding','','[]','老去唯耽酒，春來不著家。去年來校晚，不見洛陽花。',24,'御定全唐詩/json/451.json','["老去唯耽酒，春來不著家。去年來校晚，不見洛陽花。"]'),
('yuding-2','早出晚歸','白居易','唐','御定全唐诗','yuding','','[]','早起或因攜酒出，晚歸多是看花回。',32,'御定全唐詩/json/451.json','["早起或因攜酒出，晚歸多是看花回。", "若拋風景長閑坐，自問東京作底來。"]'),
('yuding-3','魏王堤','白居易','唐','御定全唐诗','yuding','','[]','花寒懶發鳥慵啼，信馬閑行到日西。',32,'御定全唐詩/json/451.json','["花寒懶發鳥慵啼，信馬閑行到日西。", "何處未春先有思，柳條無力魏王堤。"]'),
('yuding-4','嘗黃醅新酎憶微之','白居易','唐','御定全唐诗','yuding','','[]','世間好物黃醅酒，天下閒人白侍郎。愛向卯時謀洽樂，',40,'御定全唐詩/json/451.json','["世間好物黃醅酒，天下閒人白侍郎。愛向卯時謀洽樂，", "元九計程殊未到，甕頭一醆共誰嘗。"]'),
('yuding-5','勸行樂','白居易','唐','御定全唐诗','yuding','','[]','少年信美何曾久，春日雖遲不再中。',32,'御定全唐詩/json/451.json','["少年信美何曾久，春日雖遲不再中。", "歡笑勝愁歌勝哭，請君莫道等頭空。"]'),
('yuding-6','老慵','白居易','唐','御定全唐诗','yuding','','[]','豈是交親向我疏，老慵自愛閉門居。',32,'御定全唐詩/json/451.json','["豈是交親向我疏，老慵自愛閉門居。", "近來漸喜知聞斷，免惱嵇康索報書。"]'),
('yuding-7','酬別微之','白居易','唐','御定全唐诗','yuding','','[]','灃頭峽口錢唐岸，三別都經二十年。且喜筋骸俱健在，',48,'御定全唐詩/json/451.json','["灃頭峽口錢唐岸，三別都經二十年。且喜筋骸俱健在，", "博望自來非棄置，承明重入莫拘牽。醉收杯杓停燈語，"]'),
('yuding-8','予與微之老而無子發於言歎著在詩篇今年冬各有一子戲作二什一以相賀一以自嘲','白居易','唐','御定全唐诗','yuding','','[]','常憂到老都無子，何況新生又是兒。陰德自然宜有慶，',80,'御定全唐詩/json/451.json','["常憂到老都無子，何況新生又是兒。陰德自然宜有慶，", "莫慮鵷雛無浴處，即應重入鳳凰池。", "五十八翁方有後，靜思堪喜亦堪嗟。一珠甚小還慚蚌，", "持杯祝願無他語，慎勿頑愚似汝爺。"]'),
('yuding-9','自問','白居易','唐','御定全唐诗','yuding','','[]','年來私自問，何故不歸京。佩玉腰無力，看花眼不明。',49,'御定全唐詩/json/451.json','["年來私自問，何故不歸京。佩玉腰無力，看花眼不明。", "老慵難發遣，春病易滋生。賴有彈琴女，時時聽一聲。主"]'),
('yuding-10','晚桃花','白居易','唐','御定全唐诗','yuding','','[]','一樹紅桃亞拂池，竹遮松蔭晚開時。非因斜日無由見，',41,'御定全唐詩/json/451.json','["一樹紅桃亞拂池，竹遮松蔭晚開時。非因斜日無由見，", "春深欲落誰憐惜，白侍郎來折一枝。主"]'),
('yuding-11','夜調琴憶崔少卿','白居易','唐','御定全唐诗','yuding','','[]','今夜調琴忽有情，欲彈惆悵憶崔卿。',32,'御定全唐詩/json/451.json','["今夜調琴忽有情，欲彈惆悵憶崔卿。", "何人解愛中徽上，秋思頭邊八九聲。"]'),
('yuding-12','阿崔','白居易','唐','御定全唐诗','yuding','','[]','謝病臥東都，羸然一老夫。孤單同伯道，遲暮過商瞿。',144,'御定全唐詩/json/451.json','["謝病臥東都，羸然一老夫。孤單同伯道，遲暮過商瞿。", "豈料鬢成雪，方看掌弄珠。已衰寧望有，雖晚亦勝無。", "蘭入前春夢，桑懸昨日弧。裏閭多慶賀，親戚共歡娛。", "膩剃新胎髮，香繃小繡襦。玉芽開手爪，酥顆點肌膚。", "弓冶將傳汝，琴書勿墜吾。未能知壽夭，何暇慮賢愚。", "乳氣初離殼，啼聲漸變雛。何時能反哺，供養白頭烏。"]'),
('yuding-13','贈鄰里往還','白居易','唐','御定全唐诗','yuding','','[]','問予何故獨安然，免被饑寒婚嫁牽。骨肉都盧無十口，',40,'御定全唐詩/json/451.json','["問予何故獨安然，免被饑寒婚嫁牽。骨肉都盧無十口，", "唯恐往還相厭賤，南家飲酒北家眠。"]'),
('yuding-14','王子晉廟','白居易','唐','御定全唐诗','yuding','','[]','子晉廟前山月明，人聞往往夜吹笙。',32,'御定全唐詩/json/451.json','["子晉廟前山月明，人聞往往夜吹笙。", "鸞吟鳳唱聽無拍，多似霓裳散序聲。"]'),
('yuding-15','晚起','白居易','唐','御定全唐诗','yuding','','[]','起晚憐春暖，歸遲愛月明。放慵長飽睡，聞健且閑行。',48,'御定全唐詩/json/451.json','["起晚憐春暖，歸遲愛月明。放慵長飽睡，聞健且閑行。", "北闕停朝簿，西方入社名。唯吟一句偈，無念是無生。"]'),
('yuding-16','酬皇甫賓客','白居易','唐','御定全唐诗','yuding','','[]','玄晏家風黃綺身，深居高臥養精神。性慵無病常稱病，',40,'御定全唐詩/json/451.json','["玄晏家風黃綺身，深居高臥養精神。性慵無病常稱病，", "自嫌詩酒猶多興，若比先生是俗人。"]'),
('yuding-17','池上贈韋山人','白居易','唐','御定全唐诗','yuding','','[]','新竹夾平流，新荷拂小舟。眾皆嫌好拙，誰肯伴閒遊。',48,'御定全唐詩/json/451.json','["新竹夾平流，新荷拂小舟。眾皆嫌好拙，誰肯伴閒遊。", "客為忙多去，僧因飯暫留。獨憐韋處士，盡日共悠悠。"]'),
('yuding-18','無夢','白居易','唐','御定全唐诗','yuding','','[]','老眼花前暗，春衣雨後寒。舊詩多忘卻，新酒且嘗看。',49,'御定全唐詩/json/451.json','["老眼花前暗，春衣雨後寒。舊詩多忘卻，新酒且嘗看。", "拙定於身穩，慵應趁伴難。漸銷名利想，無夢到長安。主"]'),
('yuding-19','對小潭寄遠上人','白居易','唐','御定全唐诗','yuding','','[]','小潭澄見底，閑客坐開襟。借問不流水，何如無念心。',48,'御定全唐詩/json/451.json','["小潭澄見底，閑客坐開襟。借問不流水，何如無念心。", "彼惟清且淺，此乃寂而深。是義誰能答，明朝問道林。"]'),
('yuding-20','閑吟二首','白居易','唐','御定全唐诗','yuding','','[]','留司老賓客，春盡興如何。官寺行香少，僧房寄宿多。',97,'御定全唐詩/json/451.json','["留司老賓客，春盡興如何。官寺行香少，僧房寄宿多。", "閑傾一醆酒，醉聽兩聲歌。憶得陶潛語，羲皇無以過。", "閒遊來早晚，已得一周年。嵩洛供雲水，朝廷乞俸錢。", "長歌時獨酌，飽食後安眠。聞道山榴發，明朝向玉泉。主"]'),
('yuding-21','獨遊玉泉寺','白居易','唐','御定全唐诗','yuding','','[]','雲樹玉泉寺，肩舁半日程。更無人作伴，只共酒同行。',48,'御定全唐詩/json/451.json','["雲樹玉泉寺，肩舁半日程。更無人作伴，只共酒同行。", "新葉千萬影，殘鶯三兩聲。閒遊竟未足，春盡有餘情。"]'),
('yuding-22','晚出尋人不遇','白居易','唐','御定全唐诗','yuding','','[]','籃輿不乘乘晚涼，相尋不遇亦無妨。',32,'御定全唐詩/json/451.json','["籃輿不乘乘晚涼，相尋不遇亦無妨。", "輕衣穩馬槐陰下，自要閑行一兩坊。"]'),
('yuding-23','苦熱','白居易','唐','御定全唐诗','yuding','','[]','頭痛汗盈巾，連宵複達晨。不堪逢苦熱，猶賴是閒人。',49,'御定全唐詩/json/451.json','["頭痛汗盈巾，連宵複達晨。不堪逢苦熱，猶賴是閒人。", "朝客應煩倦，農夫更苦辛。始慚當此日，得作自由身。主"]'),
('yuding-24','銷暑','白居易','唐','御定全唐诗','yuding','','[]','何以銷煩暑，端居一院中。眼前無長物，窗下有清風。',48,'御定全唐詩/json/451.json','["何以銷煩暑，端居一院中。眼前無長物，窗下有清風。", "熱散由心靜，涼生為室空。此時身自得，難更與人同。"]'),
('yuding-25','行香歸','白居易','唐','御定全唐诗','yuding','','[]','出作行香客，歸如坐夏僧。床前雙草屨，簷下一紗燈。',48,'御定全唐詩/json/451.json','["出作行香客，歸如坐夏僧。床前雙草屨，簷下一紗燈。", "佩委腰無力，冠欹發不勝。鸞台龍尾道，合盡少年登。"]'),
('yuding-26','同王十七庶子李六員外鄭二侍禦同年四人游龍門有感而作','白居易','唐','御定全唐诗','yuding','','[]','一曲悲歌酒一尊，同年零落幾人存。世如閱水應堪歎，',40,'御定全唐詩/json/451.json','["一曲悲歌酒一尊，同年零落幾人存。世如閱水應堪歎，", "今日與君重上處，龍門不是舊龍門。"]'),
('yuding-27','池上小宴問程秀才','白居易','唐','御定全唐诗','yuding','','[]','洛下林園好自知，江南景物暗相隨。淨淘紅粒罯香飯，',40,'御定全唐詩/json/451.json','["洛下林園好自知，江南景物暗相隨。淨淘紅粒罯香飯，", "停杯一問蘇州客，何似吳松江上時。"]'),
('yuding-28','橋亭卯飲','白居易','唐','御定全唐诗','yuding','','[]','卯時偶飲齋時臥，林下高橋橋上亭。松影過窗眠始覺，',40,'御定全唐詩/json/451.json','["卯時偶飲齋時臥，林下高橋橋上亭。松影過窗眠始覺，", "生計悠悠身兀兀，甘從妻喚作劉伶。"]'),
('yuding-29','舟中夜坐','白居易','唐','御定全唐诗','yuding','','[]','潭邊霽後多清景，橋下涼來足好風。',32,'御定全唐詩/json/451.json','["潭邊霽後多清景，橋下涼來足好風。", "秋鶴一雙船一隻，夜深相伴月明中。"]'),
('yuding-30','戲和微之答竇七行軍之作','白居易','唐','御定全唐诗','yuding','','[]','旌鉞從櫜鞬，賓僚禮數全。夔龍來要地，鵷鷺下遼天。',73,'御定全唐詩/json/451.json','["旌鉞從櫜鞬，賓僚禮數全。夔龍來要地，鵷鷺下遼天。", "赭汗騎驕馬，青娥舞醉仙。合成江上作，散到洛中傳。", "陋巷能無酒，貧池亦有船。春裝秋未寄，謾道有閒錢。主"]'),
('yuding-31','閑忙','白居易','唐','御定全唐诗','yuding','','[]','奔走朝行內，棲遲林墅間。多因病後退，少及健時還。',48,'御定全唐詩/json/451.json','["奔走朝行內，棲遲林墅間。多因病後退，少及健時還。", "斑白霜侵鬢，蒼黃日下山。閑忙俱過日，忙校不如閑。"]'),
('yuding-32','西風','白居易','唐','御定全唐诗','yuding','','[]','西風來幾日，一葉已先飛。新霽乘輕屐，初涼換熟衣。',48,'御定全唐詩/json/451.json','["西風來幾日，一葉已先飛。新霽乘輕屐，初涼換熟衣。", "淺渠銷慢水，疏竹漏斜暉。薄暮青苔巷，家僮引鶴歸。"]'),
('yuding-33','題西亭','白居易','唐','御定全唐诗','yuding','','[]','多見朱門富貴人，林園未畢即無身。',32,'御定全唐詩/json/451.json','["多見朱門富貴人，林園未畢即無身。", "我今幸作西亭主，已見池塘五度春。"]'),
('yuding-34','觀遊魚','白居易','唐','御定全唐诗','yuding','','[]','繞池閒步看魚游，正值兒童弄釣舟。',32,'御定全唐詩/json/451.json','["繞池閒步看魚游，正值兒童弄釣舟。", "一種愛魚心各異，我來施食爾垂鉤。"]'),
('yuding-35','看採蓮','白居易','唐','御定全唐诗','yuding','','[]','小桃閑上小蓮船，半采紅蓮半白蓮。',32,'御定全唐詩/json/451.json','["小桃閑上小蓮船，半采紅蓮半白蓮。", "不似江南惡風浪，芙蓉池在臥床前。"]'),
('yuding-36','看采菱','白居易','唐','御定全唐诗','yuding','','[]','菱池如鏡淨無波，白點花稀青角多。',32,'御定全唐詩/json/451.json','["菱池如鏡淨無波，白點花稀青角多。", "時唱一聲新水調，謾人道是采菱歌。"]'),
('yuding-37','夭老','白居易','唐','御定全唐诗','yuding','','[]','早世身如風裏燭，暮年發似鏡中絲。',32,'御定全唐詩/json/451.json','["早世身如風裏燭，暮年發似鏡中絲。", "誰人斷得人間事，少夭堪傷老又悲。"]'),
('yuding-38','秋池','白居易','唐','御定全唐诗','yuding','','[]','洗浪清風透水霜，水邊閑坐一繩床。',32,'御定全唐詩/json/451.json','["洗浪清風透水霜，水邊閑坐一繩床。", "眼塵心垢見皆盡，不是秋池是道場。"]'),
('yuding-39','登天宮閣','白居易','唐','御定全唐诗','yuding','','[]','午時乘興出，薄暮未能還。高上煙中閣，平看雪後山。',48,'御定全唐詩/json/451.json','["午時乘興出，薄暮未能還。高上煙中閣，平看雪後山。", "委形群動裏，任性一生間。洛下多閑客，其中我最閑。"]'),
('yuding-40','新雪二首','白居易','唐','御定全唐诗','yuding','','[]','不思北省煙霄地，不憶南宮風月天。',64,'御定全唐詩/json/451.json','["不思北省煙霄地，不憶南宮風月天。", "唯憶靜恭楊閣老，小園新雪暖爐前。", "不思朱雀街東鼓，不憶青龍寺後鐘。", "唯憶夜深新雪後，新昌臺上七株松。"]'),
('yuding-41','日高臥','白居易','唐','御定全唐诗','yuding','','[]','怕寒放懶日高臥，臨老誰言牽率身。夾幕繞房深似洞，',41,'御定全唐詩/json/451.json','["怕寒放懶日高臥，臨老誰言牽率身。夾幕繞房深似洞，", "未裹頭前傾一醆，何如沖雪趁朝人。主"]'),
('yuding-42','和微之任校書郎日過三鄉','白居易','唐','御定全唐诗','yuding','','[]','三鄉過日君年幾，今日君年五十餘。',32,'御定全唐詩/json/451.json','["三鄉過日君年幾，今日君年五十餘。", "不獨年催身亦變，校書郎變作尚書。"]'),
('yuding-43','和微之十七與君別及隴月花枝之詠','白居易','唐','御定全唐诗','yuding','','[]','別時十七今頭白，惱亂君心三十年。',32,'御定全唐詩/json/451.json','["別時十七今頭白，惱亂君心三十年。", "垂老休吟花月句，恐君更結後身緣。"]'),
('yuding-44','和微之歎槿花','白居易','唐','御定全唐诗','yuding','','[]','朝榮殊可惜，暮落實堪嗟。若向花中比，猶應勝眼花。',24,'御定全唐詩/json/451.json','["朝榮殊可惜，暮落實堪嗟。若向花中比，猶應勝眼花。"]'),
('yuding-45','思往喜今','白居易','唐','御定全唐诗','yuding','','[]','憶除司馬向江州，及此凡經十五秋。雖在簪裾從俗累，',40,'御定全唐詩/json/451.json','["憶除司馬向江州，及此凡經十五秋。雖在簪裾從俗累，", "爭似如今作賓客，都無一念到心頭。"]'),
('yuding-46','題平泉薛家雪堆莊','白居易','唐','御定全唐诗','yuding','','[]','怪石千年應自結，靈泉一帶是誰開。蹙為宛轉青蛇項，',40,'御定全唐詩/json/451.json','["怪石千年應自結，靈泉一帶是誰開。蹙為宛轉青蛇項，", "所嗟地去都門遠，不得肩舁每日來。"]'),
('yuding-47','和微之道保生三日','白居易','唐','御定全唐诗','yuding','','[]','相看鬢似絲，始作弄璋詩。且有承家望，誰論得力時。',72,'御定全唐詩/json/451.json','["相看鬢似絲，始作弄璋詩。且有承家望，誰論得力時。", "莫興三日歎，猶勝七年遲。我未能忘喜，君應不合悲。", "嘉名稱道保，乞姓號崔兒。但恐持相並，蒹葭瓊樹枝。"]'),
('yuding-48','哭皇甫七郎中','白居易','唐','御定全唐诗','yuding','','[]','志業過玄晏，詞華似禰衡。多才非福祿，薄命是聰明。',48,'御定全唐詩/json/451.json','["志業過玄晏，詞華似禰衡。多才非福祿，薄命是聰明。", "不得人間壽，還留身後名。涉江文一首，便可敵公卿。"]'),
('yuding-49','晚起','白居易','唐','御定全唐诗','yuding','','[]','爛熳朝眠後，頻伸晚起時。暖爐生火早，寒鏡裹頭遲。',72,'御定全唐詩/json/451.json','["爛熳朝眠後，頻伸晚起時。暖爐生火早，寒鏡裹頭遲。", "融雪煎香茗，調酥煮乳糜。慵饞還自哂，快活亦誰知。", "酒性溫無毒，琴聲淡不悲。榮公三樂外，仍弄小男兒。"]'),
('yuding-50','疑夢二首','白居易','唐','御定全唐诗','yuding','','[]','莫驚寵辱虛憂喜，莫計恩讎浪苦辛。',64,'御定全唐詩/json/451.json','["莫驚寵辱虛憂喜，莫計恩讎浪苦辛。", "黃帝孔丘無處問，安知不是夢中身。", "鹿疑鄭相終難辨，蝶化莊生詎可知。", "假使如今不是夢，能長於夢幾多時。"]'),
('yuding-51','夜宴惜別','白居易','唐','御定全唐诗','yuding','','[]','笙歌旖旎曲終頭，轉作離聲滿坐愁。箏怨朱弦從此斷，',41,'御定全唐詩/json/451.json','["笙歌旖旎曲終頭，轉作離聲滿坐愁。箏怨朱弦從此斷，", "何況雞鳴即須別，門前風雨冷修修。主"]'),
('yuding-52','歸來二周歲','白居易','唐','御定全唐诗','yuding','','[]','歸來二周歲，二歲似須臾。池藕重生葉，林鴉再引雛。',48,'御定全唐詩/json/451.json','["歸來二周歲，二歲似須臾。池藕重生葉，林鴉再引雛。", "時豐實倉廩，春暖葺庖廚。更作三年計，三年身健無。"]'),
('yuding-53','吾土','白居易','唐','御定全唐诗','yuding','','[]','身心安處為吾土，豈限長安與洛陽。水竹花前謀活計，',40,'御定全唐詩/json/451.json','["身心安處為吾土，豈限長安與洛陽。水竹花前謀活計，", "不用將金買莊宅，城東無主是春光。"]'),
('yuding-54','題岐王舊山池石壁','白居易','唐','御定全唐诗','yuding','','[]','樹深藤老竹回環，石壁重重錦翠斑。俗客看來猶解愛，',40,'御定全唐詩/json/451.json','["樹深藤老竹回環，石壁重重錦翠斑。俗客看來猶解愛，", "黃綺更歸何處去，洛陽城內有商山。"]'),
('yuding-55','病眼花','白居易','唐','御定全唐诗','yuding','','[]','頭風目眩乘衰老，只有增加豈有瘳。花發眼中猶足怪，',40,'御定全唐詩/json/451.json','["頭風目眩乘衰老，只有增加豈有瘳。花發眼中猶足怪，", "必若不能分黑白，卻應無悔複無尤。"]'),
('yuding-56','早飲醉中除河南尹敕到','白居易','唐','御定全唐诗','yuding','','[]','雪擁衡門水滿池，溫爐卯後暖寒時。綠醅新酎嘗初醉，',40,'御定全唐詩/json/451.json','["雪擁衡門水滿池，溫爐卯後暖寒時。綠醅新酎嘗初醉，", "應須了卻丘中計，女嫁男婚三徑資。"]'),
('yuding-57','除夜','白居易','唐','御定全唐诗','yuding','','[]','病眼少眠非守歲，老心多感又臨春。',32,'御定全唐詩/json/451.json','["病眼少眠非守歲，老心多感又臨春。", "火銷燈盡天明後，便是平頭六十人。"]'),
('yuding-58','府西池','白居易','唐','御定全唐诗','yuding','','[]','柳無氣力枝先動，池有波紋冰盡開。',32,'御定全唐詩/json/451.json','["柳無氣力枝先動，池有波紋冰盡開。", "今日不知誰計會，春風春水一時來。"]'),
('yuding-59','天津橋','白居易','唐','御定全唐诗','yuding','','[]','津橋東北斗亭西，到此令人詩思迷。眉月晚生神女浦，',40,'御定全唐詩/json/451.json','["津橋東北斗亭西，到此令人詩思迷。眉月晚生神女浦，", "報導前驅少呼喝，恐驚黃鳥不成啼。"]'),
('yuding-60','不准擬二首','白居易','唐','御定全唐诗','yuding','','[]','籃輿騰騰一老夫，褐裘烏帽白髭須。早衰饒病多蔬食，',48,'御定全唐詩/json/451.json','["籃輿騰騰一老夫，褐裘烏帽白髭須。早衰饒病多蔬食，", "憶昔謫居炎瘴地，巴猿引哭虎隨行。多於賈誼長沙苦，"]'),
('yuding-61','府中夜賞','白居易','唐','御定全唐诗','yuding','','[]','櫻桃廳院春偏好，石井欄堂夜更幽。白粉牆頭花半出，',41,'御定全唐詩/json/451.json','["櫻桃廳院春偏好，石井欄堂夜更幽。白粉牆頭花半出，", "舞袖飄颻棹容與，忽疑身是夢中游。主"]'),
('yuding-62','府西池北新葺水齋，即事招賓，偶題十六韻','白居易','唐','御定全唐诗','yuding','','[]','繚繞府西面，潺湲池北頭。鑿開明月峽，決破白蘋洲。',192,'御定全唐詩/json/451.json','["繚繞府西面，潺湲池北頭。鑿開明月峽，決破白蘋洲。", "清淺漪瀾急，夤緣浦嶼幽。直沖行徑斷，平入臥齋流。", "石疊青棱玉，波翻白片鷗。噴時千點雨，澄處一泓油。", "絕境應難別，同心豈易求。少逢人愛玩，多是我淹留。", "夾岸鋪長簟，當軒泊小舟。枕前看鶴浴，床下見魚遊。", "洞戶斜開扇，疏簾半上鉤。紫浮萍泛泛，碧亞竹修修。", "讀罷書仍展，棋終局未收。午茶能散睡，卯酒善銷愁。", "簷雨晚初霽，窗風涼欲休。誰能伴老尹，時複一閒遊。"]'),
('yuding-63','哭崔兒','白居易','唐','御定全唐诗','yuding','','[]','掌珠一顆兒三歲，鬢雪千莖父六旬。豈料汝先為異物，',40,'御定全唐詩/json/451.json','["掌珠一顆兒三歲，鬢雪千莖父六旬。豈料汝先為異物，", "懷抱又空天默默，依前重作鄧攸身。"]'),
('yuding-64','初喪崔兒報微之晦叔','白居易','唐','御定全唐诗','yuding','','[]','書報微之晦叔知，欲題崔字淚先垂。世間此恨偏敦我，',40,'御定全唐詩/json/451.json','["書報微之晦叔知，欲題崔字淚先垂。世間此恨偏敦我，", "文章十帙官三品，身後傳誰庇蔭誰。"]'),
('yuding-65','府齋感懷酬夢得','白居易','唐','御定全唐诗','yuding','','[]','府伶呼喚爭先到，家醞提攜動輒隨。合是人生開眼日，',40,'御定全唐詩/json/451.json','["府伶呼喚爭先到，家醞提攜動輒隨。合是人生開眼日，", "勞寄新詩遠安慰，不聞枯樹再生枝。"]'),
('yuding-66','齋居','白居易','唐','御定全唐诗','yuding','','[]','香火多相對，葷腥久不嘗。黃耆數匙粥，赤箭一甌湯。',49,'御定全唐詩/json/451.json','["香火多相對，葷腥久不嘗。黃耆數匙粥，赤箭一甌湯。", "厚俸將何用，閒居不可忘。明年官滿後，擬買雪堆莊。主"]'),
('yuding-67','與諸道者同遊二室至九龍潭作','白居易','唐','御定全唐诗','yuding','','[]','喜逢二室游仙子，厭作三川守土臣。舉手摩挲潭上石，',41,'御定全唐詩/json/451.json','["喜逢二室游仙子，厭作三川守土臣。舉手摩挲潭上石，", "若言尹是嵩山主，三十六峰應笑人。主"]'),
('yuding-68','履道池上作','白居易','唐','御定全唐诗','yuding','','[]','家池動作經旬別，松竹琴魚好在無。樹暗小巢藏巧婦，',41,'御定全唐詩/json/451.json','["家池動作經旬別，松竹琴魚好在無。樹暗小巢藏巧婦，", "猶喜春深公事少，每來花下得踟躕。主"]'),
('yuding-69','六十拜河南尹','白居易','唐','御定全唐诗','yuding','','[]','六十河南尹，前途足可知。老應無處避，病不與人期。',73,'御定全唐詩/json/451.json','["六十河南尹，前途足可知。老應無處避，病不與人期。", "幸遇芳菲日，猶當強健時。萬金何假藉，一醆莫推辭。", "流水光陰急，浮雲富貴遲。人間若無酒，盡合鬢成絲。主"]'),
('yuding-70','重修府西水亭院','白居易','唐','御定全唐诗','yuding','','[]','因下疏為沼，隨高築作台。龍門分水入，金穀取花栽。',48,'御定全唐詩/json/451.json','["因下疏為沼，隨高築作台。龍門分水入，金穀取花栽。", "繞岸行初匝，憑軒立未回。園西有池位，留與後人開。"]'),
('yuding-71','與諸公同出城觀稼','白居易','唐','御定全唐诗','yuding','','[]','老尹醉醺醺，來隨年少群。不憂頭似雪，但喜稼如雲。',48,'御定全唐詩/json/451.json','["老尹醉醺醺，來隨年少群。不憂頭似雪，但喜稼如雲。", "歲望千箱積，秋憐五穀分。何人知帝力，堯舜正為君。"]'),
('yuding-72','水堂醉臥問杜三十一','白居易','唐','御定全唐诗','yuding','','[]','聞君洛下住多年，何處春流最可憐。為問魏王堤岸下，',40,'御定全唐詩/json/451.json','["聞君洛下住多年，何處春流最可憐。為問魏王堤岸下，", "那似此堂簾幕底，連明連夜碧潺湲。"]'),
('yuding-73','歲暮言懷','白居易','唐','御定全唐诗','yuding','','[]','職與才相背，心將口自言。磨鉛教切玉，驅鶴遣乘軒。',48,'御定全唐詩/json/451.json','["職與才相背，心將口自言。磨鉛教切玉，驅鶴遣乘軒。", "只合居岩窟，何因入府門。年終若無替，轉恐負君恩。"]'),
('yuding-74','座中戲呈諸少年','白居易','唐','御定全唐诗','yuding','','[]','衰容禁得無多酒，秋鬢新添幾許霜。縱有風情應淡薄，',40,'御定全唐詩/json/451.json','["衰容禁得無多酒，秋鬢新添幾許霜。縱有風情應淡薄，", "不為倚官兼挾勢，因何入得少年場。"]'),
('yuding-75','雪後早過天津橋偶呈諸客','白居易','唐','御定全唐诗','yuding','','[]','官橋晴雪曉峨峨，老尹行吟獨一過。紫綬相輝應不惡，',41,'御定全唐詩/json/451.json','["官橋晴雪曉峨峨，老尹行吟獨一過。紫綬相輝應不惡，", "猶賴洛中饒醉客，時時bZ我喚笙歌。"]'),
('yuding-76','新制綾襖成，感而有詠','白居易','唐','御定全唐诗','yuding','','[]','水波文襖造新成，綾軟綿勻溫複輕。晨興好擁向陽坐，',64,'御定全唐詩/json/451.json','["水波文襖造新成，綾軟綿勻溫複輕。晨興好擁向陽坐，", "宴安往往歡侵夜，臥穩昏昏睡到明。百姓多寒無可救，", "爭得大裘長萬丈，與君都蓋洛陽城。"]'),
('yuding-77','早春雪後贈洛陽李長官長水鄭明府二同年','白居易','唐','御定全唐诗','yuding','','[]','獻歲晴和風景新，銅駝街郭暖無塵。府庭共賀三川雪，',40,'御定全唐詩/json/451.json','["獻歲晴和風景新，銅駝街郭暖無塵。府庭共賀三川雪，", "有何功德紆金紫，若比同年是幸人。"]'),
('yuding-78','醉吟','白居易','唐','御定全唐诗','yuding','','[]','醉來忘渴複忘饑，冠帶形骸杳若遺。耳底齋鐘初過後，',40,'御定全唐詩/json/451.json','["醉來忘渴複忘饑，冠帶形骸杳若遺。耳底齋鐘初過後，", "應被眾疑公事慢，承前府尹不吟詩。"]'),
('yuding-79','府酒五絕：變法','白居易','唐','御定全唐诗','yuding','','[]','自慚到府來周歲，惠愛威棱一事無。',32,'御定全唐詩/json/451.json','["自慚到府來周歲，惠愛威棱一事無。", "唯是改張官酒法，漸從濁水作醍醐。"]'),
('yuding-80','府酒五絕：招客','白居易','唐','御定全唐诗','yuding','','[]','日午微風且暮寒，春風冷峭雪幹殘。',32,'御定全唐詩/json/451.json','["日午微風且暮寒，春風冷峭雪幹殘。", "碧氈帳下紅爐畔，試為來嘗一醆看。"]'),
('yuding-81','府酒五絕：辨味','白居易','唐','御定全唐诗','yuding','','[]','甘露太甜非正味，醴泉雖潔不芳馨。',32,'御定全唐詩/json/451.json','["甘露太甜非正味，醴泉雖潔不芳馨。", "杯中此物何人別，柔旨之中有典刑。"]'),
('yuding-82','府酒五絕：自勸','白居易','唐','御定全唐诗','yuding','','[]','憶昔羈貧應舉年，脫衣典酒麴江邊。',32,'御定全唐詩/json/451.json','["憶昔羈貧應舉年，脫衣典酒麴江邊。", "十千一鬥猶賒飲，何況官供不著錢。"]'),
('yuding-83','府酒五絕：諭妓','白居易','唐','御定全唐诗','yuding','','[]','燭淚夜粘桃葉袖，酒痕春汙石榴裙。',32,'御定全唐詩/json/451.json','["燭淚夜粘桃葉袖，酒痕春汙石榴裙。", "莫辭辛苦供歡宴，老後思量悔煞君。"]'),
('yuding-84','晚歸早出','白居易','唐','御定全唐诗','yuding','','[]','筋力年年減，風光日日新。退衙歸逼夜，拜表出侵晨。',72,'御定全唐詩/json/451.json','["筋力年年減，風光日日新。退衙歸逼夜，拜表出侵晨。", "何處台無月，誰家池不春。莫言無勝地，自是少閒人。", "坐厭推囚案，行嫌引馬塵。幾時辭府印，卻作自由身。"]'),
('yuding-85','南龍興寺殘雪','白居易','唐','御定全唐诗','yuding','','[]','南龍興寺春晴後，緩步徐吟繞四廊。老趁風花應不稱，',40,'御定全唐詩/json/451.json','["南龍興寺春晴後，緩步徐吟繞四廊。老趁風花應不稱，", "不擬人間更求事，些些疏懶亦何妨。"]'),
('yuding-86','天宮閣早春','白居易','唐','御定全唐诗','yuding','','[]','天宮高閣上何頻，每上令人耳目新。前日晚登緣看雪，',40,'御定全唐詩/json/451.json','["天宮高閣上何頻，每上令人耳目新。前日晚登緣看雪，", "可惜三川虛作主，風光不屬白頭人。"]'),
('yuding-87','履道居三首','白居易','唐','御定全唐诗','yuding','','[]','莫嫌地窄林亭小，莫厭貧家活計微。',96,'御定全唐詩/json/451.json','["莫嫌地窄林亭小，莫厭貧家活計微。", "大有高門鎖寬宅，主人到老不曾歸。", "東裏素帷猶未徹，南鄰丹旐又新懸。", "衡門蝸舍自慚愧，收得身來已五年。", "世事平分眾所知，何嘗苦樂不相隨。", "唯餘耽酒狂歌客，只有樂時無苦時。"]'),
('yuding-88','和夢得冬日晨興','白居易','唐','御定全唐诗','yuding','','[]','漏傳初五點，雞報第三聲。帳下從容起，窗間曨昒明。',49,'御定全唐詩/json/451.json','["漏傳初五點，雞報第三聲。帳下從容起，窗間曨昒明。", "照書燈未滅，暖酒火重生。理曲弦歌動，先聞唱渭城。主"]'),
('yuding-89','雪夜對酒招客','白居易','唐','御定全唐诗','yuding','','[]','帳小青氈暖，杯香綠蟻新。醉憐今夜月，歡憶去年人。',48,'御定全唐詩/json/451.json','["帳小青氈暖，杯香綠蟻新。醉憐今夜月，歡憶去年人。", "暗落燈花燼，閑生草座塵。殷勤報弦管，明日有嘉賓。"]'),
('yuding-90','贈晦叔憶夢得','白居易','唐','御定全唐诗','yuding','','[]','自別崔公四五秋，因何臨老轉風流。歸來不說秦中事，',40,'御定全唐詩/json/451.json','["自別崔公四五秋，因何臨老轉風流。歸來不說秦中事，", "得君更有無厭意，猶恨尊前欠老劉。"]'),
('yuding-91','醉後重贈晦叔','白居易','唐','御定全唐诗','yuding','','[]','老伴知君少，歡情向我偏。無論疏與數，相見輒欣然。',72,'御定全唐詩/json/451.json','["老伴知君少，歡情向我偏。無論疏與數，相見輒欣然。", "各以詩成癖，俱因酒得仙。笑回青眼語，醉並白頭眠。", "豈是今投分，多疑宿結緣。人間更何事，攜手送衰年。"]'),
('yuding-92','睡覺','白居易','唐','御定全唐诗','yuding','','[]','星河耿耿漏綿綿，月暗燈微欲曙天。轉枕頻伸書帳下，',40,'御定全唐詩/json/451.json','["星河耿耿漏綿綿，月暗燈微欲曙天。轉枕頻伸書帳下，", "五欲已銷諸念息，世間無境可勾牽。"]'),
('yuding-0','詠興五首：解印出公府','白居易','唐','御定全唐诗','yuding','','[]','解印出公府，鬥藪塵土衣。百吏放爾散，雙鶴隨我歸。',108,'御定全唐詩/json/452.json','["解印出公府，鬥藪塵土衣。百吏放爾散，雙鶴隨我歸。", "歸來履道宅，下馬入柴扉。馬嘶返舊櫪，鶴舞還故池。", "雞犬何忻忻，鄰里亦依依。年顏老去日，生計勝前時。", "有帛禦冬寒，有穀防歲饑。飽于東方朔，樂於榮啟期。", "人生且如此，此外吾不知。"]'),
('yuding-1','詠興五首：出府歸吾廬','白居易','唐','御定全唐诗','yuding','','[]','出府歸吾廬，靜然安且逸。更無客幹謁，時有僧問疾。',144,'御定全唐詩/json/452.json','["出府歸吾廬，靜然安且逸。更無客幹謁，時有僧問疾。", "家僮十餘人，櫪馬三四匹。慵發經旬臥，興來連日出。", "出遊愛何處，嵩碧伊瑟瑟。況有清和天，正當疏散日。", "身閑自為貴，何必居榮秩。心足即非貧，豈唯金滿室。", "吾觀權勢者，苦以身徇物。炙手外炎炎，履冰中栗栗。", "朝饑口忘味，夕惕心憂失。但有富貴名，而無富貴實。"]'),
('yuding-2','詠興五首：池上有小舟','白居易','唐','御定全唐诗','yuding','','[]','池上有小舟，舟中有胡床。床前有新酒，獨酌還獨嘗。',132,'御定全唐詩/json/452.json','["池上有小舟，舟中有胡床。床前有新酒，獨酌還獨嘗。", "熏若春日氣，皎如秋水光。可洗機巧心，可蕩塵垢腸。", "岸曲舟行遲，一曲進一觴。未知幾曲醉，醉入無何鄉。", "寅緣潭島間，水竹深青蒼。身閒心無事，白日為我長。", "我若未忘世，雖閒心亦忙。世若未忘我，雖退身難藏。", "我今異於是，身世交相忘。"]'),
('yuding-3','詠興五首：四月池水滿','白居易','唐','御定全唐诗','yuding','','[]','四月池水滿，龜遊魚躍出。吾亦愛吾池，池邊開一室。',96,'御定全唐詩/json/452.json','["四月池水滿，龜遊魚躍出。吾亦愛吾池，池邊開一室。", "人魚雖異族，其樂歸於一。且與爾為徒，逍遙同過日。", "爾無羨滄海，蒲藻可委質。吾亦忘青雲，衡茅足容膝。", "況吾與爾輩，本非蛟龍匹。假如雲雨來，只是池中物。"]'),
('yuding-4','詠興五首：小庭亦有月','白居易','唐','御定全唐诗','yuding','','[]','小庭亦有月，小院亦有花。可憐好風景，不解嫌貧家。',168,'御定全唐詩/json/452.json','["小庭亦有月，小院亦有花。可憐好風景，不解嫌貧家。", "菱角執笙簧，谷兒抹琵琶。紅綃信手舞，紫綃隨意歌。", "村歌與社舞，客哂主人誇。但問樂不樂，豈在鐘鼓多。", "客告暮將歸，主稱日未斜。請客稍深酌，願見朱顏酡。", "客知主意厚，分數隨口加。堂上燭未秉，座中冠已峨。", "左顧短紅袖，右命小青娥。長跪謝貴客，蓬門勞見過。", "客散有餘興，醉臥獨吟哦。幕天而席地，誰奈劉伶何。"]'),
('yuding-5','秋涼閑臥','白居易','唐','御定全唐诗','yuding','','[]','殘暑晝猶長，早涼秋尚嫩。露荷散清香，風竹含疏韻。',48,'御定全唐詩/json/452.json','["殘暑晝猶長，早涼秋尚嫩。露荷散清香，風竹含疏韻。", "幽閒竟日臥，衰病無人問。薄暮宅門前，槐花深一寸。"]'),
('yuding-6','酬思黯相公見過弊居戲贈','白居易','唐','御定全唐诗','yuding','','[]','軒蓋光照地，行人為裴回。呼傳君子出，乃是故人來。',120,'御定全唐詩/json/452.json','["軒蓋光照地，行人為裴回。呼傳君子出，乃是故人來。", "訪我入窮巷，引君登小台。台前多竹樹，池上無塵埃。", "貧家何所有，新酒三兩杯。停杯款曲語，上馬複遲回。", "留守不外宿，日斜宮漏催。但留金刀贈，未接玉山頹。", "家醞不敢惜，待君來即開。村妓不辭出，恐君囅然咍。"]'),
('yuding-7','再授賓客分司','白居易','唐','御定全唐诗','yuding','','[]','優穩四皓官，清崇三品列。伊予再塵忝，內愧非才哲。',144,'御定全唐詩/json/452.json','["優穩四皓官，清崇三品列。伊予再塵忝，內愧非才哲。", "俸錢七八萬，給受無虛月。分命在東司，又不勞朝謁。", "既資閑養疾，亦賴慵藏拙。賓友得從容，琴觴恣怡悅。", "乘籃城外去，系馬花前歇。六游金穀春，五看龍門雪。", "吾若默無語，安知吾快活。吾欲更盡言，複恐人豪奪。", "應為時所笑，苦惜分司闕。但問適意無，豈論官冷熱。"]'),
('yuding-8','把酒','白居易','唐','御定全唐诗','yuding','','[]','把酒仰問天，古今誰不死。所貴未死間，少憂多歡喜。',144,'御定全唐詩/json/452.json','["把酒仰問天，古今誰不死。所貴未死間，少憂多歡喜。", "窮通諒在天，憂喜即由己。是故達道人，去彼而取此。", "勿言未富貴，久忝居祿仕。借問宗族間，幾人拖金紫。", "勿憂漸衰老，且喜加年紀。試數班行中，幾人及暮齒。", "朝餐不過飽，五鼎徒為爾。夕寢止求安，一衾而已矣。", "此外皆長物，於我雲相似。有子不留金，何況兼無子。"]'),
('yuding-9','首夏','白居易','唐','御定全唐诗','yuding','','[]','林靜蚊未生，池靜蛙未鳴。景長天氣好，竟日和且清。',120,'御定全唐詩/json/452.json','["林靜蚊未生，池靜蛙未鳴。景長天氣好，竟日和且清。", "春禽餘哢在，夏木新陰成。兀爾水邊坐，翛然橋上行。", "自問一何適，身閑官不輕。料錢隨月用，生計逐日營。", "食飽慚伯夷，酒足愧淵明。壽倍顏氏子，富百黔婁生。", "有一即為樂，況吾四者並。所以私自慰，雖老有心情。"]'),
('yuding-10','代鶴','白居易','唐','御定全唐诗','yuding','','[]','我本海上鶴，偶逢江南客。感君一顧恩，同來洛陽陌。',96,'御定全唐詩/json/452.json','["我本海上鶴，偶逢江南客。感君一顧恩，同來洛陽陌。", "洛陽寡族類，皎皎唯兩翼。貌是天與高，色非日浴白。", "主人誠可戀，其奈軒庭窄。飲啄雜雞群，年深損標格。", "故鄉渺何處，雲水重重隔。誰念深籠中，七換摩天翮。"]'),
('yuding-11','立秋夕有懷夢得','白居易','唐','御定全唐诗','yuding','','[]','露簟荻竹清，風扇蒲葵輕。一與故人別，再見新蟬鳴。',72,'御定全唐詩/json/452.json','["露簟荻竹清，風扇蒲葵輕。一與故人別，再見新蟬鳴。", "是夕涼飆起，閑境入幽情。回燈見棲鶴，隔竹聞吹笙。", "夜茶一兩杓，秋吟三數聲。所思渺千里，雲外長洲城。"]'),
('yuding-12','哭崔常侍晦叔','白居易','唐','御定全唐诗','yuding','','[]','頑賤一拳石，精珍百煉金。名價既相遠，交分何其深。',168,'御定全唐詩/json/452.json','["頑賤一拳石，精珍百煉金。名價既相遠，交分何其深。", "中誠一以合，外物不能侵。逶迤二十年，與世同浮沈。", "晚有退閑約，白首歸雲林。垂老忽相失，悲哉口語心。", "春日嵩高陽，秋夜清洛陰。丘園共誰蔔，山水共誰尋。", "風月共誰賞，詩篇共誰吟。花開共誰看，酒熟共誰斟。", "惠死莊杜口，鐘歿師廢琴。道理使之然，從古非獨今。", "吾道自此孤，我情安可任。唯將病眼淚，一灑秋風襟。"]'),
('yuding-13','新秋曉興','白居易','唐','御定全唐诗','yuding','','[]','濁暑忽已退，清宵未全長。晨釭耿殘焰，宿合凝微香。',96,'御定全唐詩/json/452.json','["濁暑忽已退，清宵未全長。晨釭耿殘焰，宿合凝微香。", "喔喔雞下樹，輝輝日上樑。枕低茵席軟，臥穩身入床。", "睡足景猶早，起初風乍涼。展張小屏幛，收拾生衣裳。", "還有惆悵事，遲遲未能忘。拂鏡梳白髮，可憐冰照霜。"]'),
('yuding-14','秋日與張賓客舒著作同游龍門醉中狂歌凡二百三十八字','白居易','唐','御定全唐诗','yuding','','[]','秋天高高秋光清，秋風嫋嫋秋蟲鳴。嵩峰餘霞錦綺卷，',144,'御定全唐詩/json/452.json','["秋天高高秋光清，秋風嫋嫋秋蟲鳴。嵩峰餘霞錦綺卷，", "商嶺老人自追逐，蓬丘逸士相逢迎。南出鼎門十八裏，", "並轡踟躕下西岸，扣舷容與繞中汀。開懷曠達無所系，", "翠藻蔓長孔雀尾，彩船櫓急寒雁聲。家醞一壺白玉液，", "暫停杯觴輟吟詠，我有狂言君試聽。丈夫一生有二志，", "況吾頭白眼已暗，終日戚促何所成。不如展眉開口笑，"]'),
('yuding-15','履信池櫻桃島上醉後走筆送別舒員外兼寄宗正李卿考功崔郎中','白居易','唐','御定全唐诗','yuding','','[]','櫻桃島前春，去春花萬枝。忽憶與宗卿閑飲日，',45,'御定全唐詩/json/452.json','["櫻桃島前春，去春花萬枝。忽憶與宗卿閑飲日，", "蹋葉悲秋複憶春，池邊樹下重殷勤。今朝一酌臨寒水，"]'),
('yuding-16','秋池獨泛','白居易','唐','御定全唐诗','yuding','','[]','蕭疏秋竹籬，清淺秋風池。一隻短舫艇，一張斑鹿皮。',72,'御定全唐詩/json/452.json','["蕭疏秋竹籬，清淺秋風池。一隻短舫艇，一張斑鹿皮。", "皮上有野叟，手中持酒卮。半酣箕踞坐，自問身為誰。", "嚴子垂釣日，蘇門長嘯時。悠然意自得，意外何人知。"]'),
('yuding-17','冬日早起閑詠','白居易','唐','御定全唐诗','yuding','','[]','水塘耀初旭，風竹飄餘霰。幽境雖目前，不因閑不見。',72,'御定全唐詩/json/452.json','["水塘耀初旭，風竹飄餘霰。幽境雖目前，不因閑不見。", "晨起對爐香，道經尋兩卷。晚坐拂琴塵，秋思彈一遍。", "此外更無事，開尊時自勸。何必東風來，一杯春上面。"]'),
('yuding-18','歲暮','白居易','唐','御定全唐诗','yuding','','[]','慘澹歲雲暮，窮陰動經旬。霜風裂人面，冰雪摧車輪。',120,'御定全唐詩/json/452.json','["慘澹歲雲暮，窮陰動經旬。霜風裂人面，冰雪摧車輪。", "而我當是時，獨不知苦辛。晨炊廩有米，夕爨廚有薪。", "夾帽長覆耳，重裘寬裹身。加之一杯酒，煦嫗如陽春。", "洛城士與庶，比屋多饑貧。何處爐有火，誰家甑無塵。", "如我飽暖者，百人無一人。安得不慚愧，放歌聊自陳。"]'),
('yuding-19','南池早春有懷','白居易','唐','御定全唐诗','yuding','','[]','朝遊北橋上，晚憩南塘畔。西日雪全銷，東風冰盡泮。',96,'御定全唐詩/json/452.json','["朝遊北橋上，晚憩南塘畔。西日雪全銷，東風冰盡泮。", "蓰蓰魚尾掉，瞥瞥鵝毛換。泥暖草芽生，沙虛泉脈散。", "晴芳冒苔島，宿潤侵蒲岸。洛下日初長，江南春欲半。", "時光共拋擲，人事堪嗟歎。倚棹忽尋思，去年池上伴。"]'),
('yuding-20','古意','白居易','唐','御定全唐诗','yuding','','[]','脈脈複脈脈，美人千里隔。不見來幾時，瑤草三四碧。',72,'御定全唐詩/json/452.json','["脈脈複脈脈，美人千里隔。不見來幾時，瑤草三四碧。", "玉琴聲悄悄，鸞鏡塵冪冪。昔為連理枝，今作分飛翮。", "寄書多不達，加飯終無益。心腸不自寬，衣帶何由窄。"]'),
('yuding-21','山遊示小妓','白居易','唐','御定全唐诗','yuding','','[]','雙鬟垂未合，三十才過半。本是綺羅人，今為山水伴。',72,'御定全唐詩/json/452.json','["雙鬟垂未合，三十才過半。本是綺羅人，今為山水伴。", "春泉共揮弄，好樹同攀玩。笑容共底迷，酒思風前亂。", "紅凝舞袖急，黛慘歌聲緩。莫唱楊柳枝，無腸與君斷。"]'),
('yuding-22','神照禪師同宿','白居易','唐','御定全唐诗','yuding','','[]','八年三月晦，山梨花滿枝。龍門水西寺，夜與遠公期。',48,'御定全唐詩/json/452.json','["八年三月晦，山梨花滿枝。龍門水西寺，夜與遠公期。", "晏坐自相對，密語誰得知。前後際斷處，一念不生時。"]'),
('yuding-23','張常侍相訪','白居易','唐','御定全唐诗','yuding','','[]','西亭晚寂寞，鶯散柳陰繁。水戶簾不卷，風床席自翻。',48,'御定全唐詩/json/452.json','["西亭晚寂寞，鶯散柳陰繁。水戶簾不卷，風床席自翻。", "忽聞車馬客，來訪蓬蒿門。況是張常侍，安得不開尊。"]'),
('yuding-24','早夏遊宴','白居易','唐','御定全唐诗','yuding','','[]','雖慵興猶在，雖老心猶健。昨日山水游，今朝花酒宴。',72,'御定全唐詩/json/452.json','["雖慵興猶在，雖老心猶健。昨日山水游，今朝花酒宴。", "山榴豔似火，王蕊飄如霰。榮落逐瞬遷，炎涼隨刻變。", "未收木綿褥，已動蒲葵扇。且喜物與人，年年得相見。"]'),
('yuding-25','感白蓮花','白居易','唐','御定全唐诗','yuding','','[]','白白芙蓉花，本生吳江濆。不與紅者雜，色類自區分。',144,'御定全唐詩/json/452.json','["白白芙蓉花，本生吳江濆。不與紅者雜，色類自區分。", "誰移爾至此，姑蘇白使君。初來苦憔悴，久乃芳氛氳。", "月月葉換葉，年年根生根。陳根與故葉，銷化成泥塵。", "化者日已遠，來者日複新。一為池中物，永別江南春。", "忽想西涼州，中有天寶民。埋歿漢父祖，孳生胡子孫。", "已忘鄉土戀，豈念君親恩。生人尚複爾，草木何足雲。"]'),
('yuding-26','詠所樂','白居易','唐','御定全唐诗','yuding','','[]','獸樂在山谷，魚樂在陂池。蟲樂在深草，鳥樂在高枝。',180,'御定全唐詩/json/452.json','["獸樂在山谷，魚樂在陂池。蟲樂在深草，鳥樂在高枝。", "所樂雖不同，同歸適其宜。不以彼易此，況論是與非。", "而我何所樂，所樂在分司。分司有何樂，樂哉人不知。", "官優有祿料，職散無羈縻。懶與道相近，鈍將閑自隨。", "昨朝拜表回，今晚行香歸。歸來北窗下，解巾脫塵衣。", "冷泉灌我頂，暖水濯四肢。體中幸無疾，臥任清風吹。", "心中又無事，坐任白日移。或開書一篇，或引酒一卮。", "但得如今日，終身無厭時。"]'),
('yuding-27','思舊','白居易','唐','御定全唐诗','yuding','','[]','閑日一思舊，舊遊如目前。再思今何在，零落歸下泉。',192,'御定全唐詩/json/452.json','["閑日一思舊，舊遊如目前。再思今何在，零落歸下泉。", "退之服硫黃，一病訖不痊。微之煉秋石，未老身溘然。", "杜子得丹訣，終日斷腥膻。崔君誇藥力，經冬不衣綿。", "或疾或暴夭，悉不過中年。唯予不服食，老命反遲延。", "況在少壯時，亦為嗜欲牽。但耽葷與血，不識汞與鉛。", "饑來吞熱物，渴來飲寒泉。詩役五藏神，酒汩三丹田。", "隨日合破壞，至今粗完全。齒牙未缺落，肢體尚輕便。", "已開第七秩，飽食仍安眠。且進杯中物，其餘皆付天。"]'),
('yuding-28','寄盧少尹','白居易','唐','御定全唐诗','yuding','','[]','老誨心不亂，莊戒形太勞。生命既能保，死籍亦可逃。',168,'御定全唐詩/json/452.json','["老誨心不亂，莊戒形太勞。生命既能保，死籍亦可逃。", "嘉肴與旨酒，信是腐腸膏。豔聲與麗色，真為伐性刀。", "補養在積功，如裘集眾毛。將欲致千里，可得差一毫。", "顏回何為者，簟瓢才自給。肥醲不到口，年不登三十。", "張蒼何為者，染愛浩無際。妾媵填後房，竟壽百餘歲。", "蒼壽有何德，回夭有何辜。誰謂具聖體，不如肥瓠軀。", "遂使世俗心，多疑仙道書。寄問盧先生，此理當何如。"]'),
('yuding-29','池上清晨候皇甫郎中','白居易','唐','御定全唐诗','yuding','','[]','曉景麗未熱，晨飆鮮且涼。池幽綠蘋合，霜潔白蓮香。',72,'御定全唐詩/json/452.json','["曉景麗未熱，晨飆鮮且涼。池幽綠蘋合，霜潔白蓮香。", "深掃竹間徑，靜拂松下床。玉柄鶴翎扇，銀罌雲母漿。", "屏除無俗物，瞻望唯清光。何人擬相訪，嬴女從蕭郎。"]'),
('yuding-30','詠懷','白居易','唐','御定全唐诗','yuding','','[]','我知世無幻，了無干世意。世知我無堪，亦無責我事。',144,'御定全唐詩/json/452.json','["我知世無幻，了無干世意。世知我無堪，亦無責我事。", "由茲兩相忘，因得長自遂。自遂意何如，閑官在閑地。", "閑地唯東都，東都少名利。閑官是賓客，賓客無牽累。", "嵇康日日懶，畢卓時時醉。酒肆夜深歸，僧房日高睡。", "形安不勞苦，神泰無憂畏。從官三十年，無如今氣味。", "鴻雖脫羅弋，鶴尚居祿位。唯此未忘懷，有時猶內愧。"]'),
('yuding-31','北窗三友','白居易','唐','御定全唐诗','yuding','','[]','今日北窗下，自問何所為。欣然得三友，三友者為誰。',204,'御定全唐詩/json/452.json','["今日北窗下，自問何所為。欣然得三友，三友者為誰。", "琴罷輒舉酒，酒罷輒吟詩。三友遞相引，迴圈無已時。", "一彈愜中心，一詠暢四肢。猶恐中有間，以酒彌縫之。", "豈獨吾拙好，古人多若斯。嗜詩有淵明，嗜琴有啟期。", "嗜酒有伯倫，三人皆吾師。或乏儋石儲，或穿帶索衣。", "弦歌複觴詠，樂道知所歸。三師去已遠，高風不可追。", "三友游甚熟，無日不相隨。左擲白玉卮，右拂黃金徽。", "興酣不疊紙，走筆操狂詞。誰能持此詞，為我謝親知。", "縱未以為是，豈以我為非。"]'),
('yuding-32','吟四雖','白居易','唐','御定全唐诗','yuding','','[]','酒酣後，歌歇時。請君添一酌，聽我吟四雖。年雖老，',24,'御定全唐詩/json/452.json','["酒酣後，歌歇時。請君添一酌，聽我吟四雖。年雖老，"]'),
('yuding-33','裴侍中晉公以集賢林亭即事詩三十六韻見贈猥蒙徵和才拙詞繁輒廣為五百言以伸酬獻','白居易','唐','御定全唐诗','yuding','','[]','三江路千里，五湖天一涯。何如集賢第，中有平津池。',577,'御定全唐詩/json/452.json','["三江路千里，五湖天一涯。何如集賢第，中有平津池。", "池勝主見覺，景新人未知。竹森翠琅玕，水深洞琉璃。", "水竹以為質，質立而文隨。文之者何人，公來親指麾。", "疏鑿出人意，結構得地宜。靈襟一搜索，勝概無遁遺。", "因下張沼沚，依高築階基。嵩峰見數片，伊水分一支。", "南溪修且直，長波碧逶迤。北館壯複麗，倒影紅參差。", "東島號晨光，杲曜迎朝曦。西嶺名夕陽，杳曖留落暉。", "前有水心亭，動盪架漣漪。後有開闔堂，寒溫變天時。", "幽泉鏡泓澄，怪石山欹危。春葩雪漠漠，夏果珠離離。", "主人命方舟，宛在水中坻。親賓次第至，酒樂前後施。", "解纜始登泛，山游仍水嬉。沿洄無滯礙，向背窮幽奇。", "瞥過遠橋下，飄旋深澗陲。管弦去縹緲，羅綺來霏微。", "棹風逐舞回，梁塵隨歌飛。宴餘日雲暮，醉客未放歸。", "高聲索彩箋，大笑催金卮。唱和筆走疾，問答杯行遲。", "一詠清兩耳，一酣暢四肢。主客忘貴賤，不知俱是誰。", "客有詩魔者，吟哦不知疲。乞公殘紙墨，一掃狂歌詞。", "維雲社稷臣，赫赫文武姿。十授丞相印，五建大將旗。", "四朝致勳華，一身冠皋夔。去年才七十，決赴懸車期。", "公志不可奪，君恩亦難希。從容就中道，勉黽來保厘。", "貂蟬雖未脫，鸞皇已不羈。曆征今與古，獨步無等夷。", "陸賈功業少，二疏官秩卑。乘舟範蠡懼，辟谷留侯饑。", "豈若公今日，身安家國肥。羊祜在漢南，空留峴首碑。", "柳惲在江南，只賦汀洲詩。謝安入東山，但說攜蛾眉。", "山簡醉高陽，唯聞倒接z5。豈如公今日，餘力兼有之。"]'),
('yuding-34','晚歸香山寺，因詠所懷','白居易','唐','御定全唐诗','yuding','','[]','我年日已老，我身日已閑。閑出都門望，但見水與山。',132,'御定全唐詩/json/452.json','["我年日已老，我身日已閑。閑出都門望，但見水與山。", "關塞碧岩岩，伊流清潺潺。中有古精舍，軒戶無扃關。", "岸草歇可藉，徑蘿行可攀。朝隨浮雲出，夕與飛鳥還。", "吾道本迂拙，世途多險艱。嘗聞嵇呂輩，尤悔生疏頑。", "巢悟入箕潁，皓知返商巔。豈唯樂肥遁，聊複祛憂患。", "吾亦從此去，終老伊嵩間。"]'),
('yuding-35','張常侍池涼夜閑宴贈諸公','白居易','唐','御定全唐诗','yuding','','[]','竹橋新月上，水岸涼風至。對月五六人，管弦三兩事。',84,'御定全唐詩/json/452.json','["竹橋新月上，水岸涼風至。對月五六人，管弦三兩事。", "留連池上酌，款曲城外意。或嘯或謳吟，誰知此閑味。", "回看市朝客，矻矻趨名利。朝忙少遊宴，夕困多眠睡。", "清涼屬吾徒，相逢勿辭醉。"]'),
('yuding-36','和皇甫郎中秋曉同登天宮閣言懷六韻','白居易','唐','御定全唐诗','yuding','','[]','碧天忽已高，白日猶未短。玲瓏曉樓閣，清脆秋絲管。',72,'御定全唐詩/json/452.json','["碧天忽已高，白日猶未短。玲瓏曉樓閣，清脆秋絲管。", "張翰一杯酣，嵇康終日懶。塵中足憂累，雲外多疏散。", "病木斧斤遺，冥鴻羈絏斷。逍遙二三子，永願為閑伴。"]'),
('yuding-37','送呂漳州','白居易','唐','御定全唐诗','yuding','','[]','今朝一壺酒，言送漳州牧。半自要閒遊，愛花憐草綠。',72,'御定全唐詩/json/452.json','["今朝一壺酒，言送漳州牧。半自要閒遊，愛花憐草綠。", "花前下鞍馬，草上攜絲竹。行客飲數杯，主人歌一曲。", "端居惜風景，屢出勞僮僕。獨醉似無名，借君作題目。"]'),
('yuding-38','短歌曲','白居易','唐','御定全唐诗','yuding','','[]','世人求富貴，多為奉嗜欲。盛衰不自由，得失常相逐。',168,'御定全唐詩/json/452.json','["世人求富貴，多為奉嗜欲。盛衰不自由，得失常相逐。", "問君少年日，苦學將幹祿。負笈塵中游，抱書雪前讀。", "布衾不周體，藜茹才充腹。三十登宦途，五十被朝服。", "奴溫新挾纊，馬肥初食粟。未敢議歡游，尚為名檢束。", "耳目聾暗後，堂上調絲竹。牙齒缺落時，盤中堆酒肉。", "彼來此已去，外餘中不足。少壯與榮華，相避如寒燠。", "青雲去地遠，白日經天速。從古無奈何，短歌聽一曲。"]'),
('yuding-39','詠懷','白居易','唐','御定全唐诗','yuding','','[]','高人樂丘園，中人慕官職。一事尚難成，兩途安可得。',96,'御定全唐詩/json/452.json','["高人樂丘園，中人慕官職。一事尚難成，兩途安可得。", "遑遑幹世者，多苦時命塞。亦有愛閒人，又為窮餓逼。", "我今幸雙遂，祿仕兼遊息。未嘗羨榮華，不省勞心力。", "妻孥與婢僕，亦免愁衣食。所以吾一家，面無憂喜色。"]'),
('yuding-40','府西亭納涼歸','白居易','唐','御定全唐诗','yuding','','[]','避暑府西亭，晚歸有閑思。夏淺蟬未多，綠槐陰滿地。',96,'御定全唐詩/json/452.json','["避暑府西亭，晚歸有閑思。夏淺蟬未多，綠槐陰滿地。", "帶寬衫解領，馬穩人攏轡。面上有涼風，眼前無俗事。", "路經府門過，落日照官次。牽聯縲絏囚，奔走塵埃吏。", "低眉悄不語，誰複知茲意。憶得五年前，晚衙時氣味。"]'),
('yuding-41','老熱','白居易','唐','御定全唐诗','yuding','','[]','一飽百情足，一酣萬事休。何人不衰老，我老心無憂。',144,'御定全唐詩/json/452.json','["一飽百情足，一酣萬事休。何人不衰老，我老心無憂。", "仕者拘職役，農者勞田疇。何人不苦熱，我熱身自由。", "臥風北窗下，坐月南池頭。腦涼脫烏帽，足熱濯清流。", "慵發晝高枕，興來夜泛舟。何乃有餘適，只緣無過求。", "或問諸親友，樂天是與不。亦無別言語，多道天悠悠。", "悠悠君不知，此味深且幽。但恐君知後，亦來從我遊。"]'),
('yuding-42','新秋喜涼，因寄兵部楊侍郎','白居易','唐','御定全唐诗','yuding','','[]','外強火未退，中銳金方戰。一夕風雨來，炎涼隨數變。',120,'御定全唐詩/json/452.json','["外強火未退，中銳金方戰。一夕風雨來，炎涼隨數變。", "徐徐炎景度，稍稍涼飆扇。枕簟忽淒清，巾裳亦輕健。", "老夫納秋候，心體殊安便。睡足一屈伸，搔首摩挲面。", "褰簾對池竹，幽寂如僧院。俯觀遊魚群，仰數浮雲片。", "閑忙各有趣，彼此寧相見。昨日聞慕巢，召對延英殿。"]'),
('yuding-43','懶放二首，呈劉夢得、吳方之','白居易','唐','御定全唐诗','yuding','','[]','青衣報平旦，呼我起盥櫛。今早天氣寒，郎君應不出。',96,'御定全唐詩/json/452.json','["青衣報平旦，呼我起盥櫛。今早天氣寒，郎君應不出。", "又無賓客至，何以銷閑日。已向微陽前，暖酒開詩帙。", "朝憐一床日，暮愛一爐火。床暖日高眠，爐溫夜深坐。", "雀羅門懶出，鶴發頭慵裹。除卻劉與吳，何人來問我。"]'),
('yuding-44','六十六','白居易','唐','御定全唐诗','yuding','','[]','病知心力減，老覺光陰速。五十八歸來，今年六十六。',72,'御定全唐詩/json/452.json','["病知心力減，老覺光陰速。五十八歸來，今年六十六。", "鬢絲千萬白，池草八九綠。童稚盡成人，園林半喬木。", "看山倚高石，引水穿深竹。雖有潺湲聲，至今聽未足。"]'),
('yuding-45','三適贈道友','白居易','唐','御定全唐诗','yuding','','[]','褐綾袍厚暖，臥蓋行坐披。紫氈履寬穩，蹇步頗相宜。',84,'御定全唐詩/json/452.json','["褐綾袍厚暖，臥蓋行坐披。紫氈履寬穩，蹇步頗相宜。", "足適已忘履，身適已忘衣。況我心又適，兼忘是與非。", "三適今為一，怡怡複熙熙。禪那不動處，混沌未鑿時。", "此固不可說，為君強言之。"]'),
('yuding-46','洛陽春贈劉李二賓客','白居易','唐','御定全唐诗','yuding','','[]','水南冠蓋地，城東桃李園。雪消洛陽堰，春入永通門。',96,'御定全唐詩/json/452.json','["水南冠蓋地，城東桃李園。雪消洛陽堰，春入永通門。", "淑景方靄靄，遊人稍喧喧。年豐酒漿賤，日晏歌吹繁。", "中有老朝客，華髮映朱軒。從容三兩人，藉草開一尊。", "尊前春可惜，身外事勿論。明日期何處，杏花游趙村。"]'),
('yuding-47','寒食','白居易','唐','御定全唐诗','yuding','','[]','人老何所樂，樂在歸鄉國。我歸故園來，九度逢寒食。',96,'御定全唐詩/json/452.json','["人老何所樂，樂在歸鄉國。我歸故園來，九度逢寒食。", "故園在何處，池館東城側。四鄰梨花時，二月伊水色。", "豈獨好風土，仍多舊親戚。出去恣歡遊，歸來聊燕息。", "有官供祿俸，無事勞心力。但恐優穩多，微躬銷不得。"]'),
('yuding-48','和裴令公一日日一年年雜言見贈','白居易','唐','御定全唐诗','yuding','','[]','一日日，作老翁。一年年，過春風。公心不以貴隔我，',70,'御定全唐詩/json/452.json','["一日日，作老翁。一年年，過春風。公心不以貴隔我，", "公有功德在生民，何因得作自由身。前日魏王潭上宴連夜，", "不敢與公閑中爭第一，亦應占得第二第三人。"]'),
('yuding-0','題裴晉公女幾山刻石詩後','白居易','唐','御定全唐诗','yuding','','[]','何處畫功業，何處題詩篇。麒麟高閣上，女幾小山前。',216,'御定全唐詩/json/453.json','["何處畫功業，何處題詩篇。麒麟高閣上，女幾小山前。", "爾後多少時，四朝二十年。賊骨化為土，賊壘犁為田。", "一從賊壘平，陳蔡民晏然。騾軍成牛戶，鬼火變人煙。", "生子已嫁娶，種桑亦絲綿。皆雲公之德，欲報無由緣。", "公今在何處，守都鎮三川。舊宅留永樂，新居開集賢。", "公今在何官，被袞珥貂蟬。戰袍破猶在，髀肉生欲圓。", "襟懷轉蕭灑，氣力彌精堅。登山不拄杖，上馬能掉鞭。", "利澤浸入池，福降升自天。昔號天下將，今稱地上仙。", "勿追赤松遊，勿拍洪崖肩。商山有遺老，可以奉周旋。"]'),
('yuding-1','洛陽有愚叟','白居易','唐','御定全唐诗','yuding','','[]','洛陽有愚叟，白黑無分別。浪跡雖似狂，謀身亦不拙。',144,'御定全唐詩/json/453.json','["洛陽有愚叟，白黑無分別。浪跡雖似狂，謀身亦不拙。", "點檢盤中飯，非精亦非糲。點檢身上衣，無餘亦無闕。", "天時方得所，不寒複不熱。體氣正調和，不饑仍不渴。", "閑將酒壺出，醉向人家歇。野食或烹鮮，寓眠多擁褐。", "抱琴榮啟樂，荷鍤劉伶達。放眼看青山，任頭生白髮。", "不知天地內，更得幾年活。從此到終身，盡為閑日月。"]'),
('yuding-2','飽食閑坐','白居易','唐','御定全唐诗','yuding','','[]','紅粒陸渾稻，白鱗伊水魴。庖童呼我食，飯熱魚鮮香。',204,'御定全唐詩/json/453.json','["紅粒陸渾稻，白鱗伊水魴。庖童呼我食，飯熱魚鮮香。", "箸箸適我口，匙匙充我腸。八珍與五鼎，無複心思量。", "捫腹起盥漱，下階振衣裳。繞庭行數匝，卻上簷下床。", "箕踞擁裘坐，半身在日暘。可憐飽暖味，誰肯來同嘗。", "是歲太和八，兵銷時漸康。朝廷重經術，草澤搜賢良。", "堯舜求理切，夔龍啟沃忙。懷才抱智者，無不走遑遑。", "唯此不才叟，頑慵戀洛陽。飽食不出門，閑坐不下堂。", "子弟多寂寞，僮僕少精光。衣食雖充給，神意不揚揚。", "為爾謀則短，為吾謀甚長。"]'),
('yuding-3','閒居自題','白居易','唐','御定全唐诗','yuding','','[]','門前有流水，牆上多高樹。竹徑繞荷池，縈回百餘步。',96,'御定全唐詩/json/453.json','["門前有流水，牆上多高樹。竹徑繞荷池，縈回百餘步。", "波閑戲魚鱉，風靜下鷗鷺。寂無城市喧，渺有江湖趣。", "吾廬在其上，偃臥朝複暮。洛下安一居，山中亦慵去。", "時逢過客愛，問是誰家住。此是白家翁，閉門終老處。"]'),
('yuding-4','覽鏡喜老','白居易','唐','御定全唐诗','yuding','','[]','今朝覽明鏡，須鬢盡成絲。行年六十四，安得不衰羸。',168,'御定全唐詩/json/453.json','["今朝覽明鏡，須鬢盡成絲。行年六十四，安得不衰羸。", "親屬惜我老，相顧興歎咨。而我獨微笑，此意何人知。", "笑罷仍命酒，掩鏡捋白髭。爾輩且安坐，從容聽我詞。", "生若不足戀，老亦何足悲。生若苟可戀，老即生多時。", "不老即須夭，不夭即須衰。晚衰勝早夭，此理決不疑。", "古人亦有言，浮生七十稀。我今欠六歲，多幸或庶幾。", "倘得及此限，何羨榮啟期。當喜不當歎，更傾酒一卮。"]'),
('yuding-5','風雪中作','白居易','唐','御定全唐诗','yuding','','[]','歲暮風動地，夜寒雪連天。老夫何處宿，暖帳溫爐前。',144,'御定全唐詩/json/453.json','["歲暮風動地，夜寒雪連天。老夫何處宿，暖帳溫爐前。", "兩重褐綺衾，一領花茸氈。粥熟呼不起，日高安穩眠。", "是時心與身，了無閒事牽。以此度風雪，閒居來六年。", "忽思遠遊客，複想早朝士。蹋凍侵夜行，淩寒未明起。", "心為身君父，身為心臣子。不得身自由，皆為心所使。", "我心既知足，我身自安止。方寸語形骸，吾應不負爾。"]'),
('yuding-6','對琴酒','白居易','唐','御定全唐诗','yuding','','[]','西窗明且暖，晚坐卷書帷。琴匣拂開後，酒瓶添滿時。',96,'御定全唐詩/json/453.json','["西窗明且暖，晚坐卷書帷。琴匣拂開後，酒瓶添滿時。", "角尊白螺醆，玉軫黃金徽。未及彈與酌，相對已依依。", "泠泠秋泉韻，貯在龍鳳池。油油春雲心，一杯可致之。", "自古有琴酒，得此味者稀。只因康與籍，及我三心知。"]'),
('yuding-7','雪中晏起偶詠所懷兼呈張常侍、韋庶子、皇甫郎中','白居易','唐','御定全唐诗','yuding','','[]','窮陰蒼蒼雪雰雰，雪深沒脛泥埋輪。東家典錢歸礙夜，',162,'御定全唐詩/json/453.json','["窮陰蒼蒼雪雰雰，雪深沒脛泥埋輪。東家典錢歸礙夜，", "怕寒放懶不肯動，日高眠足方頻伸。瓶中有酒爐有炭，", "上無皋陶伯益廊廟材，的不能匡君輔國活生民。", "下無巢父許由箕潁操，又不能食薇飲水自苦辛。", "君不見南山悠悠多白雲，又不見西京浩浩唯紅塵。", "紅塵鬧熱白雲冷，好于冷熱中間安置身。三年僥倖忝洛尹，", "冉冉老去過六十，騰騰閑來經七春。不知張韋與皇甫，"]'),
('yuding-8','和裴侍中南園靜興見示','白居易','唐','御定全唐诗','yuding','','[]','池館清且幽，高懷亦如此。有時簾動風，盡日橋照水。',48,'御定全唐詩/json/453.json','["池館清且幽，高懷亦如此。有時簾動風，盡日橋照水。", "靜將鶴為伴，閑與雲相似。何必學留侯，崎嶇覓松子。"]'),
('yuding-9','春寒','白居易','唐','御定全唐诗','yuding','','[]','今朝春氣寒，自問何所欲。酥暖薤白酒，乳和地黃粥。',71,'御定全唐詩/json/453.json','["今朝春氣寒，自問何所欲。酥暖薤白酒，乳和地黃粥。", "豈惟厭饞口，亦可調病腹。助酌有枯魚，佐餐兼旨蓄。", "省躬念前哲，醉飽多慚忸。君不聞靖節先生尊長空，"]'),
('yuding-10','菩提寺上方晚望香山寺，寄舒員外','白居易','唐','御定全唐诗','yuding','','[]','晚登西寶刹，晴望東精舍。反照轉樓臺，輝輝似圖畫。',72,'御定全唐詩/json/453.json','["晚登西寶刹，晴望東精舍。反照轉樓臺，輝輝似圖畫。", "冰浮水明滅，雪壓松偃亞。石閣僧上來，雲汀雁飛下。", "西京鬧於市，東洛閑如社。曾憶舊遊無，香山明月夜。"]'),
('yuding-11','二月一日作，贈韋七庶子','白居易','唐','御定全唐诗','yuding','','[]','園杏紅萼坼，庭蘭紫芽出。不覺春已深，今朝二月一。',96,'御定全唐詩/json/453.json','["園杏紅萼坼，庭蘭紫芽出。不覺春已深，今朝二月一。", "去冬病瘡痏，將養遵醫術。今春入道場，清淨依僧律。", "嘗聞聖賢語，所慎齋與疾。遂使愛酒人，停杯一百日。", "明朝二月二，疾平齋複畢。應須挈一壺，尋花覓韋七。"]'),
('yuding-12','犬鳶','白居易','唐','御定全唐诗','yuding','','[]','晚來天氣好，散步中門前。門前何所有，偶睹犬與鳶。',96,'御定全唐詩/json/453.json','["晚來天氣好，散步中門前。門前何所有，偶睹犬與鳶。", "鳶飽淩風飛，犬暖向日眠。腹舒穩貼地，翅凝高摩天。", "上無羅弋憂，下無羈鎖牽。見彼物遂性，我亦心適然。", "心適複何為，一詠逍遙篇。此仍著於適，尚未能忘言。"]'),
('yuding-13','夢劉二十八，因詩問之','白居易','唐','御定全唐诗','yuding','','[]','昨夜夢夢得，初覺思踟躕。忽忘來汝郡，猶疑在吳都。',108,'御定全唐詩/json/453.json','["昨夜夢夢得，初覺思踟躕。忽忘來汝郡，猶疑在吳都。", "吳都三千里，汝郡二百餘。非夢亦不見，近與遠何殊。", "尚能齊近遠，焉用論榮枯。但問寢與食，近日兩何如。", "病後能吟否，春來曾醉無。樓臺與風景，汝又何如蘇。", "相思一相報，勿複慵為書。"]'),
('yuding-14','閑吟','白居易','唐','御定全唐诗','yuding','','[]','貧窮汲汲求衣食，富貴營營役心力。人生不富即貧窮，',40,'御定全唐詩/json/453.json','["貧窮汲汲求衣食，富貴營營役心力。人生不富即貧窮，", "看雪尋花玩風月，洛陽城裏七年閑。"]'),
('yuding-15','西行','白居易','唐','御定全唐诗','yuding','','[]','衣裘不單薄，車馬不羸弱。藹藹三月天，閑行亦不惡。',96,'御定全唐詩/json/453.json','["衣裘不單薄，車馬不羸弱。藹藹三月天，閑行亦不惡。", "壽安流水館，硤石青山郭。官道柳陰陰，行宮花漠漠。", "常聞俗間語，有錢在處樂。我雖非富人，亦不苦寂寞。", "家僮解弦管，騎從攜杯杓。時向春風前，歇鞍開一酌。"]'),
('yuding-16','東歸','白居易','唐','御定全唐诗','yuding','','[]','翩翩平肩輿，中有醉老夫。膝上展詩卷，竿頭懸酒壺。',120,'御定全唐詩/json/453.json','["翩翩平肩輿，中有醉老夫。膝上展詩卷，竿頭懸酒壺。", "食宿無定程，僕馬多緩驅。臨水歇半日，望山傾一盂。", "藉草坐嵬峨，攀花行踟躕。風將景共暖，體與心同舒。", "始悟有營者，居家如在途。方知無系者，在道如安居。", "前夕宿三堂，今旦游申湖。殘春三百里，送我歸東都。"]'),
('yuding-17','途中作','白居易','唐','御定全唐诗','yuding','','[]','早起上肩舁，一杯平旦醉。晚憩下肩舁，一覺殘春睡。',48,'御定全唐詩/json/453.json','["早起上肩舁，一杯平旦醉。晚憩下肩舁，一覺殘春睡。", "身不經營物，心不思量事。但恐綺與裏，只如吾氣味。"]'),
('yuding-18','小台','白居易','唐','御定全唐诗','yuding','','[]','新樹低如帳，小台平似掌。六尺白藤床，一莖青竹杖。',48,'御定全唐詩/json/453.json','["新樹低如帳，小台平似掌。六尺白藤床，一莖青竹杖。", "風飄竹皮落，苔印鶴跡上。幽境與誰同，閒人自來往。"]'),
('yuding-19','睡後茶興憶楊同州','白居易','唐','御定全唐诗','yuding','','[]','昨晚飲太多，嵬峨連宵醉。今朝餐又飽，爛漫移時睡。',120,'御定全唐詩/json/453.json','["昨晚飲太多，嵬峨連宵醉。今朝餐又飽，爛漫移時睡。", "睡足摩挲眼，眼前無一事。信腳繞池行，偶然得幽致。", "婆娑綠陰樹，斑駁青苔地。此處置繩床，傍邊洗茶器。", "白瓷甌甚潔，紅爐炭方熾。沫下麹塵香，花浮魚眼沸。", "盛來有佳色，咽罷餘芳氣。不見楊慕巢，誰人知此味。"]'),
('yuding-20','題文集櫃','白居易','唐','御定全唐诗','yuding','','[]','破柏作書櫃，櫃牢柏複堅。收貯誰家集，題雲白樂天。',96,'御定全唐詩/json/453.json','["破柏作書櫃，櫃牢柏複堅。收貯誰家集，題雲白樂天。", "我生業文字，自幼及老年。前後七十卷，小大三千篇。", "誠知終散失，未忍遽棄捐。自開自鎖閉，置在書帷前。", "身是鄧伯道，世無王仲宣。只應分付女，留與外孫傳。"]'),
('yuding-21','旱熱二首','白居易','唐','御定全唐诗','yuding','','[]','彤雲散不雨，赫日籲可畏。端坐猶揮汗，出門豈容易。',228,'御定全唐詩/json/453.json','["彤雲散不雨，赫日籲可畏。端坐猶揮汗，出門豈容易。", "忽思公府內，青衫折腰吏。複想驛路中，紅塵走馬使。", "征夫更辛苦，逐客彌憔悴。日入尚趨程，宵分不遑寐。", "安知北窗叟，偃臥風颯至。簟拂碧龍鱗，扇搖白鶴翅。", "豈唯身所得，兼示心無事。誰言苦熱天，元有清涼地。", "勃勃旱塵氣，炎炎赤日光。飛禽颭將墜，行人渴欲狂。", "壯者不耐饑，饑火燒其腸。肥者不禁熱，喘急汗如漿。", "此時方自悟，老瘦亦何妨。肉輕足健逸，發少頭清涼。", "薄食不饑渴，端居省衣裳。數匙粱飯冷，一領綃衫香。", "持此聊過日，焉知畏景長。"]'),
('yuding-22','偶作二首','白居易','唐','御定全唐诗','yuding','','[]','戰馬春放歸，農牛冬歇息。何獨徇名人，終身役心力。',120,'御定全唐詩/json/453.json','["戰馬春放歸，農牛冬歇息。何獨徇名人，終身役心力。", "來者殊未已，去者不知還。我今悟已晚，六十方退閑。", "猶勝不悟者，老死紅塵間。", "名無高與卑，未得多健羨。事無小與大，已得多厭賤。", "如此常自苦，反此或自安。此理知甚易，此道行甚難。", "勿信人虛語，君當事上看。"]'),
('yuding-23','池上作','白居易','唐','御定全唐诗','yuding','','[]','西溪風生竹森森，南潭萍開水沉沉。叢翠萬竿湘岸色，',88,'御定全唐詩/json/453.json','["西溪風生竹森森，南潭萍開水沉沉。叢翠萬竿湘岸色，", "澄瀾方丈若萬頃，倒影咫尺如千尋。泛然獨遊邈然坐，", "豈如白翁退老地，樹高竹密池塘深。華亭雙鶴白矯矯，", "洛陽冠蓋自相索，誰肯來此同抽簪。"]'),
('yuding-24','何處堪避暑','白居易','唐','御定全唐诗','yuding','','[]','何處堪避暑，林間背日樓。何處好追涼，池上隨風舟。',144,'御定全唐詩/json/453.json','["何處堪避暑，林間背日樓。何處好追涼，池上隨風舟。", "日高饑始食，食竟飽還遊。遊罷睡一覺，覺來茶一甌。", "眼明見青山，耳醒聞碧流。脫襪閑濯足，解巾快搔頭。", "如此來幾時，已過六七秋。從心至百骸，無一不自由。", "拙退是其分，榮耀非所求。雖被世間笑，終無身外憂。", "此語君莫怪，靜思吾亦愁。如何三伏月，楊尹謫虔州。"]'),
('yuding-25','詔下','白居易','唐','御定全唐诗','yuding','','[]','昨日詔下去罪人，今日詔下得賢臣。進退者誰非我事，',48,'御定全唐詩/json/453.json','["昨日詔下去罪人，今日詔下得賢臣。進退者誰非我事，", "但喜今年飽飯吃，洛陽禾稼如秋雲。更傾一尊歌一曲，"]'),
('yuding-26','七月一日作','白居易','唐','御定全唐诗','yuding','','[]','七月一日天，秋生履道裏。閒居見清景，高興從此始。',120,'御定全唐詩/json/453.json','["七月一日天，秋生履道裏。閒居見清景，高興從此始。", "林間暑雨歇，池上涼風起。橋竹碧鮮鮮，岸莎青靡靡。", "蒼然古磐石，清淺平流水。何言中門前，便是深山裏。", "雙僮侍坐臥，一杖扶行止。饑聞麻粥香，渴覺雲湯美。", "平生所好物，今日多在此。此外更何思，市朝心已矣。"]'),
('yuding-27','開襟','白居易','唐','御定全唐诗','yuding','','[]','開襟何處好，竹下池邊地。餘熱體猶煩，早涼風有味。',48,'御定全唐詩/json/453.json','["開襟何處好，竹下池邊地。餘熱體猶煩，早涼風有味。", "黃萎槐蕊結，紅破蓮芳墜。無奈每年秋，先來入衰思。"]'),
('yuding-28','自賓客遷太子少傅分司','白居易','唐','御定全唐诗','yuding','','[]','頭上漸無發，耳間新有毫。形容逐日老，官秩隨年高。',96,'御定全唐詩/json/453.json','["頭上漸無發，耳間新有毫。形容逐日老，官秩隨年高。", "優饒又加俸，閑穩仍分曹。飲食免藜藿，居處非蓬蒿。", "何言家尚貧，銀榼提綠醪。勿謂身未貴，金章照紫袍。", "誠合知止足，豈宜更貪饕。默默心自問，于國有何勞。"]'),
('yuding-29','自在','白居易','唐','御定全唐诗','yuding','','[]','杲杲冬日光，明暖真可愛。移榻向陽坐，擁裘仍解帶。',120,'御定全唐詩/json/453.json','["杲杲冬日光，明暖真可愛。移榻向陽坐，擁裘仍解帶。", "小奴捶我足，小婢搔我背。自問我為誰，胡然獨安泰。", "安泰良有以，與君論梗概。心了事未了，饑寒迫於外。", "事了心未了，念慮煎於內。我今實多幸，事與心和會。", "內外及中間，了然無一礙。所以日陽中，向君言自在。"]'),
('yuding-30','詠史','白居易','唐','御定全唐诗','yuding','','[]','秦磨利刀斬李斯，齊燒沸鼎烹酈其。可憐黃綺入商洛，',40,'御定全唐詩/json/453.json','["秦磨利刀斬李斯，齊燒沸鼎烹酈其。可憐黃綺入商洛，", "去者逍遙來者死，乃知禍福非天為。"]'),
('yuding-31','因夢有悟','白居易','唐','御定全唐诗','yuding','','[]','交友淪歿盡，悠悠勞夢思。平生所厚者，昨夜夢見之。',144,'御定全唐詩/json/453.json','["交友淪歿盡，悠悠勞夢思。平生所厚者，昨夜夢見之。", "夢中幾許事，枕上無多時。款曲數杯酒，從容一局棋。", "初見韋尚書，金紫何輝輝。中遇李侍郎，笑言甚怡怡。", "終為崔常侍，意色苦依依。一夕三改變，夢心不驚疑。", "此事人盡怪，此理誰得知。我粗知此理，聞于竺幹師。", "識行妄分別，智隱迷是非。若轉識為智，菩提其庶幾。"]'),
('yuding-32','春遊','白居易','唐','御定全唐诗','yuding','','[]','上馬臨出門，出門複逡巡。回頭問妻子，應怪春遊頻。',108,'御定全唐詩/json/453.json','["上馬臨出門，出門複逡巡。回頭問妻子，應怪春遊頻。", "誠知春遊頻，其奈老大身。朱顏去複去，白髮新更新。", "請君屈十指，為我數交親。大限年百歲，幾人及七旬。", "我今六十五，走若下阪輪。假使得七十，只有五度春。", "逢春不遊樂，但恐是癡人。"]'),
('yuding-33','題天竺南院贈閑元旻清四上人','白居易','唐','御定全唐诗','yuding','','[]','雜芳澗草合，繁綠岩樹新。山深景候晚，四月有餘春。',72,'御定全唐詩/json/453.json','["雜芳澗草合，繁綠岩樹新。山深景候晚，四月有餘春。", "竹寺過微雨，石徑無纖塵。白衣一居士，方袍四道人。", "地是佛國土，人非俗交親。城中山下別，相送亦殷勤。"]'),
('yuding-34','哭師皋','白居易','唐','御定全唐诗','yuding','','[]','南康丹旐引魂回，洛陽籃舁送葬來。北邙原邊尹村畔，',72,'御定全唐詩/json/453.json','["南康丹旐引魂回，洛陽籃舁送葬來。北邙原邊尹村畔，", "往者何人送者誰，樂天哭別師皋時。平生分義向人盡，", "何日重聞掃市歌，誰家收得琵琶伎。蕭蕭風樹白楊影，"]'),
('yuding-35','隱幾贈客','白居易','唐','御定全唐诗','yuding','','[]','宦情本淡薄，年貌又老醜。紫綬與金章，于予亦何有。',96,'御定全唐詩/json/453.json','["宦情本淡薄，年貌又老醜。紫綬與金章，于予亦何有。", "有時獨隱幾，答然無所偶。臥枕一卷書，起嘗一杯酒。", "書將引昏睡，酒用扶衰朽。客到忽已酣，脫巾坐搔首。", "疏頑倚老病，容恕慚交友。忽思莊生言，亦擬鞭其後。"]'),
('yuding-36','夏日作','白居易','唐','御定全唐诗','yuding','','[]','葛衣疏且單，紗帽輕複寬。一衣與一帽，可以過炎天。',132,'御定全唐詩/json/453.json','["葛衣疏且單，紗帽輕複寬。一衣與一帽，可以過炎天。", "止於便吾體，何必被羅紈。宿雨林筍嫩，晨露園葵鮮。", "烹葵炮嫩筍，可以備朝餐。止於適吾口，何必飫腥膻。", "飯訖盥漱已，捫腹方果然。婆娑庭前步，安穩窗下眠。", "外養物不費，內歸心不煩。不費用難盡，不煩神易安。", "庶幾無夭閼，得以終天年。"]'),
('yuding-37','晚涼偶詠','白居易','唐','御定全唐诗','yuding','','[]','日下西牆西，風來北窗北。中有逐涼人，單床獨棲息。',72,'御定全唐詩/json/453.json','["日下西牆西，風來北窗北。中有逐涼人，單床獨棲息。", "飄蕭過雲雨，搖曳歸飛翼。新葉多好陰，初筠有佳色。", "幽深小池館，優穩閑官職。不愛勿複論，愛亦不易得。"]'),
('yuding-38','酬牛相公宮城早秋寓言見示兼呈夢得','白居易','唐','御定全唐诗','yuding','','[]','七月中氣後，金與火交爭。一聞白雪唱，暑退清風生。',72,'御定全唐詩/json/453.json','["七月中氣後，金與火交爭。一聞白雪唱，暑退清風生。", "碧樹未搖落，寒蟬始悲鳴。夜涼枕簟滑，秋燥衣巾輕。", "疏受老慵出，劉楨疾未平。何人伴公醉，新月上宮城。"]'),
('yuding-39','小台晚坐憶夢得','白居易','唐','御定全唐诗','yuding','','[]','汲泉灑小台，臺上無纖埃。解帶面西坐，輕襟隨風開。',48,'御定全唐詩/json/453.json','["汲泉灑小台，臺上無纖埃。解帶面西坐，輕襟隨風開。", "晚涼閑興動，憶同傾一杯。月明候柴戶，藜杖何時來。"]'),
('yuding-40','種桃歌','白居易','唐','御定全唐诗','yuding','','[]','食桃種其核，一年核生芽。二年長枝葉，三年桃有花。',96,'御定全唐詩/json/453.json','["食桃種其核，一年核生芽。二年長枝葉，三年桃有花。", "憶昨五六歲，灼灼盛芬華。迨茲八九載，有減而無加。", "去春已稀少，今春漸無多。明年後年後，芳意當如何。", "命酒樹下飲，停杯拾餘葩。因桃忽自感，悲吒成狂歌。"]'),
('yuding-41','狂言示諸侄','白居易','唐','御定全唐诗','yuding','','[]','世欺不識字，我忝攻文筆。世欺不得官，我忝居班秩。',168,'御定全唐詩/json/453.json','["世欺不識字，我忝攻文筆。世欺不得官，我忝居班秩。", "人老多病苦，我今幸無疾。人老多憂累，我今婚嫁畢。", "心安不移轉，身泰無牽率。所以十年來，形神閑且逸。", "況當垂老歲，所要無多物。一裘暖過冬，一飯飽終日。", "勿言舍宅小，不過寢一室。何用鞍馬多，不能騎兩匹。", "如我優幸身，人中十有七。如我知足心，人中百無一。", "傍觀愚亦見，當己賢多失。不敢論他人，狂言示諸侄。"]'),
('yuding-42','偶以拙詩數首寄呈裴少尹侍郎蒙以盛制四篇一時酬和重投長句美而謝之','白居易','唐','御定全唐诗','yuding','','[]','投君之文甚荒蕪，數篇價直一束芻。報我之章何璀璨，',48,'御定全唐詩/json/453.json','["投君之文甚荒蕪，數篇價直一束芻。報我之章何璀璨，", "一麋麗龜絕報賽，五鹿連柱難支梧。高興獨因秋日盡，"]'),
('yuding-0','六年冬暮贈崔常侍晦叔','白居易','唐','御定全唐诗','yuding','','[]','鬢毛霜一色，光景水爭流。易過唯冬日，難銷是老愁。',48,'御定全唐詩/json/454.json','["鬢毛霜一色，光景水爭流。易過唯冬日，難銷是老愁。", "香開綠蟻酒，暖擁褐綾裘。已共崔君約，尊前倒即休。"]'),
('yuding-1','戲招諸客','白居易','唐','御定全唐诗','yuding','','[]','黃醅綠醑迎冬熟，絳帳紅爐逐夜開。',32,'御定全唐詩/json/454.json','["黃醅綠醑迎冬熟，絳帳紅爐逐夜開。", "誰道洛中多逸客，不將書喚不曾來。"]'),
('yuding-2','十二月二十三日作，兼呈晦叔','白居易','唐','御定全唐诗','yuding','','[]','案頭曆日雖未盡，向後唯殘六七行。床下酒瓶雖不滿，',40,'御定全唐詩/json/454.json','["案頭曆日雖未盡，向後唯殘六七行。床下酒瓶雖不滿，", "聞健偷閒且勤飲，一杯之外莫思量。"]'),
('yuding-3','七年元日對酒五首','白居易','唐','御定全唐诗','yuding','','[]','慶吊經過懶，逢迎跪拜遲。不因時節日，豈覺此身羸。',120,'御定全唐詩/json/454.json','["慶吊經過懶，逢迎跪拜遲。不因時節日，豈覺此身羸。", "眾老憂添歲，餘衰喜入春。年開第七秩，屈指幾多人。", "三杯藍尾酒，一碟膠牙餳。除卻崔常侍，無人共我爭。", "今朝吳與洛，相憶一欣然。夢得君知否，俱過本命年。", "同歲崔何在，同年杜又無。應無藏避處，只有且歡娛。"]'),
('yuding-4','七年春題府廳','白居易','唐','御定全唐诗','yuding','','[]','潦倒守三川，因循涉四年。推誠廢鉤距，示恥用蒲鞭。',48,'御定全唐詩/json/454.json','["潦倒守三川，因循涉四年。推誠廢鉤距，示恥用蒲鞭。", "以此稱公事，將何銷俸錢。雖非好官職，歲久亦妨賢。"]'),
('yuding-5','早春醉吟，寄太原令狐相公、蘇州劉郎中','白居易','唐','御定全唐诗','yuding','','[]','雪夜閒遊多秉燭，花時暫出亦提壺。別來少遇新詩敵，',40,'御定全唐詩/json/454.json','["雪夜閒遊多秉燭，花時暫出亦提壺。別來少遇新詩敵，", "不知歌酒騰騰興，得似河南醉尹無。"]'),
('yuding-6','洛下送牛相公出鎮淮南','白居易','唐','御定全唐诗','yuding','','[]','北闕至東京，風光十六程。坐移丞相閣，春入廣陵城。',72,'御定全唐詩/json/454.json','["北闕至東京，風光十六程。坐移丞相閣，春入廣陵城。", "紅旆擁雙節，白須無一莖。萬人開路看，百吏立班迎。", "閫外君彌重，尊前我亦榮。何須身自得，將相是門生。"]'),
('yuding-7','箏','白居易','唐','御定全唐诗','yuding','','[]','雲髻飄蕭綠，花顏旖旎紅。雙眸剪秋水，十指剝春蔥。',169,'御定全唐詩/json/454.json','["雲髻飄蕭綠，花顏旖旎紅。雙眸剪秋水，十指剝春蔥。", "楚豔為門閥，秦聲是女工。甲明銀玓瓅，柱觸玉玲瓏。", "猿苦啼嫌月，鶯嬌語bZ風。移愁來手底，送恨入弦中。", "趙瑟清相似，胡琴鬧不同。慢彈回斷雁，急奏轉飛蓬。", "霜佩鏘還委，冰泉咽複通。珠聯千拍碎，刀截一聲終。", "倚麗精神定，矜能意態融。歇時情不斷，休去思無窮。", "燈下青春夜，尊前白首翁。且聽應得在，老耳未多聾。"]'),
('yuding-8','洛中春遊呈諸親友','白居易','唐','御定全唐诗','yuding','','[]','莫歎年將暮，須憐歲又新。府中三遇臘，洛下五逢春。',96,'御定全唐詩/json/454.json','["莫歎年將暮，須憐歲又新。府中三遇臘，洛下五逢春。", "春樹花珠顆，春塘水麹塵。春娃無氣力，春馬有精神。", "並轡鞭徐動，連盤酒慢巡。經過舊鄰里，追逐好交親。", "笑語銷閑日，酣歌送老身。一生歡樂事，亦不少於人。"]'),
('yuding-9','酬舒三員外見贈長句','白居易','唐','御定全唐诗','yuding','','[]','自請假來多少日，五旬光景似須臾。已判到老為狂客，',40,'御定全唐詩/json/454.json','["自請假來多少日，五旬光景似須臾。已判到老為狂客，", "頭風不敢多多飲，能酌三分相勸無。"]'),
('yuding-10','將歸一絕','白居易','唐','御定全唐诗','yuding','','[]','欲去公門返野扉，預思泉竹已依依。',32,'御定全唐詩/json/454.json','["欲去公門返野扉，預思泉竹已依依。", "更憐家醞迎春熟，一甕醍醐待我歸。"]'),
('yuding-11','罷府歸舊居','白居易','唐','御定全唐诗','yuding','','[]','陋巷乘籃入，朱門掛印回。腰間拋組綬，纓上拂塵埃。',72,'御定全唐詩/json/454.json','["陋巷乘籃入，朱門掛印回。腰間拋組綬，纓上拂塵埃。", "屈曲閑池沼，無非手自開。青蒼好竹樹，亦是眼看栽。", "石片抬琴匣，松枝閣酒杯。此生終老處，昨日卻歸來。"]'),
('yuding-12','睡覺偶吟','白居易','唐','御定全唐诗','yuding','','[]','官初罷後歸來夜，天欲明前睡覺時。',32,'御定全唐詩/json/454.json','["官初罷後歸來夜，天欲明前睡覺時。", "起坐思量更無事，身心安樂複誰知。"]'),
('yuding-13','問支琴石','白居易','唐','御定全唐诗','yuding','','[]','疑因星隕空中落，歎被泥埋澗底沈。天上定應勝地上，',24,'御定全唐詩/json/454.json','["疑因星隕空中落，歎被泥埋澗底沈。天上定應勝地上，"]'),
('yuding-14','自喜','白居易','唐','御定全唐诗','yuding','','[]','身慵難勉強，性拙易遲回。布被辰時起，柴門午後開。',48,'御定全唐詩/json/454.json','["身慵難勉強，性拙易遲回。布被辰時起，柴門午後開。", "忙驅能者去，閑逐鈍人來。自喜誰能會，無才勝有才。"]'),
('yuding-15','裴常侍以題薔薇架十八韻見示因廣為三十韻以和之','白居易','唐','御定全唐诗','yuding','','[]','托質依高架，攢花對小堂。晚開春去後，獨秀院中央。',360,'御定全唐詩/json/454.json','["托質依高架，攢花對小堂。晚開春去後，獨秀院中央。", "霽景朱明早，芳時白晝長。穠因天與色，麗共日爭光。", "剪碧排千萼，研朱染萬房。煙條塗石綠，粉蕊撲雌黃。", "根動彤雲湧，枝搖赤羽翔。九微燈炫轉，七寶帳熒煌。", "淑氣熏行徑，清陰接步廊。照梁迷藻棁，耀壁變雕牆。", "爛若叢然火，殷于葉得霜。胭脂含臉笑，蘇合裛衣香。", "浹洽濡晨露，玲瓏漏夕陽。合羅排勘纈，醉暈淺深妝。", "乍見疑回面，遙看誤斷腸。風朝舞飛燕，雨夜泣蕭娘。", "桃李慚無語，芝蘭讓不芳。山榴何細碎，石竹苦尋常。", "蕙慘偎欄避，蓮羞映浦藏。怯教蕉葉戰，妒得柳花狂。", "豈可輕嘲詠，應須痛比方。畫屏風自展，繡傘蓋誰張。", "翠錦挑成字，丹砂印著行。猩猩凝血點，瑟瑟蹙金匡。", "散亂萎紅片，尖纖嫩紫芒。觸僧飄毳褐，留妓冒羅裳。", "寡和陽春曲，多情騎省郎。緣誇美顏色，引出好文章。", "東顧辭仁裏，西歸入帝鄉。假如君愛殺，留著莫移將。"]'),
('yuding-16','感舊詩卷','白居易','唐','御定全唐诗','yuding','','[]','夜深吟罷一長籲，老淚燈前濕白須。',32,'御定全唐詩/json/454.json','["夜深吟罷一長籲，老淚燈前濕白須。", "二十年前舊詩卷，十人酬和九人無。"]'),
('yuding-17','酬李二十侍郎','白居易','唐','御定全唐诗','yuding','','[]','筍老蘭長花漸稀，衰翁相對惜芳菲。殘鶯著雨慵休囀，',40,'御定全唐詩/json/454.json','["筍老蘭長花漸稀，衰翁相對惜芳菲。殘鶯著雨慵休囀，", "十年分手今同醉，醉未如泥莫道歸。"]'),
('yuding-18','和夢得','白居易','唐','御定全唐诗','yuding','','[]','綸閣沉沉天寵命，蘇台籍籍有能聲。豈唯不得清文力，',40,'御定全唐詩/json/454.json','["綸閣沉沉天寵命，蘇台籍籍有能聲。豈唯不得清文力，", "所嗟非獨君如此，自古才難共命爭。"]'),
('yuding-19','贈草堂宗密上人','白居易','唐','御定全唐诗','yuding','','[]','吾師道與佛相應，念念無為法法能。口藏宣傳十二部，',40,'御定全唐詩/json/454.json','["吾師道與佛相應，念念無為法法能。口藏宣傳十二部，", "少有人知菩薩行，世間只是重高僧。"]'),
('yuding-20','喜照密閑實四上人見過','白居易','唐','御定全唐诗','yuding','','[]','紫袍朝士白髯翁，與俗乖疏與道通。官秩三回分洛下，',40,'御定全唐詩/json/454.json','["紫袍朝士白髯翁，與俗乖疏與道通。官秩三回分洛下，", "齋後將何充供養，西軒泉石北窗風。"]'),
('yuding-21','贈皇甫六張十五李二十三賓客','白居易','唐','御定全唐诗','yuding','','[]','昨日三川新罷守，今年四皓盡分司。幸陪散秩閒居日，',40,'御定全唐詩/json/454.json','["昨日三川新罷守，今年四皓盡分司。幸陪散秩閒居日，", "龍門泉石香山月，早晚同遊報一期。"]'),
('yuding-22','微之敦詩晦叔相次長逝，巋然自傷，因成二絕','白居易','唐','御定全唐诗','yuding','','[]','並失鵷鸞侶，空留麋鹿身。只應嵩洛下，長作獨遊人。',48,'御定全唐詩/json/454.json','["並失鵷鸞侶，空留麋鹿身。只應嵩洛下，長作獨遊人。", "長夜君先去，殘年我幾何。秋風滿衫淚，泉下故人多。"]'),
('yuding-23','池上閑詠','白居易','唐','御定全唐诗','yuding','','[]','青莎臺上起書樓，綠藻潭中系釣舟。日晚愛行深竹裏，',40,'御定全唐詩/json/454.json','["青莎臺上起書樓，綠藻潭中系釣舟。日晚愛行深竹裏，", "一部清商聊送老，白須蕭颯管弦秋。"]'),
('yuding-24','涼風歎','白居易','唐','御定全唐诗','yuding','','[]','昨夜涼風又颯然，螢飄葉墜臥床前。',32,'御定全唐詩/json/454.json','["昨夜涼風又颯然，螢飄葉墜臥床前。", "逢秋莫歎須知分，已過潘安三十年。"]'),
('yuding-25','和高僕射罷節度讓尚書授少保分司喜遂遊山水之作','白居易','唐','御定全唐诗','yuding','','[]','暫辭八座罷雙旌，便作登山臨水行。能以忠貞酬重任，',40,'御定全唐詩/json/454.json','["暫辭八座罷雙旌，便作登山臨水行。能以忠貞酬重任，", "鞍轡鬧裝光滿馬，何人通道是書生。"]'),
('yuding-26','送考功崔郎中赴闕','白居易','唐','御定全唐诗','yuding','','[]','稱意新官又少年，秋涼身健好朝天。',32,'御定全唐詩/json/454.json','["稱意新官又少年，秋涼身健好朝天。", "青雲上了無多路，卻要徐驅穩著鞭。"]'),
('yuding-27','重修香山寺畢，題二十二韻以紀之','白居易','唐','御定全唐诗','yuding','','[]','闕塞龍門口，祇園鷲嶺頭。曾隨減劫壞，今遇勝緣修。',264,'御定全唐詩/json/454.json','["闕塞龍門口，祇園鷲嶺頭。曾隨減劫壞，今遇勝緣修。", "再瑩新金刹，重裝舊石樓。病僧皆引起，忙客亦淹留。", "四望窮沙界，孤標出贍州。地圖鋪洛邑，天柱倚崧丘。", "兩面蒼蒼岸，中心瑟瑟流。波翻八灘雪，堰護一潭油。", "台殿朝彌麗，房廊夜更幽。千花高下塔，一葉往來舟。", "岫合雲初吐，林開霧半收。靜聞樵子語，遠聽棹郎謳。", "官散殊無事，身閑甚自由。吟來攜筆硯，宿去抱衾裯。", "霽月當窗白，涼風滿簟秋。煙香封藥灶，泉冷洗茶甌。", "南祖心應學，西方社可投。先宜知止足，次要悟浮休。", "覺路隨方樂，迷塗到老愁。須除愛名障，莫作戀家囚。", "便合窮年住，何言竟日遊。可憐終老地，此是我菟裘。"]'),
('yuding-28','送楊八給事赴常州','白居易','唐','御定全唐诗','yuding','','[]','無嗟別青瑣，且喜擁朱輪。五十得三品，百千無一人。',48,'御定全唐詩/json/454.json','["無嗟別青瑣，且喜擁朱輪。五十得三品，百千無一人。", "須勤念黎庶，莫苦憶交親。此外無過醉，毗陵何限春。"]'),
('yuding-29','聞歌者唱微之詩','白居易','唐','御定全唐诗','yuding','','[]','新詩絕筆聲名歇，舊卷生塵篋笥深。',32,'御定全唐詩/json/454.json','["新詩絕筆聲名歇，舊卷生塵篋笥深。", "時向歌中聞一句，未容傾耳已傷心。"]'),
('yuding-30','醉送李二十常侍赴鎮浙東','白居易','唐','御定全唐诗','yuding','','[]','靖安客舍花枝下，共脫青衫典濁醪。今日洛橋還醉別，',40,'御定全唐詩/json/454.json','["靖安客舍花枝下，共脫青衫典濁醪。今日洛橋還醉別，", "好去商山紫芝伴，珊瑚鞭動馬頭高。"]'),
('yuding-31','醉別程秀才','白居易','唐','御定全唐诗','yuding','','[]','五度龍門點額回，卻緣多藝複多才。貧泥客路黏難出，',40,'御定全唐詩/json/454.json','["五度龍門點額回，卻緣多藝複多才。貧泥客路黏難出，", "吳弦楚調瀟湘弄，為我殷勤送一杯。"]'),
('yuding-32','自詠','白居易','唐','御定全唐诗','yuding','','[]','白衣居士紫芝仙，半醉行歌半坐禪。今日維摩兼飲酒，',40,'御定全唐詩/json/454.json','["白衣居士紫芝仙，半醉行歌半坐禪。今日維摩兼飲酒，", "但問此身銷得否，分司氣味不論年。"]'),
('yuding-33','把酒思閒事二首','白居易','唐','御定全唐诗','yuding','','[]','把酒思閒事，春愁誰最深。乞錢羈客面，落第舉人心。',96,'御定全唐詩/json/454.json','["把酒思閒事，春愁誰最深。乞錢羈客面，落第舉人心。", "月下低眉立，燈前抱膝吟。憑君勸一醉，勝與萬黃金。", "把酒思閒事，春嬌何處多。試鞍新白馬，弄鏡小青娥。", "掌上初教舞，花前欲按歌。憑君勸一醉，勸了問如何。"]'),
('yuding-34','衰荷','白居易','唐','御定全唐诗','yuding','','[]','白露凋花花不殘，涼風吹葉葉初幹。',32,'御定全唐詩/json/454.json','["白露凋花花不殘，涼風吹葉葉初幹。", "無人解愛蕭條境，更繞衰叢一匝看。"]'),
('yuding-35','池上送考功崔郎中，兼別房竇二妓','白居易','唐','御定全唐诗','yuding','','[]','文昌列宿征還日，洛浦行雲放散時。',32,'御定全唐詩/json/454.json','["文昌列宿征還日，洛浦行雲放散時。", "鵷鷺上天花逐水，無因再會白家池。"]'),
('yuding-36','自問','白居易','唐','御定全唐诗','yuding','','[]','依仁台廢悲風晚，履信池荒宿草春。',32,'御定全唐詩/json/454.json','["依仁台廢悲風晚，履信池荒宿草春。", "自問老身騎馬出，洛陽城裏覓何人。"]'),
('yuding-37','送陳許高僕射赴鎮','白居易','唐','御定全唐诗','yuding','','[]','敦詩說禮中軍帥，重士輕財大丈夫。常與師徒同苦樂，',40,'御定全唐詩/json/454.json','["敦詩說禮中軍帥，重士輕財大丈夫。常與師徒同苦樂，", "商皓老狂唯愛醉，時時能寄酒錢無。"]'),
('yuding-38','青氈帳二十韻','白居易','唐','御定全唐诗','yuding','','[]','合聚千羊毳，施張百子弮。骨盤邊柳健，色染塞藍鮮。',240,'御定全唐詩/json/454.json','["合聚千羊毳，施張百子弮。骨盤邊柳健，色染塞藍鮮。", "北制因戎創，南移逐虜遷。汰風吹不動，禦雨濕彌堅。", "有頂中央聳，無隅四向圓。傍通門豁爾，內密氣溫然。", "遠別關山外，初安庭戶前。影孤明月夜，價重苦寒年。", "軟暖圍氈毯，槍摐束管弦。最宜霜後地，偏稱雪中天。", "側置低歌座，平鋪小舞筵。閑多揭簾入，醉便擁袍眠。", "鐵檠移燈背，銀囊帶火懸。深藏曉蘭焰，暗貯宿香煙。", "獸炭休親近，狐裘可棄捐。硯溫融凍墨，瓶暖變春泉。", "蕙帳徒招隱，茅庵浪坐禪。貧僧應嘆羨，寒士定留連。", "客賓於中接，兒孫向後傳。王家誇舊物，未及此青氈。"]'),
('yuding-39','答夢得秋日書懷見寄','白居易','唐','御定全唐诗','yuding','','[]','倖免非常病，甘當本分衰。眼昏燈最覺，腰瘦帶先知。',48,'御定全唐詩/json/454.json','["倖免非常病，甘當本分衰。眼昏燈最覺，腰瘦帶先知。", "樹葉霜紅日，髭須雪白時。悲愁緣欲老，老過卻無悲。"]'),
('yuding-40','同諸客題于家公主舊宅','白居易','唐','御定全唐诗','yuding','','[]','平陽舊宅少人游，應是遊人到即愁。布穀鳥啼桃李院，',40,'御定全唐詩/json/454.json','["平陽舊宅少人游，應是遊人到即愁。布穀鳥啼桃李院，", "聞道至今蕭史在，髭須雪白向明州。"]'),
('yuding-41','答夢得八月十五日夜玩月見寄','白居易','唐','御定全唐诗','yuding','','[]','南國碧雲客，東京白首翁。松江初有月，伊水正無風。',48,'御定全唐詩/json/454.json','["南國碧雲客，東京白首翁。松江初有月，伊水正無風。", "遠思兩鄉斷，清光千里同。不知娃館上，何似石樓中。"]'),
('yuding-42','初冬早起寄夢得','白居易','唐','御定全唐诗','yuding','','[]','起戴烏紗帽，行披白布裘。爐溫先暖酒，手冷未梳頭。',48,'御定全唐詩/json/454.json','["起戴烏紗帽，行披白布裘。爐溫先暖酒，手冷未梳頭。", "早起煙霜白，初寒鳥雀愁。詩成遣誰和，還是寄蘇州。"]'),
('yuding-43','秋夜聽高調涼州','白居易','唐','御定全唐诗','yuding','','[]','樓上金風聲漸緊，月中銀字韻初調。',32,'御定全唐詩/json/454.json','["樓上金風聲漸緊，月中銀字韻初調。", "促張弦柱吹高管，一曲涼州入泬寥。"]'),
('yuding-44','香山寺二絕','白居易','唐','御定全唐诗','yuding','','[]','空山寂靜老夫閑，伴鳥隨雲往復還。',64,'御定全唐詩/json/454.json','["空山寂靜老夫閑，伴鳥隨雲往復還。", "家醞滿瓶書滿架，半移生計入香山。", "愛風岩上攀松蓋，戀月潭邊坐石棱。", "且共雲泉結緣境，他生當作此山僧。"]'),
('yuding-45','送舒著作重授省郎赴闕','白居易','唐','御定全唐诗','yuding','','[]','三歲相依在洛都，遊花宴月飽歡娛。惜別笙歌多怨咽，',40,'御定全唐詩/json/454.json','["三歲相依在洛都，遊花宴月飽歡娛。惜別笙歌多怨咽，", "從此求閑應不得，更能重醉白家無。"]'),
('yuding-46','同諸客嘲雪中馬上妓','白居易','唐','御定全唐诗','yuding','','[]','珊瑚鞭嚲馬踟躕，引手低蛾索一盂。腰為逆風成弱柳，',40,'御定全唐詩/json/454.json','["珊瑚鞭嚲馬踟躕，引手低蛾索一盂。腰為逆風成弱柳，", "雪裏君看何所似，王昭君妹寫真圖。"]'),
('yuding-47','喜劉蘇州恩賜金紫，遙想賀宴，以詩慶之','白居易','唐','御定全唐诗','yuding','','[]','海內姑蘇太守賢，恩加章綬豈徒然。賀賓喜色欺杯酒，',40,'御定全唐詩/json/454.json','["海內姑蘇太守賢，恩加章綬豈徒然。賀賓喜色欺杯酒，", "莫嫌鬢上些些白，金紫由來稱長年。"]'),
('yuding-48','藍田劉明府攜酌相過與皇甫郎中卯時同飲醉後贈之','白居易','唐','御定全唐诗','yuding','','[]','臘月九日暖寒客，卯時十分空腹杯。玄晏舞狂烏帽落，',40,'御定全唐詩/json/454.json','["臘月九日暖寒客，卯時十分空腹杯。玄晏舞狂烏帽落，", "不為劉家賢聖物，愁翁笑口大難開。"]'),
('yuding-49','劉蘇州以華亭一鶴遠寄，以詩謝之','白居易','唐','御定全唐诗','yuding','','[]','老鶴風姿異，衰翁詩思深。素毛如我鬢，丹頂似君心。',48,'御定全唐詩/json/454.json','["老鶴風姿異，衰翁詩思深。素毛如我鬢，丹頂似君心。", "松際雪相映，雞群塵不侵。殷勤遠來意，一隻重千金。"]'),
('yuding-50','早春憶蘇州寄夢得','白居易','唐','御定全唐诗','yuding','','[]','吳苑四時風景好，就中偏好是春天。霞光曙後殷於火，',40,'御定全唐詩/json/454.json','["吳苑四時風景好，就中偏好是春天。霞光曙後殷於火，", "誠知歡樂堪留戀，其奈離鄉已四年。"]'),
('yuding-51','嘗新酒憶晦叔二首','白居易','唐','御定全唐诗','yuding','','[]','尊裏看無色，杯中動有光。自君拋我去，此物共誰嘗。',48,'御定全唐詩/json/454.json','["尊裏看無色，杯中動有光。自君拋我去，此物共誰嘗。", "世上強欺弱，人間醉勝醒。自君拋我去，此語更誰聽。"]'),
('yuding-52','負春','白居易','唐','御定全唐诗','yuding','','[]','病來道士教調氣，老去山僧勸坐禪。',32,'御定全唐詩/json/454.json','["病來道士教調氣，老去山僧勸坐禪。", "孤負春風楊柳曲，去年斷酒到今年。"]'),
('yuding-53','池上閑吟二首','白居易','唐','御定全唐诗','yuding','','[]','高臥閑行自在身，池邊六見柳條新。幸逢堯舜無為日，',80,'御定全唐詩/json/454.json','["高臥閑行自在身，池邊六見柳條新。幸逢堯舜無為日，", "莫愁客到無供給，家醞香濃野菜春。", "非莊非宅非蘭若，竹樹池亭十畝餘。非道非僧非俗吏，", "雖未定知生與死，其間勝負兩何如。"]'),
('yuding-54','早春招張賓客','白居易','唐','御定全唐诗','yuding','','[]','久雨初晴天氣新，風煙草樹盡欣欣。雖當冷落衰殘日，',40,'御定全唐詩/json/454.json','["久雨初晴天氣新，風煙草樹盡欣欣。雖當冷落衰殘日，", "商山老伴相收拾，不用隨他年少人。"]'),
('yuding-55','營閒事','白居易','唐','御定全唐诗','yuding','','[]','自笑營閒事，從朝到日斜。澆畦引泉脈，掃徑避蘭芽。',48,'御定全唐詩/json/454.json','["自笑營閒事，從朝到日斜。澆畦引泉脈，掃徑避蘭芽。", "暖變牆衣色，晴催木筆花。桃根知酒渴，晚送一甌茶。"]'),
('yuding-56','感春','白居易','唐','御定全唐诗','yuding','','[]','老思不禁春，風光照眼新。花房紅鳥觜，池浪碧魚鱗。',48,'御定全唐詩/json/454.json','["老思不禁春，風光照眼新。花房紅鳥觜，池浪碧魚鱗。", "倚棹誰為伴，持杯自問身。心情多少在，六十二三人。"]'),
('yuding-57','春池上戲贈李郎中','白居易','唐','御定全唐诗','yuding','','[]','滿池春水何人愛，唯我回看指似君。',32,'御定全唐詩/json/454.json','["滿池春水何人愛，唯我回看指似君。", "直似挼藍新汁色，與君南宅染羅裙。"]');
